/* AUTO-GENERATED — Maine Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["ME"] = {"code":"ME","name":"Maine","agency":"Maine BMV","agencyShort":"BMV","handbook":"https://www.maine.gov/sos/sites/maine.gov.sos/files/inline-files/CDL%20Manual%20FInal.pdf","links":{},"en":[{"q":"On a Maine public way, what is the maximum overall width allowed for a vehicle without a special permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Under 29-A M.R.S. §2380, a vehicle wider than 102 inches (8'6\") overall may not be operated on a Maine public way or bridge without a permit. Source: Maine Revised Statutes Title 29-A, §2380.","handbook":"","hbref":""},{"q":"What is the maximum legal structural height of a vehicle on Maine highways without an overlimit permit?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"answer":2,"explanation":"29-A M.R.S. §2380 prohibits operating a vehicle with a permanent or temporary structural part more than 13 feet 6 inches high. A nonreducible load may extend up to 6 inches above that, but the structural limit is 13'6\". Source: Maine Revised Statutes Title 29-A, §2380.","handbook":"","hbref":""},{"q":"In Maine, certain side appurtenances (such as mirrors and mud flaps) are excluded from the width measurement only if they do not extend beyond the vehicle's side by more than how much?","options":["2 inches","3 inches","6 inches","9 inches"],"answer":1,"explanation":"29-A M.R.S. §2380 excludes specified appurtenances (mirrors, door hinges, rain gutters, mud flaps, etc.) from the 102-inch width measurement provided they extend no more than 3 inches from the vehicle's side. Source: Maine Revised Statutes Title 29-A, §2380.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of a five-or-more-axle combination vehicle on Maine's general (non-Interstate) highways under the standard weight limits?","options":["69,000 pounds","73,280 pounds","80,000 pounds","90,000 pounds"],"answer":2,"explanation":"Under 29-A M.R.S. §2353, the maximum gross weight for a combination of five or more axles is 80,000 pounds (a 2-axle vehicle is limited to 34,000, a 3-axle to 54,000, and a 4-axle to 69,000). Source: Maine Revised Statutes Title 29-A, §2353.","handbook":"","hbref":""},{"q":"Under Maine's standard (non-Interstate) weight limits in §2353, what is the maximum weight allowed on a single axle?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":2,"explanation":"29-A M.R.S. §2353 sets the single-axle limit at 22,400 pounds on Maine's general highway system, which is higher than the 20,000-pound federal Interstate single-axle figure. Source: Maine Revised Statutes Title 29-A, §2353.","handbook":"","hbref":""},{"q":"On Maine's general highway system (§2353), what is the maximum weight permitted on a tandem-axle unit?","options":["34,000 pounds","36,000 pounds","38,000 pounds","41,000 pounds"],"answer":2,"explanation":"29-A M.R.S. §2353 allows 38,000 pounds on a tandem-axle unit on Maine's general ways, which exceeds the 34,000-pound tandem limit that applies on the Interstate Highway System under §2355. Source: Maine Revised Statutes Title 29-A, §2353.","handbook":"","hbref":""},{"q":"On the Interstate Highway System in Maine, what is the maximum weight allowed on a tandem-axle unit?","options":["32,000 pounds","34,000 pounds","38,000 pounds","41,000 pounds"],"answer":1,"explanation":"29-A M.R.S. §2355 limits a tandem-axle unit to 34,000 pounds on the Interstate Highway System, matching the federal standard. Maine's general ways allow a higher 38,000-pound tandem under §2353. Source: Maine Revised Statutes Title 29-A, §2355.","handbook":"","hbref":""},{"q":"On the Maine Interstate system, a vehicle with a gross vehicle weight greater than 73,280 pounds is limited to what single-axle weight?","options":["18,000 pounds","20,000 pounds","22,000 pounds","22,400 pounds"],"answer":1,"explanation":"29-A M.R.S. §2355 limits the single axle to 20,000 pounds when GVW exceeds 73,280 pounds (and 22,000 pounds when GVW is 73,280 or less) on the Interstate Highway System. Source: Maine Revised Statutes Title 29-A, §2355.","handbook":"","hbref":""},{"q":"On the Maine Interstate system, a vehicle with a gross vehicle weight of 73,280 pounds or less may carry what maximum weight on a single axle?","options":["20,000 pounds","22,000 pounds","22,400 pounds","24,200 pounds"],"answer":1,"explanation":"29-A M.R.S. §2355 allows a single axle up to 22,000 pounds when the GVW is 73,280 pounds or less on the Interstate, dropping to 20,000 pounds when GVW exceeds 73,280. Source: Maine Revised Statutes Title 29-A, §2355.","handbook":"","hbref":""},{"q":"In the federal bridge formula used on the Maine Interstate system, W = 500(LN/(N-1) + 12N + 36), what does the variable \"L\" represent?","options":["The length of the load in feet","The distance in feet between the extreme axles of a group","The legal weight per axle in thousands of pounds","The number of loaded axles on the vehicle"],"answer":1,"explanation":"In the federal Bridge Formula B applied by 29-A M.R.S. §2355, W is the allowable gross weight on a group of axles, N is the number of axles in the group, and L is the distance in feet between the extreme (outer) axles of that group. Source: Maine Revised Statutes Title 29-A, §2355 (federal bridge formula).","handbook":"","hbref":""},{"q":"A six-axle combination in Maine (3-axle tractor with tri-axle semitrailer) may reach a maximum gross weight of up to what amount when all conditions are met?","options":["80,000 pounds","90,000 pounds","100,000 pounds","120,000 pounds"],"answer":2,"explanation":"29-A M.R.S. §2354 permits a six-axle combination (3-axle truck tractor with tri-axle semitrailer) up to 100,000 pounds when the spacing and other conditions are met; the base limit is 90,000 pounds. Source: Maine Revised Statutes Title 29-A, §2354.","handbook":"","hbref":""},{"q":"For Maine's six-axle 100,000-pound combination, the distance between the extreme axles (excluding the steering axle) must be at least how many feet?","options":["30 feet","32 feet","36 feet","40 feet"],"answer":2,"explanation":"29-A M.R.S. §2354 requires the distance between the extreme axles (excluding the steering axle) to be not less than 36 feet; the maximum gross weight is reduced by 2,000 pounds for each foot the distance is less than 36 feet. Source: Maine Revised Statutes Title 29-A, §2354.","handbook":"","hbref":""},{"q":"Under Maine's six-axle weight statute, by how much is the maximum gross weight reduced for each foot that the extreme-axle spacing falls below the required minimum?","options":["1,000 pounds per foot","1,500 pounds per foot","2,000 pounds per foot","2,500 pounds per foot"],"answer":2,"explanation":"29-A M.R.S. §2354 reduces the maximum permitted gross weight of a six-axle combination by 2,000 pounds for each foot the extreme-axle distance is less than the required 36 feet. Source: Maine Revised Statutes Title 29-A, §2354.","handbook":"","hbref":""},{"q":"Maine's weight-tolerance statute (§2357) allows qualifying loads (e.g., wood products, road salt, gravel) to exceed the maximum gross weight by what amount?","options":["Up to 5% over the maximum","Up to 10% (110% of the maximum)","Up to 15% over the maximum","Up to 2,000 pounds over the maximum"],"answer":1,"explanation":"29-A M.R.S. §2357 provides that a qualifying vehicle is not in violation if its gross vehicle weight does not exceed 110% (10% over) of the maximum gross weight in §2353, for listed commodities such as wood products, gravel, road salt and similar bulk materials. Source: Maine Revised Statutes Title 29-A, §2357.","handbook":"","hbref":""},{"q":"Maine's 10% weight tolerance for certain commodities (§2357) applies on which roads?","options":["Only on the Interstate Highway System","On all Maine ways except the Interstate Highway System","Only on the Maine Turnpike","On all Maine roads including the Interstate"],"answer":1,"explanation":"29-A M.R.S. §2357 expressly states the weight tolerance does not apply to a vehicle operated on the Interstate Highway System; it is available on Maine's general (non-Interstate) ways. Source: Maine Revised Statutes Title 29-A, §2357.","handbook":"","hbref":""},{"q":"Who is the authority that grants statewide overlimit (oversize/overweight) movement permits in Maine, acting under the advice of the Commissioner of Transportation?","options":["The Secretary of State","The Maine State Police","The Maine Turnpike Authority","The Public Utilities Commission"],"answer":0,"explanation":"Under 29-A M.R.S. §2382, the Secretary of State (through the Bureau of Motor Vehicles), acting under guidelines and advice of the Commissioner of Transportation, grants overlimit movement permits; counties and municipalities may permit travel on their own ways. Source: Maine Revised Statutes Title 29-A, §2382.","handbook":"","hbref":""},{"q":"In Maine, an overlimit (oversize/overweight) permit is required to move which kind of load that exceeds the legal dimension or weight limits?","options":["Any load, whether or not it can be separated","Only divisible loads that can be split into legal units","A nondivisible object that cannot be reduced to legal limits","Only loads carried on the Interstate Highway System"],"answer":2,"explanation":"29-A M.R.S. §2381 and §2382 authorize permits for nondivisible objects (those that cannot reasonably be reduced to legal length, width, height or weight). Divisible loads must be broken down to legal limits rather than permitted. Source: Maine Revised Statutes Title 29-A, §§2381–2382.","handbook":"","hbref":""},{"q":"What is the maximum duration of a long-term overlimit permit the Maine Secretary of State may issue for trucks, tractors and semitrailers?","options":["30 days","6 months","One year","Two years"],"answer":2,"explanation":"29-A M.R.S. §2382 allows the Secretary of State to grant permits valid for up to one year for trucks, truck tractors, semitrailers, heavy-duty recovery vehicles and Class A special mobile equipment; otherwise single-trip permits are issued. Source: Maine Revised Statutes Title 29-A, §2382.","handbook":"","hbref":""},{"q":"When a Maine 53-foot semitrailer operates off the national network of highways, the total length of the vehicle and load may not exceed what overall length?","options":["65 feet","69 feet","74 feet","80 feet"],"answer":2,"explanation":"29-A M.R.S. §2390 permits a semitrailer over 48 feet but not more than 53 feet (with kingpin-to-rear-axle distance no more than 43 feet), but when operating off the national network the overall length may not exceed 74 feet. On the Interstate Highway System the overall length limit does not apply. Source: Maine Revised Statutes Title 29-A, §2390.","handbook":"","hbref":""},{"q":"Under Maine law, which class of CDL is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the vehicle(s) being towed exceed 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Maine defines Class A as any combination of vehicles with a GCWR of 26,001 or more pounds, provided the GVWR/gross weight of the vehicle(s) towed exceeds 10,000 pounds. Source: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253.","handbook":"","hbref":""},{"q":"A Maine driver operates a single straight truck with a gross vehicle weight rating of 30,000 pounds and tows no trailer. Which CDL class does this require?","options":["Class A","Class B","Class C","No CDL is required"],"answer":1,"explanation":"Maine's Class B covers any single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a unit not over 10,000 pounds. A 30,000-pound single unit is Class B. Source: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253.","handbook":"","hbref":""},{"q":"In Maine, a vehicle that does not meet the Class A or Class B weight definitions but is designed to transport 16 or more passengers (including the driver), or carries placarded hazardous materials, falls into which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"Maine's Class C is any single or combination vehicle not meeting Class A/B that is designed to carry 16 or more passengers (including the driver) or transports placarded hazardous materials. Source: Maine CDL Manual, 'Definitions of Classes' and Figure 1.1; 29-A MRSA §1253.","handbook":"","hbref":""},{"q":"According to the Maine CDL Manual, which endorsement is required to operate vehicles carrying hazardous materials when the load must be placarded under federal DOT regulations?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"Maine uses the H endorsement for the operation of vehicles carrying hazardous material when required to be placarded by federal DOT regulation. The X endorsement combines tank (N) and hazmat (H). Source: Maine CDL Manual, 'Endorsements.'","handbook":"","hbref":""},{"q":"On a Maine CDL, what does the 'X' endorsement authorize?","options":["Operation of tank vehicles only","Operation of tank vehicles carrying hazardous materials (combines N and H)","Operation of double and triple trailers","Operation of passenger buses over 15 passengers"],"answer":1,"explanation":"Maine's X endorsement is for the operation of tank vehicles carrying hazardous materials, combining the N (tank) and H (hazmat) endorsements into one. Source: Maine CDL Manual, 'Endorsements.'","handbook":"","hbref":""},{"q":"The Maine CDL Manual notes a specific restriction regarding the 'T' (doubles/triples) endorsement. Which statement is correct for Maine?","options":["Both double and triple trailers may be operated freely statewide","Triple trailers are not allowed in Maine","The T endorsement also authorizes tank vehicles","Double trailers require a separate passenger test"],"answer":1,"explanation":"The Maine CDL Manual describes the T endorsement as being for double/triple trailers 'where allowed by law' and states plainly that triple trailers are not allowed in Maine. Source: Maine CDL Manual, 'Endorsements.'","handbook":"","hbref":""},{"q":"Per the Maine CDL Manual, the N (tank vehicle) endorsement is required to haul a liquid or liquid gas in a permanently mounted cargo tank rated at what minimum capacity?","options":["100 gallons or more","119 gallons or more","1,000 gallons or more","450 gallons or more"],"answer":1,"explanation":"Maine requires the tanker (N) test/endorsement to haul liquid or liquid gas in a permanently mounted cargo tank rated at 119 gallons or more, or a portable tank rated at 1,000 gallons or more. Source: Maine CDL Manual, '1.1.1 Knowledge Tests' and tank vehicle section.","handbook":"","hbref":""},{"q":"In Maine, successfully qualifying for which endorsement automatically also earns the 'P' (passenger) endorsement at no additional fee or further examination?","options":["H (Hazardous Materials)","N (Tank Vehicle)","S (School Bus)","T (Doubles/Triples)"],"answer":2,"explanation":"The Maine CDL Manual states that successful qualification for the S (school bus) endorsement also earns the P (passenger) endorsement without an additional fee or further examination. Source: Maine CDL Manual, 'Endorsements.'","handbook":"","hbref":""},{"q":"According to the Maine CDL Manual, which endorsements are awarded upon passing only the knowledge (written) test, without requiring a separate skills test?","options":["P and S","N, H, X, and T","Only H","All endorsements require a skills test"],"answer":1,"explanation":"The Maine CDL Manual states the N, H, X, and T endorsements are awarded to the CDL holder upon successful completion of the knowledge examination only; P and S require the complete test including skills testing. Source: Maine CDL Manual, 'Endorsements.'","handbook":"","hbref":""},{"q":"Maine recognizes a '3' endorsement for one type of school bus operation that does NOT require the driver to hold a CDL. That bus is designed to transport how many passengers?","options":["16 or more passengers including the driver","15 passengers or fewer including the driver","Exactly 24 passengers","Over 15 passengers excluding the driver"],"answer":1,"explanation":"The Maine CDL Manual describes a '3' endorsement for a school bus designed to transport 15 passengers or fewer (including the driver); it may be affixed to a non-commercial license and does not require a CDL. Source: Maine CDL Manual, '\"3\" endorsement.'","handbook":"","hbref":""},{"q":"Under Maine's CDL rules, what is the minimum age to operate a commercial motor vehicle in intrastate commerce (within Maine only)?","options":["16 years","18 years","21 years","19 years"],"answer":1,"explanation":"Maine's minimum age for an intrastate CDL is 18. (The Maine CDL Manual's older text references age 16 for some intrastate operations, but the BMV applies the federal floor of 18 for intrastate CDL operation.) Source: Maine BMV / FMCSA 49 CFR 391.11; Maine CDL Manual age provisions.","handbook":"","hbref":""},{"q":"What is the minimum age in Maine to obtain a CDL valid for interstate commerce (crossing state lines)?","options":["18 years","19 years","21 years","25 years"],"answer":2,"explanation":"A driver must be at least 21 years of age to operate a CMV in interstate commerce, to transport hazardous materials, or to drive a passenger bus. Source: Maine CDL Manual age provisions; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Per 29-A MRSA §1304(4-A), a Maine commercial learner's permit (CLP) holder is NOT eligible to take the CDL skills test during which period after the permit's initial issuance?","options":["The first 7 days","The first 14 days","The first 30 days","The first 60 days"],"answer":1,"explanation":"Maine law provides that a CLP holder is not eligible to take the CDL skills test in the first 14 days after the initial issuance of the CLP, matching the federal requirement. Source: 29-A MRSA §1304(4-A)(I).","handbook":"","hbref":""},{"q":"Under 29-A MRSA §1304, a Maine commercial learner's permit (CLP) is valid for no more than how long from the date of issuance?","options":["180 days","One year","Two years","Five years"],"answer":1,"explanation":"Maine law states the commercial learner's permit is valid for no more than one year from the date of issuance. Source: 29-A MRSA §1304(4-A)(G).","handbook":"","hbref":""},{"q":"While operating a CMV under a Maine commercial learner's permit, the CLP holder must be accompanied by a CDL holder who is positioned where?","options":["Anywhere in the vehicle","Following in a separate vehicle","Physically present in the front seat next to the CLP holder (or, in a passenger vehicle, directly behind or in the first row behind the driver)","Available by phone during operation"],"answer":2,"explanation":"Maine law requires the accompanying CDL holder to be physically present in the front seat next to the CLP holder, or in a passenger vehicle directly behind or in the first row behind the driver, with the proper class and endorsements. Source: 29-A MRSA §1304(4-A)(A).","handbook":"","hbref":""},{"q":"Which activity is expressly prohibited for a Maine commercial learner's permit holder under 29-A MRSA §1304(4-A)?","options":["Operating a commercial motor vehicle transporting hazardous materials","Driving during daylight hours","Operating a Class B vehicle","Practicing on interstate highways"],"answer":0,"explanation":"Maine law prohibits a CLP holder from operating a CMV transporting hazardous materials as defined in 49 CFR §383.5. Source: 29-A MRSA §1304(4-A)(F).","handbook":"","hbref":""},{"q":"Per 29-A MRSA §1304(4-A), what minimum age must a Maine CLP holder be in order to apply for a passenger (P) or school bus (S) endorsement?","options":["18 years","20 years","21 years","22 years"],"answer":2,"explanation":"Maine law requires a CLP holder to be at least 21 years of age to apply for a passenger or school bus endorsement, and the accompanying CDL holder must hold a passenger endorsement, have at least one year of experience, and be at least 22. Source: 29-A MRSA §1304(4-A)(E).","handbook":"","hbref":""},{"q":"The Entry-Level Driver Training (ELDT) requirement applicable to new Maine CDL applicants is verified through which system?","options":["The Maine BMV online portal","The FMCSA Training Provider Registry (TPR)","The National Driver Register","The TSA Secure Flight database"],"answer":1,"explanation":"Effective February 7, 2022, FMCSA's ELDT rule requires training for new CDL operators and certain upgrades, completed by a provider listed in and recorded with the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov). Source: Maine CDL Manual, 'Entry Level Driver Training (ELDT)'; FMCSA 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When applying for a Maine CDL, an applicant must self-certify to one type of driving operation. Which set correctly lists the four federal self-certification categories used by Maine?","options":["Local, regional, national, and international","Non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate","Commercial, private, agricultural, and emergency","Class A, Class B, Class C, and Class D operations"],"answer":1,"explanation":"Maine, following 49 CFR §383.71, requires CDL applicants to self-certify to one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, or excepted intrastate. Non-excepted categories require a valid medical examiner's certificate. Source: FMCSA 49 CFR §383.71; Maine BMV.","handbook":"","hbref":""},{"q":"Beyond identity, residency, and lawful-presence documents, which additional item must a Maine CDL applicant disclose, as mandated by 29-A MRSA for driver license issuance?","options":["A passport number","A Social Security number","A voter registration card","A vehicle title"],"answer":1,"explanation":"The Maine CDL Manual's Social Security Number Disclosure Statement notes that disclosure of the SSN is mandatory and required by 29-A MRSA to apply for or renew a driver's license; the BMV also requires proof of identity, Maine residency, and lawful presence. Source: Maine CDL Manual, 'Social Security Number Disclosure Statement'; 29-A MRSA.","handbook":"","hbref":""},{"q":"Under Maine CDL rules, at what blood alcohol concentration (BAC) is it illegal to operate a commercial motor vehicle?","options":["0.04% or more","0.08% or more","0.02% or more","0.10% or more"],"answer":0,"explanation":"The Maine CDL Manual (Section 1.2.2) states it is illegal to operate a CMV if your BAC is .04% or more. This 0.04 limit is half the 0.08 limit for ordinary drivers and matches federal standard 49 CFR 383.51.","handbook":"","hbref":""},{"q":"By operating a commercial motor vehicle in Maine, a driver is legally deemed to have done what?","options":["Waived the right to a defense attorney","Given consent to alcohol testing","Agreed to a vehicle search at any time","Consented to random drug urinalysis weekly"],"answer":1,"explanation":"The Maine CDL Manual (Section 1.2.2) states: 'If you operate a CMV, you shall be deemed to have given your consent to alcohol testing.' This is Maine's implied-consent rule for CMV operation (see also 29-A M.R.S. 2521).","handbook":"","hbref":""},{"q":"For a first major offense (such as driving a CMV with a BAC of .04% or higher), how long will a Maine driver lose their CDL?","options":["At least 60 days","At least 6 months","At least 1 year","At least 90 days"],"answer":2,"explanation":"The Maine CDL Manual (Section 1.2.2) states you will lose your CDL for at least one year for a first major offense, including driving a CMV with a BAC of .04% or higher. This matches federal standard 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Maine, what happens to a CDL holder who refuses to undergo blood alcohol testing when required while operating a CMV (first offense)?","options":["A warning with no disqualification","Loss of CDL for 30 days","Loss of CDL for 120 days","Loss of CDL for at least 1 year"],"answer":3,"explanation":"The Maine CDL Manual (Section 1.2.2) lists 'refusing to undergo blood alcohol testing' as a first major offense, carrying loss of CDL for at least one year (3 years if placarded for hazardous materials).","handbook":"","hbref":""},{"q":"If a first major offense (e.g., driving under the influence) occurs while a Maine driver is operating a CMV placarded for hazardous materials, the CDL is lost for at least how long?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"The Maine CDL Manual (Section 1.2.2) states you will lose your CDL for at least three years if a first major offense occurs while you are operating a CMV placarded for hazardous materials, per 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the consequence in Maine for a second major offense (such as a second DUI in a CMV)?","options":["Loss of CDL for 10 years","Loss of CDL for life","Loss of CDL for 3 years","Loss of CDL for 5 years"],"answer":1,"explanation":"The Maine CDL Manual (Section 1.2.2) states you will lose your CDL for life for a second major offense. This lifetime disqualification follows federal standard 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Maine rules, what is the penalty for using a CMV to commit a felony involving controlled substances?","options":["1-year loss of CDL","3-year loss of CDL","Lifetime loss of CDL","120-day loss of CDL"],"answer":2,"explanation":"The Maine CDL Manual (Section 1.2.2) states you will lose your CDL for life if you use a CMV to commit a felony involving controlled substances. There is no possibility of reinstatement for this offense.","handbook":"","hbref":""},{"q":"In Maine, a driver with a detectable amount of alcohol under .04% while operating a CMV will be:","options":["Disqualified for 60 days","Fined $5,000","Arrested for OUI automatically","Put out-of-service for 24 hours"],"answer":3,"explanation":"The Maine CDL Manual (Section 1.2.2) states you will be put out-of-service for 24 hours if you have any detectable amount of alcohol under .04%. A full disqualification requires a BAC of .04% or more.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' in the Maine CDL Manual?","options":["Excessive speeding (15 mph or more above the posted limit)","Driving 5 mph over the posted limit","An expired vehicle registration","A single parking violation"],"answer":0,"explanation":"The Maine CDL Manual (Section 1.2.3) defines excessive speeding as 15 mph or more above the posted limit, and lists it as a serious traffic violation along with reckless driving, improper lane changes, and following too closely.","handbook":"","hbref":""},{"q":"How long will a Maine driver lose their CDL for committing TWO serious traffic violations in a CMV within a three-year period?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"The Maine CDL Manual (Section 1.2.3) states you will lose your CDL for at least 60 days for two serious traffic violations within a three-year period involving a CMV, per 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How long will a Maine driver lose their CDL for committing THREE or more serious traffic violations in a CMV within a three-year period?","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"answer":2,"explanation":"The Maine CDL Manual (Section 1.2.3) states you will lose your CDL for at least 120 days for three or more serious traffic violations within a three-year period involving a CMV, per 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of these is listed among the serious traffic violations in the Maine CDL Manual?","options":["Failing to use a turn signal in a parking lot","Driving with one headlight out","Carrying an unsecured load under 500 pounds","Driving a CMV without obtaining a CDL or having it in your possession"],"answer":3,"explanation":"The Maine CDL Manual (Section 1.2.3) lists driving a CMV without obtaining a CDL, without having the CDL in possession, or without the proper class/endorsements as serious traffic violations.","handbook":"","hbref":""},{"q":"Under federal rules adopted in Maine, texting while driving a CMV and using a hand-held mobile telephone are treated as:","options":["Serious traffic violations","Major offenses with a 1-year disqualification","Out-of-service order violations","Non-disqualifying infractions"],"answer":0,"explanation":"Per 49 CFR 383.51, texting (49 CFR 392.80) and hand-held mobile phone use (49 CFR 392.82) while driving a CMV are serious traffic violations. Two in three years bring a 60-day disqualification; three bring 120 days. Maine adopts these federal standards.","handbook":"","hbref":""},{"q":"Under federal handheld-phone rules that apply to Maine CDL drivers, a single texting or hand-held phone conviction can also carry a driver civil penalty of up to:","options":["$500","$2,750","$11,000","$250"],"answer":1,"explanation":"Under FMCSA rules (49 CFR 392.80/392.82) applicable in Maine, a driver faces a civil penalty up to $2,750 per texting or hand-held phone violation; employers who allow it face penalties up to $11,000. Two such convictions in 3 years also disqualify the CDL for 60 days.","handbook":"","hbref":""},{"q":"According to the Maine CDL Manual, how long will a driver lose their CDL for a FIRST violation of an out-of-service order?","options":["At least 60 days","At least 30 days","At least 90 days","At least 1 year"],"answer":2,"explanation":"The Maine CDL Manual (Section 1.2.4) states you will lose your CDL for at least 90 days for a first out-of-service order violation. (Current federal 49 CFR 383.51 Table 4 sets a 180-day minimum, but Maine's published manual states 90 days.)","handbook":"","hbref":""},{"q":"Per the Maine CDL Manual, how long will a driver lose their CDL for TWO out-of-service order violations within a ten-year period?","options":["At least 90 days","At least 6 months","At least 3 years","At least 1 year"],"answer":3,"explanation":"The Maine CDL Manual (Section 1.2.4) states you will lose your CDL for at least one year for two out-of-service order violations in a ten-year period. A third within ten years brings at least three years.","handbook":"","hbref":""},{"q":"Per the Maine CDL Manual, how long will a driver lose their CDL for THREE or more out-of-service order violations within a ten-year period?","options":["At least 3 years","At least 1 year","Lifetime","At least 120 days"],"answer":0,"explanation":"The Maine CDL Manual (Section 1.2.4) states you will lose your CDL for at least three years for three or more out-of-service order violations within a ten-year period.","handbook":"","hbref":""},{"q":"Under the Maine CDL Manual, how long will a driver lose their CDL for a FIRST railroad-highway grade crossing violation?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"The Maine CDL Manual (Section 1.2.5) states you will lose your CDL for at least 60 days for a first railroad-highway grade crossing violation, per 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under the Maine CDL Manual, what is the disqualification for a THIRD railroad-highway grade crossing violation within a three-year period?","options":["At least 120 days","At least 60 days","At least 1 year","At least 90 days"],"answer":2,"explanation":"The Maine CDL Manual (Section 1.2.5) states you will lose your CDL for at least one year for a third railroad-highway grade crossing violation within a three-year period (first is 60 days, second is 120 days).","handbook":"","hbref":""},{"q":"In Maine, if a CDL holder's personal-vehicle driving privilege is revoked, cancelled, or suspended due to an alcohol, controlled-substance, or felony violation, what happens to the CDL?","options":["No effect, because it occurred in a personal vehicle","Loss of CDL for 60 days only","An immediate lifetime disqualification on the first violation","Loss of CDL for 1 year (lifetime for a second such violation)"],"answer":3,"explanation":"The Maine CDL Manual (Section 1.2.7), reflecting the Motor Carrier Safety Improvement Act, states that if your personal-vehicle privilege is revoked/cancelled/suspended for alcohol, controlled-substance, or felony violations you lose your CDL for 1 year, and for life on a second such violation. No hardship CDL is available.","handbook":"","hbref":""},{"q":"Under Maine's Move Over law, when you approach a stopped emergency or service vehicle displaying flashing lights on a multi-lane road, what is your FIRST required action if it can be done safely?","options":["Move out of the lane adjacent to the stopped vehicle into a non-adjacent lane","Stop completely until the emergency vehicle leaves the scene","Sound your horn and continue at the posted speed limit","Pull onto the right shoulder and wait to be waved past"],"answer":0,"explanation":"Maine's Move Over law (29-A MRSA Sec. 2054(9), and Sec. 2070(8) for stationary/disabled vehicles) requires the driver to pass in a lane NOT adjacent to the stopped vehicle if possible; only if changing lanes is impossible or unsafe may you pass at a careful and prudent reduced speed. Source: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070.","handbook":"","hbref":""},{"q":"On a two-lane road where moving to a non-adjacent lane is impossible, Maine's Move Over law requires a driver passing a stopped emergency or disabled vehicle to do what?","options":["Come to a full stop before passing the vehicle","Maintain at least the posted minimum speed limit","Pass at a careful and prudent speed reasonable for passing safely","Reduce speed to exactly 20 mph below the posted limit"],"answer":2,"explanation":"When a lane change is not possible or is unsafe, 29-A MRSA Sec. 2070(8)(B) (and Sec. 2054) requires passing at 'a careful and prudent speed reasonable for passing the vehicle safely.' Maine does not specify an exact mph figure. Source: Maine Revised Statutes Title 29-A Sec. 2070(8).","handbook":"","hbref":""},{"q":"Maine's Move Over law was expanded in 2023. In addition to authorized emergency and public service vehicles, the duty to move over or slow down now also applies when passing:","options":["Only marked police cruisers and ambulances","Any stationary vehicle a reasonable person would conclude is disabled or is using flashing lights","Only tow trucks and highway maintenance vehicles","Only vehicles displaying a red warning flag"],"answer":1,"explanation":"29-A MRSA Sec. 2070(8), enacted by PL 2023 c. 122, extends the move-over/slow-down duty to any stationary vehicle that a reasonable person would conclude is disabled or that is using flashing lights to warn of its presence. Source: Maine Revised Statutes Title 29-A Sec. 2070(8).","handbook":"","hbref":""},{"q":"What is the minimum fine adjudged for violating Maine's move-over / pass-a-stationary-vehicle requirement?","options":["$135","$500","$1,000","$275"],"answer":3,"explanation":"29-A MRSA Sec. 2070(8) provides that a violation is a traffic infraction for which a fine of not less than $275 must be adjudged. Source: Maine Revised Statutes Title 29-A Sec. 2070(8).","handbook":"","hbref":""},{"q":"When a Maine railroad crossing has a cross-buck with no painted white stop line, a placarded hazardous-materials vehicle or a bus that is required to stop must stop within what distance of the nearest rail?","options":["Not less than 15 feet and not more than 50 feet","Not less than 5 feet and not more than 25 feet","Not less than 25 feet and not more than 75 feet","Not less than 10 feet and not more than 100 feet"],"answer":0,"explanation":"29-A MRSA Sec. 2076(3) requires buses transporting passengers and placarded/marked hazardous-materials and cargo-tank vehicles to stop not less than 15 feet and not more than 50 feet from the nearest rail. The Maine CDL Manual (Sec. 2.15) states the same 15-to-50-foot range. Source: Maine Revised Statutes Title 29-A Sec. 2076; Maine CDL Manual.","handbook":"","hbref":""},{"q":"At which of the following railroad crossings is a Maine bus or placarded hazmat vehicle NOT required to stop?","options":["Any crossing located outside a business district","A crossing with flashing red lights that are not activated","A crossing of tracks used exclusively for industrial switching, or one marked with an 'exempt' sign","Any crossing on a road posted at 45 mph or less"],"answer":2,"explanation":"29-A MRSA Sec. 2076 lists exceptions to the mandatory stop, including streetcar crossings, tracks used exclusively for industrial switching, when directed to proceed by an officer or flagger, abandoned crossings so marked, and crossings posted with an 'exempt' sign. Source: Maine Revised Statutes Title 29-A Sec. 2076.","handbook":"","hbref":""},{"q":"Maine law (29-A Sec. 2306) directs a school bus operator approaching a railroad grade crossing to make a full stop and then do what before crossing?","options":["Wait a full 30 seconds regardless of conditions","Sound the horn twice and then proceed","Have a passenger exit and act as a flagger","Ascertain beyond a reasonable doubt that no train is approaching on the track"],"answer":3,"explanation":"29-A MRSA Sec. 2306 requires the school bus operator to make a full stop (not more than 50 feet nor less than 15 feet from the nearest rail) and ascertain beyond a reasonable doubt that no train, engine or conveyance is approaching before crossing. Source: Maine Revised Statutes Title 29-A Sec. 2306.","handbook":"","hbref":""},{"q":"A Maine school bus stops on a two-lane road with its red lights flashing to discharge passengers. What must the driver of a vehicle approaching from the OPPOSITE direction do?","options":["Slow to 15 mph and pass with caution","Stop the vehicle before reaching the bus and not proceed until the bus moves or signals","Continue normally because opposing traffic is exempt","Stop only if children are visibly crossing the road"],"answer":1,"explanation":"29-A MRSA Sec. 2308(2) requires the operator of a vehicle meeting OR overtaking a school bus from either direction, when the bus is stopped with red lights flashing, to stop before reaching the bus and not proceed until the bus resumes motion or the operator signals. Source: Maine Revised Statutes Title 29-A Sec. 2308(2).","handbook":"","hbref":""},{"q":"Under Maine's school-bus law, on what kind of roadway need a driver NOT stop for a school bus that is stopped on the other side?","options":["A way separated by curbing or other physical barrier, for a bus in a lane separated by that barrier","Any roadway with a painted double-yellow center line","Any roadway with two or more lanes in each direction","Any roadway with a posted limit of 50 mph or higher"],"answer":0,"explanation":"29-A MRSA Sec. 2308(3) exempts a driver from stopping only when the way is separated by curbing or other physical barrier (for a bus in a lane separated by that barrier), or on a limited-access highway where pedestrians may not cross. A painted line alone does NOT create the exception. Source: Maine Revised Statutes Title 29-A Sec. 2308(3).","handbook":"","hbref":""},{"q":"Maine requires a school bus operator to activate the bus's flashing warning lights at least how far before stopping to receive or discharge passengers?","options":["50 feet","200 feet","300 feet","100 feet"],"answer":3,"explanation":"29-A MRSA Sec. 2308(1) requires a school bus operator to activate the flashing lights at least 100 feet before a stop is made to receive or discharge passengers, and to keep them displayed until passengers are received or discharged. Source: Maine Revised Statutes Title 29-A Sec. 2308(1).","handbook":"","hbref":""},{"q":"In Maine, illegally passing a stopped school bus that has its red lights flashing is classified as what, with what first-offense penalty?","options":["A simple traffic infraction with a $135 fine","A civil violation with no fine for a first offense","A Class E crime with a $250 minimum fine","A Class C crime with mandatory jail time"],"answer":2,"explanation":"29-A MRSA Sec. 2308(6) makes a violation of subsection 2 a Class E crime punishable by a $250 minimum fine for a first offense, with a mandatory 30-day license suspension for a 2nd offense within 3 years. Source: Maine Revised Statutes Title 29-A Sec. 2308(6).","handbook":"","hbref":""},{"q":"Absent posted signs, what does Maine law set as the maximum speed in a business or residential district?","options":["20 mph","25 mph","30 mph","35 mph"],"answer":1,"explanation":"29-A MRSA Sec. 2074(1) sets default maximums of 15 mph in a school zone, 25 mph in a business or residential district or built-up portion, and 45 mph on all other public ways, each 'unless otherwise posted.' Source: Maine Revised Statutes Title 29-A Sec. 2074(1).","handbook":"","hbref":""},{"q":"Under Maine's default statutory speed limits (where no other limit is posted), what is the maximum speed on 'all other public ways'?","options":["55 mph","50 mph","40 mph","45 mph"],"answer":3,"explanation":"29-A MRSA Sec. 2074(1) sets the default maximum at 45 mph on all other public ways unless otherwise posted (business/residential is 25 mph; school zone is 15 mph). Most numbered highways carry higher posted limits. Source: Maine Revised Statutes Title 29-A Sec. 2074(1).","handbook":"","hbref":""},{"q":"What is the maximum speed limit on the Maine Turnpike (I-95) as set by the Maine Turnpike Authority?","options":["70 mph","65 mph","75 mph","80 mph"],"answer":0,"explanation":"The Maine Turnpike Authority's rules set the general maximum speed on the Turnpike at 70 mph, with lower posted limits on certain southern and northern segments. Source: Maine Turnpike Authority Policies & Rules.","handbook":"","hbref":""},{"q":"On three-lane sections of the Maine Turnpike south of Mile Marker 44, where are trucks (including truck tractors) permitted to operate?","options":["Only in the single rightmost lane","In any lane, including the left passing lane","Only in the two farthest right-hand lanes","Only in the center lane"],"answer":2,"explanation":"To improve southern Maine air quality, Maine Turnpike Authority rules restrict trucks (including truck tractors, excluding pickups) to the two farthest right-hand lanes on any Turnpike section south of Mile Marker 44 that has three lanes in each direction. Source: Maine Turnpike Authority Policies & Rules.","handbook":"","hbref":""},{"q":"If you must stop a CMV on or beside a one-way or divided highway in Maine, the Maine CDL Manual says to place your three warning devices at what distances toward approaching traffic?","options":["10 feet, 50 feet, and 150 feet","10 feet, 100 feet, and 200 feet","25 feet, 100 feet, and 300 feet","50 feet, 100 feet, and 500 feet"],"answer":1,"explanation":"The Maine CDL Manual (Sec. 2.5.1) directs that, when stopped on or by a one-way or divided highway, warning devices be placed at 10 feet, 100 feet, and 200 feet toward approaching traffic. Source: Maine CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"On a two-lane (two-way undivided) Maine highway, how should the three required warning devices be placed when a CMV is stopped?","options":["10 feet, 100 feet, and 200 feet, all behind the vehicle","At 50 feet, 200 feet, and 300 feet behind the vehicle only","One device within 10 feet and two devices 500 feet behind only","Within 10 feet of the vehicle, and 100 feet ahead of and 100 feet behind the vehicle"],"answer":3,"explanation":"The Maine CDL Manual (Sec. 2.5.2) directs placing a device within 10 feet of the front or rear to mark the vehicle, plus one 100 feet behind and one 100 feet ahead, on the shoulder or in the occupied lane. Source: Maine CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"After stopping a CMV on a Maine roadway, within how many minutes must you have your emergency warning devices in place?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"answer":0,"explanation":"The Maine CDL Manual (Sec. 2.5.1) states that if you must stop on a road or shoulder, you must put out emergency warning devices within ten minutes. Source: Maine CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"If a CMV is stopped just beyond a hill or curve in Maine, the Maine CDL Manual says the rear warning device should be repositioned so that:","options":["It is placed exactly 200 feet from the vehicle regardless of the curve","It is removed because the hazard lights are sufficient","It gives drivers warning back down the road, so the vehicle is visible within 500 feet","It is placed on the crest of the hill exactly 50 feet ahead"],"answer":2,"explanation":"The Maine CDL Manual (Sec. 2.5.2) directs that if a hill or curve obstructs the line of sight, move the rearmost triangle back down the road so warning is provided and other drivers can see the vehicle within 500 feet. Source: Maine CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"In Maine, a load that exceeds which dimension generally requires an overlimit (oversize) permit from the Bureau of Motor Vehicles / MaineDOT?","options":["A width greater than 10 feet 0 inches or a height greater than 15 feet 0 inches","A width greater than 8 feet 6 inches or a height greater than 13 feet 6 inches","A width greater than 8 feet 0 inches or a height greater than 12 feet 0 inches","A width greater than 9 feet 0 inches or a height greater than 14 feet 6 inches"],"answer":1,"explanation":"Maine follows the standard legal limits of 8 feet 6 inches wide and 13 feet 6 inches high; loads exceeding these require an overlimit (oversize) permit issued through the Maine BMV/MaineDOT overlimit permit program. Source: Maine BMV Overlimit Permits / MaineDOT.","handbook":"","hbref":""},{"q":"Which Maine agency issues Commercial Driver Licenses (CDLs) and administers CDL testing?","options":["The Maine Bureau of Motor Vehicles (BMV), within the Secretary of State's office","The Maine Department of Transportation (MaineDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Maine State Police Commercial Vehicle Enforcement Unit"],"answer":0,"explanation":"The Maine Bureau of Motor Vehicles (BMV), a division of the Secretary of State's office, issues all Maine CDLs and administers the knowledge and skills exams. MaineDOT handles roads and oversize/overweight permits, not licensing. Source: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv).","handbook":"","hbref":""},{"q":"On the Maine CDL self-certification form (MVE-64C), how many type-of-operation categories may an applicant choose from?","options":["Four","Two","Three","Six"],"answer":0,"explanation":"Maine requires self-certification into one of FOUR categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, or Excepted Intrastate. Source: Maine BMV CDL Medical Self-Certification Form MVE-64C; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Maine driver self-certifies as 'Non-Excepted Interstate.' What additional document must the BMV have on file?","options":["A federal DOT Medical Examiner's Certificate (medical card)","Nothing beyond the self-certification form","A notarized employer authorization letter","A Maine DOT oversize/overweight permit"],"answer":0,"explanation":"Drivers who self-certify as Non-Excepted Interstate must provide the BMV with a valid federal Medical Examiner's Certificate (MCSA-5876 / medical card). Excepted drivers are not required to submit one. Source: Maine BMV CDL self-certification guidance; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Who is qualified to perform the DOT physical exam that produces a CDL applicant's Medical Examiner's Certificate in Maine?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed physician of the applicant's choice","A BMV examiner at the testing site","The applicant's regular optometrist"],"answer":0,"explanation":"The DOT physical must be performed by a medical examiner who is listed on the FMCSA National Registry of Certified Medical Examiners. Source: Maine BMV CDL medical requirements; 49 CFR 391.43.","handbook":"","hbref":""},{"q":"What is the maximum length of time a DOT Medical Examiner's Certificate may be valid for a Maine CDL holder?","options":["2 years","1 year","3 years","5 years"],"answer":0,"explanation":"A Medical Examiner's Certificate is valid for a maximum of 2 years; an examiner may certify a driver for a shorter period if a condition requires monitoring. A new card must be on file before the old one expires. Source: Maine BMV CDL medical requirements; 49 CFR 391.45.","handbook":"","hbref":""},{"q":"How may a Maine CDL holder submit a self-certification form or medical certificate to the BMV's CDL Compliance Unit?","options":["By fax, email, or mail to the BMV CDL Compliance Unit","Only in person at the Augusta central office","Only by uploading to the FMCSA Training Provider Registry","Only through the driver's employer or motor carrier"],"answer":0,"explanation":"Maine accepts the MVE-64C self-certification and the medical certificate by fax, by email (PDF/Word) to the CDL Compliance Unit, or by mail to the BMV CDL Compliance Unit in Augusta. Source: Maine BMV CDL Compliance Unit submission instructions.","handbook":"","hbref":""},{"q":"Before a person can be issued a Maine Commercial Learner's Permit (CLP), which knowledge test must be passed at minimum?","options":["The General Knowledge test","The Air Brakes endorsement test only","The Hazardous Materials test","The pre-trip inspection skills test"],"answer":0,"explanation":"The General Knowledge test (plus any endorsement tests the applicant seeks) must be passed to obtain a CLP. The Maine BMV publishes the official CDL manual on which these tests are based. Source: Maine CDL Manual; Maine BMV CDL Exam page.","handbook":"","hbref":""},{"q":"What is the minimum passing score on each Maine CDL knowledge test?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"A driver must correctly answer at least 80% of the questions on each knowledge test to pass. Source: Maine CDL Manual; 49 CFR 383.135.","handbook":"","hbref":""},{"q":"The Maine CDL skills test consists of which three parts, in order?","options":["Pre-trip vehicle inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Air brake check, backing, and a written endorsement exam","Basic vehicle control, parallel parking, and a hazmat interview"],"answer":0,"explanation":"The CDL skills test has three parts administered in this order: the pre-trip vehicle inspection, the basic vehicle control test, and the on-road driving test. Source: Maine CDL Manual; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"Which skills-test component requires a Maine applicant to perform maneuvers such as straight-line backing, offset backing, and alley docking?","options":["The basic vehicle control test","The pre-trip vehicle inspection","The on-road driving test","The General Knowledge test"],"answer":0,"explanation":"Backing maneuvers like straight-line backing, offset backing, and alley docking are evaluated in the basic vehicle control portion of the skills test. Source: Maine CDL Manual; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"A first-time Class A CDL applicant in Maine must complete Entry-Level Driver Training (ELDT) from a provider that is:","options":["Listed on the FMCSA Training Provider Registry (TPR)","Approved only by the Maine BMV examiner pool","Certified by the local community college system","Registered with MaineDOT's permit office"],"answer":0,"explanation":"ELDT must be obtained from a provider listed on the FMCSA Training Provider Registry; the provider reports completion electronically to FMCSA. Source: Maine BMV ELDT page; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"For which of the following does Maine require ELDT before testing?","options":["A first-time Class A or B CDL, or a first-time P, S, or H endorsement","Every CDL renewal regardless of class","Only Hazardous Materials (H) endorsement applicants","Only drivers upgrading from Class B to Class A"],"answer":0,"explanation":"ELDT is required for obtaining a Class A or Class B CDL for the first time, upgrading to a higher class, or obtaining a passenger (P), school bus (S), or hazardous materials (H) endorsement for the first time. Source: Maine BMV ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When must a Maine CDL applicant complete the required ELDT?","options":["Before taking the relevant knowledge or skills test","After passing the skills test but before the license prints","Within 30 days after the CDL is issued","Only after the CLP's 14-day hold expires"],"answer":0,"explanation":"ELDT theory must be completed before the knowledge test for an H endorsement, and behind-the-wheel training before the skills test for Class A/B and P/S endorsements. Training must precede the applicable test. Source: Maine BMV ELDT page; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"After receiving a CLP, how long must a Maine applicant hold it before being allowed to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"A CLP holder must wait a minimum of 14 days after the permit is issued before taking the skills test. Source: Maine BMV CDL pages; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"When operating under a Maine CLP, the permit holder must be accompanied by:","options":["A CDL holder, valid for that vehicle's class and endorsements, seated next to the driver","Any licensed driver age 21 or older","A BMV examiner only","No one, provided the vehicle is empty"],"answer":0,"explanation":"A CLP holder may operate a commercial motor vehicle only when accompanied by a person who holds a valid CDL for that class of vehicle, seated in the front seat beside the permit holder. Source: Maine CDL Manual; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"For most Maine CDL holders under age 65, how often must the CDL be renewed?","options":["Every 5 years","Every 4 years","Every 6 years","Every 8 years"],"answer":0,"explanation":"A Maine CDL is issued for a 5-year cycle for holders under 65. (Holders 65 or older renew on a 4-year cycle.) Source: Maine BMV CDL renewal information.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Maine CDL to drive only intrastate (within Maine)?","options":["18","21","19","16"],"answer":0,"explanation":"An applicant must be at least 18 to obtain a Maine CDL for intrastate driving; 21 is required for interstate driving, transporting hazardous materials, or carrying passengers. Source: Maine CDL Manual; Maine BMV CDL pages.","handbook":"","hbref":""},{"q":"Which set of documents would a Maine applicant typically need to establish identity and eligibility when applying for a CDL?","options":["Proof of identity, legal U.S. presence, Social Security number, and Maine residency","Only a current Maine non-commercial driver's license","A passport plus a MaineDOT oversize permit","An employer letter and a vehicle registration only"],"answer":0,"explanation":"Applicants must document identity, lawful presence in the U.S., a Social Security number, and Maine residency, in addition to meeting the medical and self-certification requirements. Source: Maine BMV CDL application requirements.","handbook":"","hbref":""},{"q":"If a Maine driver lets the required medical certificate lapse so it is no longer on file with the BMV, what is the likely consequence?","options":["The driver's CDL privilege is downgraded (commercial privileges removed) until a valid certificate is filed","Nothing changes until the CDL's normal renewal date","The CDL is permanently revoked with no path to reinstatement","Only a written warning is issued with no effect on the license"],"answer":0,"explanation":"If a non-excepted driver's medical certificate expires and is not updated with the BMV, the state must downgrade the CDL by removing commercial driving privileges until a current certificate is submitted. Source: Maine BMV CDL Compliance guidance; 49 CFR 383.73.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимально допустимая общая ширина транспортного средства на дорогах общего пользования штата Мэн без специального разрешения?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Согласно 29-A M.R.S. §2380, транспортное средство общей шириной более 102 inches (8'6\") не может эксплуатироваться на дороге общего пользования или мосту штата Мэн без разрешения. Источник: Maine Revised Statutes Title 29-A, §2380."},"1":{"q":"Какова максимально допустимая по закону конструктивная высота транспортного средства на автомагистралях штата Мэн без разрешения на превышение лимита?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"29-A M.R.S. §2380 запрещает эксплуатацию транспортного средства, у которого постоянная или временная конструктивная часть превышает 13 feet 6 inches в высоту. Неуменьшаемый груз может выступать на величину до 6 inches выше этого предела, но конструктивный лимит составляет 13'6\". Источник: Maine Revised Statutes Title 29-A, §2380."},"2":{"q":"В штате Мэн некоторые боковые элементы (такие как зеркала и брызговики) исключаются из измерения ширины только в том случае, если они выступают за боковую сторону транспортного средства не более чем на какую величину?","options":["2 inches","3 inches","6 inches","9 inches"],"explanation":"29-A M.R.S. §2380 исключает указанные элементы (зеркала, дверные петли, водосточные желоба, брызговики и т. д.) из измерения ширины в 102 inches при условии, что они выступают не более чем на 3 inches от боковой стороны транспортного средства. Источник: Maine Revised Statutes Title 29-A, §2380."},"3":{"q":"Каков максимальный полный вес автопоезда с пятью или более осями на дорогах общего пользования штата Мэн (не межштатных автомагистралях) согласно стандартным весовым ограничениям?","options":["69,000 pounds","73,280 pounds","80,000 pounds","90,000 pounds"],"explanation":"Согласно 29-A M.R.S. §2353, максимальный полный вес для автопоезда с пятью или более осями составляет 80,000 pounds (двухосное транспортное средство ограничено 34,000, трёхосное — 54,000, а четырёхосное — 69,000). Источник: Maine Revised Statutes Title 29-A, §2353."},"4":{"q":"Согласно стандартным весовым ограничениям штата Мэн (не межштатным) в §2353, какова максимально допустимая нагрузка на одиночную ось?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"29-A M.R.S. §2353 устанавливает лимит для одиночной оси в 22,400 pounds на общей дорожной сети штата Мэн, что выше федерального показателя в 20,000 pounds для одиночной оси на межштатных автомагистралях. Источник: Maine Revised Statutes Title 29-A, §2353."},"5":{"q":"На общей дорожной сети штата Мэн (§2353) какова максимально допустимая нагрузка на сдвоенную ось (тандем)?","options":["34,000 pounds","36,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"29-A M.R.S. §2353 допускает 38,000 pounds на сдвоенную ось (тандем) на дорогах общего пользования штата Мэн, что превышает лимит тандема в 34,000 pounds, применяемый на системе межштатных автомагистралей согласно §2355. Источник: Maine Revised Statutes Title 29-A, §2353."},"6":{"q":"На системе межштатных автомагистралей в штате Мэн какова максимально допустимая нагрузка на сдвоенную ось (тандем)?","options":["32,000 pounds","34,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"29-A M.R.S. §2355 ограничивает нагрузку на сдвоенную ось (тандем) до 34,000 pounds на системе межштатных автомагистралей, что соответствует федеральному стандарту. Дороги общего пользования штата Мэн допускают более высокий тандем в 38,000 pounds согласно §2353. Источник: Maine Revised Statutes Title 29-A, §2355."},"7":{"q":"На межштатной системе штата Мэн транспортное средство с полной массой более 73,280 pounds ограничено какой нагрузкой на одиночную ось?","options":["18,000 pounds","20,000 pounds","22,000 pounds","22,400 pounds"],"explanation":"29-A M.R.S. §2355 ограничивает одиночную ось до 20,000 pounds, когда полная масса превышает 73,280 pounds (и до 22,000 pounds, когда полная масса составляет 73,280 или меньше) на системе межштатных автомагистралей. Источник: Maine Revised Statutes Title 29-A, §2355."},"8":{"q":"На межштатной системе штата Мэн транспортное средство с полной массой 73,280 pounds или менее может иметь какую максимальную нагрузку на одиночную ось?","options":["20,000 pounds","22,000 pounds","22,400 pounds","24,200 pounds"],"explanation":"29-A M.R.S. §2355 допускает нагрузку на одиночную ось до 22,000 pounds, когда полная масса составляет 73,280 pounds или менее на межштатной автомагистрали, снижаясь до 20,000 pounds, когда полная масса превышает 73,280. Источник: Maine Revised Statutes Title 29-A, §2355."},"9":{"q":"В федеральной формуле моста, используемой на межштатной системе штата Мэн, W = 500(LN/(N-1) + 12N + 36), что обозначает переменная \"L\"?","options":["Длину груза в футах","Расстояние в футах между крайними осями группы","Допустимый по закону вес на ось в тысячах фунтов","Количество загруженных осей на транспортном средстве"],"explanation":"В федеральной Bridge Formula B, применяемой согласно 29-A M.R.S. §2355, W — это допустимый полный вес на группу осей, N — количество осей в группе, а L — расстояние в футах между крайними (внешними) осями этой группы. Источник: Maine Revised Statutes Title 29-A, §2355 (federal bridge formula)."},"10":{"q":"Шестиосный автопоезд в штате Мэн (трёхосный тягач с трёхосным полуприцепом) может достигать максимального полного веса до какой величины при соблюдении всех условий?","options":["80,000 pounds","90,000 pounds","100,000 pounds","120,000 pounds"],"explanation":"29-A M.R.S. §2354 разрешает шестиосному автопоезду (трёхосный грузовой тягач с трёхосным полуприцепом) до 100,000 pounds при соблюдении требований к расстоянию между осями и других условий; базовый лимит составляет 90,000 pounds. Источник: Maine Revised Statutes Title 29-A, §2354."},"11":{"q":"Для шестиосного автопоезда штата Мэн весом 100,000 pounds расстояние между крайними осями (исключая рулевую ось) должно составлять не менее скольких футов?","options":["30 feet","32 feet","36 feet","40 feet"],"explanation":"29-A M.R.S. §2354 требует, чтобы расстояние между крайними осями (исключая рулевую ось) было не менее 36 feet; максимальный полный вес уменьшается на 2,000 pounds за каждый фут, на который это расстояние меньше 36 feet. Источник: Maine Revised Statutes Title 29-A, §2354."},"12":{"q":"Согласно закону штата Мэн о шестиосных весах, на сколько уменьшается максимальный полный вес за каждый фут, на который расстояние между крайними осями оказывается ниже требуемого минимума?","options":["1,000 pounds per foot","1,500 pounds per foot","2,000 pounds per foot","2,500 pounds per foot"],"explanation":"29-A M.R.S. §2354 уменьшает максимально допустимый полный вес шестиосного автопоезда на 2,000 pounds за каждый фут, на который расстояние между крайними осями меньше требуемых 36 feet. Источник: Maine Revised Statutes Title 29-A, §2354."},"13":{"q":"Закон штата Мэн о допуске по весу (§2357) разрешает соответствующим грузам (например, древесной продукции, дорожной соли, гравию) превышать максимальный полный вес на какую величину?","options":["До 5% сверх максимума","До 10% (110% от максимума)","До 15% сверх максимума","До 2,000 pounds сверх максимума"],"explanation":"29-A M.R.S. §2357 предусматривает, что соответствующее транспортное средство не нарушает закон, если его полная масса не превышает 110% (на 10% сверх) максимального полного веса по §2353, для перечисленных товаров, таких как древесная продукция, гравий, дорожная соль и аналогичные сыпучие материалы. Источник: Maine Revised Statutes Title 29-A, §2357."},"14":{"q":"Допуск по весу в 10% штата Мэн для определённых товаров (§2357) применяется на каких дорогах?","options":["Только на системе межштатных автомагистралей","На всех дорогах штата Мэн, кроме системы межштатных автомагистралей","Только на платной автомагистрали Maine Turnpike","На всех дорогах штата Мэн, включая межштатные"],"explanation":"29-A M.R.S. §2357 прямо указывает, что допуск по весу не применяется к транспортному средству, эксплуатируемому на системе межштатных автомагистралей; он доступен на дорогах общего пользования штата Мэн (не межштатных). Источник: Maine Revised Statutes Title 29-A, §2357."},"15":{"q":"Какой орган выдаёт разрешения на перемещение с превышением лимитов (негабаритные/перегруженные) по всему штату Мэн, действуя по рекомендации Commissioner of Transportation?","options":["Secretary of State","Maine State Police","Maine Turnpike Authority","Public Utilities Commission"],"explanation":"Согласно 29-A M.R.S. §2382, Secretary of State (через Bureau of Motor Vehicles), действуя по указаниям и рекомендации Commissioner of Transportation, выдаёт разрешения на перемещение с превышением лимитов; округа и муниципалитеты могут разрешать движение по своим собственным дорогам. Источник: Maine Revised Statutes Title 29-A, §2382."},"16":{"q":"В штате Мэн разрешение на превышение лимитов (негабаритный/перегруженный) требуется для перемещения какого вида груза, превышающего допустимые по закону размеры или весовые лимиты?","options":["Любого груза, независимо от того, можно ли его разделить","Только делимых грузов, которые можно разбить на законные единицы","Неделимого объекта, который невозможно уменьшить до законных лимитов","Только грузов, перевозимых по системе межштатных автомагистралей"],"explanation":"29-A M.R.S. §2381 и §2382 разрешают выдачу разрешений для неделимых объектов (тех, которые невозможно разумно уменьшить до законной длины, ширины, высоты или веса). Делимые грузы должны быть разделены до законных лимитов, а не получать разрешение. Источник: Maine Revised Statutes Title 29-A, §§2381–2382."},"17":{"q":"Каков максимальный срок действия долгосрочного разрешения на превышение лимитов, которое Secretary of State штата Мэн может выдать для грузовиков, тягачей и полуприцепов?","options":["30 days","6 months","Один год","Два года"],"explanation":"29-A M.R.S. §2382 позволяет Secretary of State выдавать разрешения, действительные на срок до одного года, для грузовиков, грузовых тягачей, полуприцепов, тяжёлых эвакуаторов и специального самоходного оборудования Class A; в противном случае выдаются разрешения на одну поездку. Источник: Maine Revised Statutes Title 29-A, §2382."},"18":{"q":"Когда полуприцеп штата Мэн длиной 53 фута эксплуатируется вне национальной сети автомагистралей, общая длина транспортного средства и груза не может превышать какую общую длину?","options":["65 feet","69 feet","74 feet","80 feet"],"explanation":"29-A M.R.S. §2390 допускает полуприцеп длиной более 48 feet, но не более 53 feet (при расстоянии от шкворня до задней оси не более 43 feet), однако при эксплуатации вне национальной сети общая длина не может превышать 74 feet. На системе межштатных автомагистралей лимит общей длины не применяется. Источник: Maine Revised Statutes Title 29-A, §2390."},"19":{"q":"Согласно закону штата Мэн, какой класс CDL требуется для управления любым автопоездом с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемое транспортное средство (средства) превышает 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"explanation":"Мэн определяет Class A как любой автопоезд с GCWR 26,001 или более pounds при условии, что GVWR/полная масса буксируемого транспортного средства (средств) превышает 10,000 pounds. Источник: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"20":{"q":"Водитель в штате Мэн управляет одиночным цельным грузовиком с полной разрешённой массой 30,000 pounds и не буксирует прицеп. Какой класс CDL для этого требуется?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Class B штата Мэн охватывает любое одиночное транспортное средство с GVWR 26,001 или более pounds, либо такое транспортное средство, буксирующее единицу не более 10,000 pounds. Одиночная единица весом 30,000 pounds относится к Class B. Источник: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"21":{"q":"В штате Мэн транспортное средство, которое не соответствует весовым определениям Class A или Class B, но предназначено для перевозки 16 или более пассажиров (включая водителя) или перевозит опасные материалы, требующие табличек, относится к какому классу CDL?","options":["Class A","Class B","Class C","Class M"],"explanation":"Class C штата Мэн — это любое одиночное транспортное средство или автопоезд, не соответствующий Class A/B, который предназначен для перевозки 16 или более пассажиров (включая водителя) либо перевозит опасные материалы, требующие табличек. Источник: Maine CDL Manual, 'Definitions of Classes' and Figure 1.1; 29-A MRSA §1253."},"22":{"q":"Согласно Maine CDL Manual, какое дополнительное удостоверение (endorsement) требуется для управления транспортными средствами, перевозящими опасные материалы, когда груз должен иметь таблички согласно федеральным правилам DOT?","options":["Удостоверение N","Удостоверение H","Удостоверение T","Удостоверение X"],"explanation":"Мэн использует удостоверение H для управления транспортными средствами, перевозящими опасные материалы, когда требуются таблички согласно федеральным правилам DOT. Удостоверение X объединяет цистерну (N) и hazmat (H). Источник: Maine CDL Manual, 'Endorsements.'"},"23":{"q":"Что разрешает удостоверение 'X' на CDL штата Мэн?","options":["Управление только автоцистернами","Управление автоцистернами, перевозящими опасные материалы (объединяет N и H)","Управление сдвоенными и строенными прицепами","Управление пассажирскими автобусами более чем на 15 пассажиров"],"explanation":"Удостоверение X штата Мэн предназначено для управления автоцистернами, перевозящими опасные материалы, объединяя удостоверения N (цистерна) и H (hazmat) в одно. Источник: Maine CDL Manual, 'Endorsements.'"},"24":{"q":"Maine CDL Manual отмечает особое ограничение в отношении удостоверения 'T' (сдвоенные/строенные прицепы). Какое утверждение верно для штата Мэн?","options":["Как сдвоенные, так и строенные прицепы можно свободно эксплуатировать по всему штату","Строенные прицепы не разрешены в штате Мэн","Удостоверение T также разрешает автоцистерны","Сдвоенные прицепы требуют отдельного пассажирского экзамена"],"explanation":"Maine CDL Manual описывает удостоверение T как предназначенное для сдвоенных/строенных прицепов 'где это разрешено законом' и прямо указывает, что строенные прицепы не разрешены в штате Мэн. Источник: Maine CDL Manual, 'Endorsements.'"},"25":{"q":"Согласно Maine CDL Manual, удостоверение N (автоцистерна) требуется для перевозки жидкости или сжиженного газа в стационарно установленной грузовой цистерне с какой минимальной номинальной ёмкостью?","options":["100 gallons or more","119 gallons or more","1,000 gallons or more","450 gallons or more"],"explanation":"Мэн требует экзамен/удостоверение для автоцистерны (N) для перевозки жидкости или сжиженного газа в стационарно установленной грузовой цистерне с номинальной ёмкостью 119 gallons or more, либо в переносной цистерне с номинальной ёмкостью 1,000 gallons or more. Источник: Maine CDL Manual, '1.1.1 Knowledge Tests' and tank vehicle section."},"26":{"q":"В штате Мэн успешная сдача на какое удостоверение автоматически также даёт удостоверение 'P' (пассажирское) без дополнительной платы или дальнейшего экзамена?","options":["H (Hazardous Materials)","N (Tank Vehicle)","S (School Bus)","T (Doubles/Triples)"],"explanation":"Maine CDL Manual указывает, что успешная сдача на удостоверение S (школьный автобус) также даёт удостоверение P (пассажирское) без дополнительной платы или дальнейшего экзамена. Источник: Maine CDL Manual, 'Endorsements.'"},"27":{"q":"Согласно Maine CDL Manual, какие удостоверения присваиваются при сдаче только теоретического (письменного) экзамена, без необходимости отдельного экзамена по навыкам вождения?","options":["P и S","N, H, X и T","Только H","Все удостоверения требуют экзамена по навыкам вождения"],"explanation":"Maine CDL Manual указывает, что удостоверения N, H, X и T присваиваются держателю CDL при успешной сдаче только теоретического экзамена; P и S требуют полного экзамена, включая проверку навыков вождения. Источник: Maine CDL Manual, 'Endorsements.'"},"28":{"q":"Мэн признаёт удостоверение '3' для одного вида эксплуатации школьного автобуса, который НЕ требует от водителя наличия CDL. Этот автобус предназначен для перевозки скольких пассажиров?","options":["16 или более пассажиров, включая водителя","15 пассажиров или менее, включая водителя","Ровно 24 пассажира","Более 15 пассажиров, не считая водителя"],"explanation":"Maine CDL Manual описывает удостоверение '3' для школьного автобуса, предназначенного для перевозки 15 пассажиров или менее (включая водителя); оно может быть добавлено к некоммерческим правам и не требует CDL. Источник: Maine CDL Manual, '\"3\" endorsement.'"},"29":{"q":"Согласно правилам CDL штата Мэн, каков минимальный возраст для управления коммерческим транспортным средством во внутриштатных перевозках (только в пределах штата Мэн)?","options":["16 years","18 years","21 years","19 years"],"explanation":"Минимальный возраст для внутриштатного CDL в штате Мэн составляет 18. (Более старый текст Maine CDL Manual ссылается на возраст 16 для некоторых внутриштатных операций, но BMV применяет федеральный минимум в 18 для внутриштатной эксплуатации по CDL.) Источник: Maine BMV / FMCSA 49 CFR 391.11; Maine CDL Manual age provisions."},"30":{"q":"Каков минимальный возраст в штате Мэн для получения CDL, действительного для межштатных перевозок (с пересечением границ штатов)?","options":["18 years","19 years","21 years","25 years"],"explanation":"Водитель должен быть не моложе 21 года, чтобы управлять CMV в межштатных перевозках, перевозить опасные материалы или водить пассажирский автобус. Источник: Maine CDL Manual age provisions; FMCSA 49 CFR 391.11."},"31":{"q":"Согласно 29-A MRSA §1304(4-A), держатель коммерческого ученического разрешения (CLP) штата Мэн НЕ имеет права сдавать экзамен по навыкам вождения CDL в течение какого периода после первоначальной выдачи разрешения?","options":["Первые 7 days","Первые 14 days","Первые 30 days","Первые 60 days"],"explanation":"Закон штата Мэн предусматривает, что держатель CLP не имеет права сдавать экзамен по навыкам вождения CDL в первые 14 days после первоначальной выдачи CLP, что соответствует федеральному требованию. Источник: 29-A MRSA §1304(4-A)(I)."},"32":{"q":"Согласно 29-A MRSA §1304, коммерческое ученическое разрешение (CLP) штата Мэн действительно не более какого срока с даты выдачи?","options":["180 days","Один год","Два года","Пять лет"],"explanation":"Закон штата Мэн указывает, что коммерческое ученическое разрешение действительно не более одного года с даты выдачи. Источник: 29-A MRSA §1304(4-A)(G)."},"33":{"q":"При управлении CMV по коммерческому ученическому разрешению штата Мэн держатель CLP должен сопровождаться держателем CDL, который находится где?","options":["В любом месте транспортного средства","Следует в отдельном транспортном средстве","Физически присутствует на переднем сиденье рядом с держателем CLP (либо, в пассажирском транспортном средстве, непосредственно позади или в первом ряду за водителем)","Доступен по телефону во время эксплуатации"],"explanation":"Закон штата Мэн требует, чтобы сопровождающий держатель CDL физически присутствовал на переднем сиденье рядом с держателем CLP, либо в пассажирском транспортном средстве — непосредственно позади или в первом ряду за водителем, имея надлежащий класс и удостоверения. Источник: 29-A MRSA §1304(4-A)(A)."},"34":{"q":"Какая деятельность прямо запрещена для держателя коммерческого ученического разрешения штата Мэн согласно 29-A MRSA §1304(4-A)?","options":["Управление коммерческим транспортным средством, перевозящим опасные материалы","Вождение в дневное время","Управление транспортным средством Class B","Практика на межштатных автомагистралях"],"explanation":"Закон штата Мэн запрещает держателю CLP управлять CMV, перевозящим опасные материалы, как определено в 49 CFR §383.5. Источник: 29-A MRSA §1304(4-A)(F)."},"35":{"q":"Согласно 29-A MRSA §1304(4-A), какого минимального возраста должен быть держатель CLP штата Мэн, чтобы подать заявку на удостоверение пассажирское (P) или школьного автобуса (S)?","options":["18 years","20 years","21 years","22 years"],"explanation":"Закон штата Мэн требует, чтобы держатель CLP был не моложе 21 года для подачи заявки на пассажирское удостоверение или удостоверение школьного автобуса, а сопровождающий держатель CDL должен иметь пассажирское удостоверение, не менее одного года опыта и быть не моложе 22. Источник: 29-A MRSA §1304(4-A)(E)."},"36":{"q":"Требование о начальном обучении водителей (ELDT), применимое к новым заявителям на CDL в штате Мэн, проверяется через какую систему?","options":["Онлайн-портал Maine BMV","FMCSA Training Provider Registry (TPR)","National Driver Register","База данных TSA Secure Flight"],"explanation":"С 7 февраля 2022 года правило ELDT FMCSA требует обучения для новых операторов CDL и определённых повышений категории, проведённого провайдером, внесённым в реестр и зарегистрированным в FMCSA Training Provider Registry (tpr.fmcsa.dot.gov). Источник: Maine CDL Manual, 'Entry Level Driver Training (ELDT)'; FMCSA 49 CFR Part 380."},"37":{"q":"При подаче заявки на CDL штата Мэн заявитель должен самостоятельно удостоверить один вид водительской деятельности. Какой набор правильно перечисляет четыре федеральные категории самостоятельного удостоверения, используемые в штате Мэн?","options":["Местные, региональные, национальные и международные","Неисключённые межштатные, исключённые межштатные, неисключённые внутриштатные и исключённые внутриштатные","Коммерческие, частные, сельскохозяйственные и аварийные","Операции Class A, Class B, Class C и Class D"],"explanation":"Мэн, следуя 49 CFR §383.71, требует, чтобы заявители на CDL самостоятельно удостоверили одну из четырёх категорий: неисключённые межштатные, исключённые межштатные, неисключённые внутриштатные или исключённые внутриштатные. Неисключённые категории требуют действительной справки медицинского эксперта. Источник: FMCSA 49 CFR §383.71; Maine BMV."},"38":{"q":"Помимо документов, удостоверяющих личность, место жительства и законность пребывания, какой дополнительный элемент должен раскрыть заявитель на CDL штата Мэн, как предписано 29-A MRSA для выдачи водительских прав?","options":["Номер паспорта","Номер Social Security","Карточку регистрации избирателя","Свидетельство о праве собственности на транспортное средство"],"explanation":"Заявление о раскрытии номера Social Security в Maine CDL Manual отмечает, что раскрытие SSN является обязательным и требуется согласно 29-A MRSA для подачи заявки или продления водительских прав; BMV также требует подтверждения личности, проживания в штате Мэн и законности пребывания. Источник: Maine CDL Manual, 'Social Security Number Disclosure Statement'; 29-A MRSA."},"39":{"q":"Согласно правилам CDL штата Мэн, при какой концентрации алкоголя в крови (BAC) запрещено управлять коммерческим транспортным средством?","options":["0.04% or more","0.08% or more","0.02% or more","0.10% or more"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что управлять CMV запрещено, если ваш BAC составляет .04% or more. Этот лимит 0.04 составляет половину от лимита 0.08 для обычных водителей и соответствует федеральному стандарту 49 CFR 383.51."},"40":{"q":"Управляя коммерческим транспортным средством в штате Мэн, водитель по закону считается совершившим что?","options":["Отказ от права на адвоката защиты","Дачу согласия на тестирование на алкоголь","Согласие на обыск транспортного средства в любое время","Согласие на случайный еженедельный анализ мочи на наркотики"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает: 'Если вы управляете CMV, вы считаетесь давшим своё согласие на тестирование на алкоголь.' Это правило подразумеваемого согласия штата Мэн для управления CMV (см. также 29-A M.R.S. 2521)."},"41":{"q":"За первое серьёзное правонарушение (например, управление CMV с BAC .04% или выше) на какой срок водитель в штате Мэн лишится своего CDL?","options":["Не менее 60 days","Не менее 6 months","Не менее 1 year","Не менее 90 days"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что вы лишитесь своего CDL не менее чем на один год за первое серьёзное правонарушение, включая управление CMV с BAC .04% или выше. Это соответствует федеральному стандарту 49 CFR 383.51."},"42":{"q":"В штате Мэн что происходит с держателем CDL, который отказывается пройти тестирование крови на алкоголь, когда это требуется при управлении CMV (первое нарушение)?","options":["Предупреждение без дисквалификации","Потеря CDL на 30 days","Потеря CDL на 120 days","Потеря CDL не менее чем на 1 year"],"explanation":"Maine CDL Manual (Section 1.2.2) относит 'отказ пройти тестирование крови на алкоголь' к первому серьёзному правонарушению, влекущему потерю CDL не менее чем на один год (3 года, если транспортное средство имеет таблички для опасных материалов)."},"43":{"q":"Если первое серьёзное правонарушение (например, вождение в состоянии опьянения) совершено в то время, когда водитель в штате Мэн управляет CMV с табличками для опасных материалов, CDL теряется не менее чем на какой срок?","options":["3 years","1 year","5 years","Пожизненно"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что вы лишитесь своего CDL не менее чем на три года, если первое серьёзное правонарушение совершено в то время, когда вы управляете CMV с табличками для опасных материалов, согласно 49 CFR 383.51."},"44":{"q":"Каковы последствия в штате Мэн за второе серьёзное правонарушение (например, второе вождение в состоянии опьянения на CMV)?","options":["Потеря CDL на 10 years","Потеря CDL пожизненно","Потеря CDL на 3 years","Потеря CDL на 5 years"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что вы лишитесь своего CDL пожизненно за второе серьёзное правонарушение. Эта пожизненная дисквалификация следует федеральному стандарту 49 CFR 383.51."},"45":{"q":"Согласно правилам штата Мэн, какое наказание предусмотрено за использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами?","options":["Потеря CDL на 1 year","Потеря CDL на 3 years","Пожизненная потеря CDL","Потеря CDL на 120 days"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что вы лишитесь своего CDL пожизненно, если используете CMV для совершения тяжкого преступления, связанного с контролируемыми веществами. Восстановление за это правонарушение невозможно."},"46":{"q":"В штате Мэн водитель с обнаруживаемым количеством алкоголя ниже .04% при управлении CMV будет:","options":["Дисквалифицирован на 60 days","Оштрафован на $5,000","Автоматически арестован за OUI","Выведен из эксплуатации (out-of-service) на 24 hours"],"explanation":"Maine CDL Manual (Section 1.2.2) указывает, что вы будете выведены из эксплуатации (out-of-service) на 24 hours, если у вас обнаруживается любое количество алкоголя ниже .04%. Для полной дисквалификации требуется BAC .04% or more."},"47":{"q":"Что из перечисленного классифицируется как 'серьёзное нарушение правил дорожного движения' в Maine CDL Manual?","options":["Чрезмерное превышение скорости (на 15 mph или более выше установленного лимита)","Движение на 5 mph выше установленного лимита","Просроченная регистрация транспортного средства","Одно нарушение правил парковки"],"explanation":"Maine CDL Manual (Section 1.2.3) определяет чрезмерное превышение скорости как 15 mph или более выше установленного лимита и относит его к серьёзным нарушениям правил дорожного движения наряду с безрассудным вождением, неправильной сменой полосы и движением на слишком близком расстоянии."},"48":{"q":"На какой срок водитель в штате Мэн лишится своего CDL за совершение ДВУХ серьёзных нарушений правил дорожного движения на CMV в течение трёхлетнего периода?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Maine CDL Manual (Section 1.2.3) указывает, что вы лишитесь своего CDL не менее чем на 60 days за два серьёзных нарушения правил дорожного движения в течение трёхлетнего периода с участием CMV, согласно 49 CFR 383.51."},"49":{"q":"На какой срок водитель в штате Мэн лишится своего CDL за совершение ТРЁХ или более серьёзных нарушений правил дорожного движения на CMV в течение трёхлетнего периода?","options":["Не менее 60 days","Не менее 90 days","Не менее 120 days","Не менее 1 year"],"explanation":"Maine CDL Manual (Section 1.2.3) указывает, что вы лишитесь своего CDL не менее чем на 120 days за три или более серьёзных нарушений правил дорожного движения в течение трёхлетнего периода с участием CMV, согласно 49 CFR 383.51."},"50":{"q":"Что из перечисленного указано среди серьёзных нарушений правил дорожного движения в Maine CDL Manual?","options":["Неиспользование указателя поворота на парковке","Вождение с одной неработающей фарой","Перевозка незакреплённого груза менее 500 pounds","Управление CMV без получения CDL или без наличия его при себе"],"explanation":"Maine CDL Manual (Section 1.2.3) относит управление CMV без получения CDL, без наличия CDL при себе или без надлежащего класса/удостоверений к серьёзным нарушениям правил дорожного движения."},"51":{"q":"Согласно федеральным правилам, принятым в штате Мэн, отправка текстовых сообщений при вождении CMV и использование ручного мобильного телефона рассматриваются как:","options":["Серьёзные нарушения правил дорожного движения","Серьёзные правонарушения с дисквалификацией на 1 year","Нарушения предписания о выводе из эксплуатации (out-of-service)","Недисквалифицирующие нарушения"],"explanation":"Согласно 49 CFR 383.51, отправка текстовых сообщений (49 CFR 392.80) и использование ручного мобильного телефона (49 CFR 392.82) при вождении CMV являются серьёзными нарушениями правил дорожного движения. Два за три года влекут дисквалификацию на 60 days; три влекут 120 days. Мэн принимает эти федеральные стандарты."},"52":{"q":"Согласно федеральным правилам о ручных телефонах, применяемым к водителям CDL штата Мэн, единичное обвинение в отправке текстовых сообщений или использовании ручного телефона также может повлечь гражданский штраф для водителя в размере до:","options":["$500","$2,750","$11,000","$250"],"explanation":"Согласно правилам FMCSA (49 CFR 392.80/392.82), применяемым в штате Мэн, водителю грозит гражданский штраф до $2,750 за каждое нарушение, связанное с отправкой текстовых сообщений или использованием ручного телефона; работодателям, которые это допускают, грозят штрафы до $11,000. Два таких обвинения за 3 года также дисквалифицируют CDL на 60 days."},"53":{"q":"Согласно Maine CDL Manual, на какой срок водитель лишится своего CDL за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service)?","options":["Не менее 60 days","Не менее 30 days","Не менее 90 days","Не менее 1 year"],"explanation":"Maine CDL Manual (Section 1.2.4) указывает, что вы лишитесь своего CDL не менее чем на 90 days за первое нарушение предписания о выводе из эксплуатации. (Действующий федеральный 49 CFR 383.51 Table 4 устанавливает минимум в 180 days, но опубликованное руководство штата Мэн указывает 90 days.)"},"54":{"q":"Согласно Maine CDL Manual, на какой срок водитель лишится своего CDL за ДВА нарушения предписания о выводе из эксплуатации (out-of-service) в течение десятилетнего периода?","options":["Не менее 90 days","Не менее 6 months","Не менее 3 years","Не менее 1 year"],"explanation":"Maine CDL Manual (Section 1.2.4) указывает, что вы лишитесь своего CDL не менее чем на один год за два нарушения предписания о выводе из эксплуатации в течение десятилетнего периода. Третье в течение десяти лет влечёт не менее трёх лет."},"55":{"q":"Согласно Maine CDL Manual, на какой срок водитель лишится своего CDL за ТРИ или более нарушений предписания о выводе из эксплуатации (out-of-service) в течение десятилетнего периода?","options":["Не менее 3 years","Не менее 1 year","Пожизненно","Не менее 120 days"],"explanation":"Maine CDL Manual (Section 1.2.4) указывает, что вы лишитесь своего CDL не менее чем на три года за три или более нарушений предписания о выводе из эксплуатации в течение десятилетнего периода."},"56":{"q":"Согласно Maine CDL Manual, на какой срок водитель лишится своего CDL за ПЕРВОЕ нарушение на железнодорожном переезде?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Maine CDL Manual (Section 1.2.5) указывает, что вы лишитесь своего CDL не менее чем на 60 days за первое нарушение на железнодорожном переезде, согласно 49 CFR 383.51."},"57":{"q":"Согласно Maine CDL Manual, какова дисквалификация за ТРЕТЬЕ нарушение на железнодорожном переезде в течение трёхлетнего периода?","options":["Не менее 120 days","Не менее 60 days","Не менее 1 year","Не менее 90 days"],"explanation":"Maine CDL Manual (Section 1.2.5) указывает, что вы лишитесь своего CDL не менее чем на один год за третье нарушение на железнодорожном переезде в течение трёхлетнего периода (первое — 60 days, второе — 120 days)."},"58":{"q":"В штате Мэн, если право вождения личного транспортного средства держателя CDL аннулировано, отменено или приостановлено из-за нарушения, связанного с алкоголем, контролируемыми веществами или тяжким преступлением, что происходит с CDL?","options":["Никаких последствий, потому что это произошло на личном транспортном средстве","Потеря CDL только на 60 days","Немедленная пожизненная дисквалификация за первое нарушение","Потеря CDL на 1 year (пожизненно за второе такое нарушение)"],"explanation":"Maine CDL Manual (Section 1.2.7), отражая Motor Carrier Safety Improvement Act, указывает, что если право вождения вашего личного транспортного средства аннулировано/отменено/приостановлено за нарушения, связанные с алкоголем, контролируемыми веществами или тяжким преступлением, вы теряете свой CDL на 1 year, а за второе такое нарушение — пожизненно. CDL по причине трудностей (hardship) не предоставляется."},"59":{"q":"Согласно закону штата Мэн «Move Over» (об уступлении дороги), когда вы приближаетесь к остановившемуся аварийному или служебному автомобилю с включенными проблесковыми маячками на многополосной дороге, каким должно быть ваше ПЕРВОЕ обязательное действие, если его можно выполнить безопасно?","options":["Перестроиться из полосы, прилегающей к остановившемуся автомобилю, в неприлегающую полосу","Полностью остановиться и ждать, пока аварийный автомобиль не покинет место","Подать звуковой сигнал и продолжать движение с установленной разрешённой скоростью","Съехать на правую обочину и ждать, пока вас не пропустят жестом"],"explanation":"Закон штата Мэн «Move Over» (29-A MRSA Sec. 2054(9) и Sec. 2070(8) для неподвижных/неисправных автомобилей) требует, чтобы водитель по возможности проезжал по полосе, НЕ прилегающей к остановившемуся автомобилю; только если сменить полосу невозможно или небезопасно, разрешается проезжать со сниженной, осторожной и разумной скоростью. Источник: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070."},"60":{"q":"На двухполосной дороге, где перестроиться в неприлегающую полосу невозможно, закон штата Мэн «Move Over» требует, чтобы водитель, проезжающий мимо остановившегося аварийного или неисправного автомобиля, сделал что?","options":["Полностью остановился перед тем, как проехать мимо автомобиля","Поддерживал как минимум установленную минимальную разрешённую скорость","Проезжал с осторожной и разумной скоростью, безопасной для проезда мимо автомобиля","Снизил скорость ровно на 20 mph ниже установленного ограничения"],"explanation":"Когда смена полосы невозможна или небезопасна, 29-A MRSA Sec. 2070(8)(B) (и Sec. 2054) требует проезжать с «осторожной и разумной скоростью, безопасной для проезда мимо автомобиля». В штате Мэн не указано точное значение в mph. Источник: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"61":{"q":"Закон штата Мэн «Move Over» был расширен в 2023 году. Помимо уполномоченных аварийных и общественных служебных автомобилей, обязанность перестроиться или снизить скорость теперь также применяется при проезде мимо:","options":["Только обозначенных полицейских патрульных машин и машин скорой помощи","Любого неподвижного автомобиля, о котором разумный человек заключил бы, что он неисправен или использует проблесковые маячки","Только эвакуаторов и автомобилей дорожно-эксплуатационных служб","Только автомобилей, выставивших красный предупреждающий флажок"],"explanation":"29-A MRSA Sec. 2070(8), принятый в соответствии с PL 2023 c. 122, распространяет обязанность перестроения/снижения скорости на любой неподвижный автомобиль, о котором разумный человек заключил бы, что он неисправен, или который использует проблесковые маячки для предупреждения о своём присутствии. Источник: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"62":{"q":"Каков минимальный штраф, назначаемый за нарушение требования штата Мэн перестроиться / проехать мимо неподвижного автомобиля?","options":["$135","$500","$1,000","$275"],"explanation":"29-A MRSA Sec. 2070(8) предусматривает, что нарушение является дорожным проступком, за который должен быть назначен штраф не менее $275. Источник: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"63":{"q":"Когда на железнодорожном переезде в штате Мэн установлен знак «крест» без нанесённой белой стоп-линии, автомобиль с табличками об опасных грузах или автобус, который обязан остановиться, должен остановиться в пределах какого расстояния от ближайшего рельса?","options":["Не менее 15 feet и не более 50 feet","Не менее 5 feet и не более 25 feet","Не менее 25 feet и не более 75 feet","Не менее 10 feet и не более 100 feet"],"explanation":"29-A MRSA Sec. 2076(3) требует, чтобы автобусы, перевозящие пассажиров, и автомобили с табличками/маркировкой об опасных грузах и автоцистерны останавливались не менее чем за 15 feet и не более чем за 50 feet от ближайшего рельса. Maine CDL Manual (Sec. 2.15) указывает тот же диапазон от 15 до 50 feet. Источник: Maine Revised Statutes Title 29-A Sec. 2076; Maine CDL Manual."},"64":{"q":"На каком из следующих железнодорожных переездов автобус или автомобиль с табличками об опасных грузах в штате Мэн НЕ обязан останавливаться?","options":["На любом переезде, расположенном за пределами делового района","На переезде с красными мигающими огнями, которые не активированы","На переезде путей, используемых исключительно для промышленного маневрирования, или переезде, обозначенном знаком «exempt» (освобождённый)","На любом переезде на дороге с ограничением 45 mph или менее"],"explanation":"29-A MRSA Sec. 2076 перечисляет исключения из обязательной остановки, включая переезды трамвайных путей, пути, используемые исключительно для промышленного маневрирования, случаи, когда сотрудник или регулировщик даёт указание двигаться, заброшенные переезды с соответствующей маркировкой и переезды, обозначенные знаком «exempt». Источник: Maine Revised Statutes Title 29-A Sec. 2076."},"65":{"q":"Закон штата Мэн (29-A Sec. 2306) предписывает водителю школьного автобуса, приближающемуся к железнодорожному переезду, сделать полную остановку и затем сделать что перед проездом?","options":["Подождать полные 30 секунд независимо от условий","Дважды подать звуковой сигнал и затем продолжать движение","Высадить пассажира, чтобы он выступил в роли регулировщика","Удостовериться вне разумных сомнений, что по пути не приближается поезд"],"explanation":"29-A MRSA Sec. 2306 требует, чтобы водитель школьного автобуса сделал полную остановку (не более чем за 50 feet и не менее чем за 15 feet от ближайшего рельса) и удостоверился вне разумных сомнений, что по пути не приближается поезд, локомотив или иное транспортное средство, прежде чем пересекать переезд. Источник: Maine Revised Statutes Title 29-A Sec. 2306."},"66":{"q":"Школьный автобус в штате Мэн останавливается на двухполосной дороге с включёнными красными мигающими огнями для высадки пассажиров. Что должен сделать водитель автомобиля, приближающегося с ПРОТИВОПОЛОЖНОГО направления?","options":["Снизить скорость до 15 mph и проехать с осторожностью","Остановить автомобиль перед тем, как поравняться с автобусом, и не продолжать движение, пока автобус не тронется или не подаст сигнал","Продолжать движение в обычном режиме, поскольку встречное движение освобождено от этого требования","Остановиться только если дети явно переходят дорогу"],"explanation":"29-A MRSA Sec. 2308(2) требует, чтобы водитель автомобиля, встречающего ИЛИ обгоняющего школьный автобус с любого направления, когда автобус остановлен с включёнными красными мигающими огнями, остановился перед тем, как поравняться с автобусом, и не продолжал движение, пока автобус не возобновит движение или водитель автобуса не подаст сигнал. Источник: Maine Revised Statutes Title 29-A Sec. 2308(2)."},"67":{"q":"Согласно закону штата Мэн о школьных автобусах, на каком типе проезжей части водитель НЕ обязан останавливаться перед школьным автобусом, остановившимся на другой стороне?","options":["На дороге, разделённой бордюром или иным физическим барьером, для автобуса в полосе, отделённой этим барьером","На любой проезжей части с нанесённой двойной жёлтой осевой линией","На любой проезжей части с двумя или более полосами в каждом направлении","На любой проезжей части с установленным ограничением 50 mph или выше"],"explanation":"29-A MRSA Sec. 2308(3) освобождает водителя от остановки только когда дорога разделена бордюром или иным физическим барьером (для автобуса в полосе, отделённой этим барьером), либо на автомагистрали с ограниченным доступом, где пешеходам запрещён переход. Одна лишь нанесённая линия НЕ создаёт такого исключения. Источник: Maine Revised Statutes Title 29-A Sec. 2308(3)."},"68":{"q":"Закон штата Мэн требует, чтобы водитель школьного автобуса включал мигающие предупреждающие огни автобуса как минимум за какое расстояние до остановки для посадки или высадки пассажиров?","options":["50 feet","200 feet","300 feet","100 feet"],"explanation":"29-A MRSA Sec. 2308(1) требует, чтобы водитель школьного автобуса включал мигающие огни как минимум за 100 feet до остановки для посадки или высадки пассажиров и держал их включёнными до завершения посадки или высадки пассажиров. Источник: Maine Revised Statutes Title 29-A Sec. 2308(1)."},"69":{"q":"В штате Мэн незаконный обгон остановившегося школьного автобуса с включёнными красными мигающими огнями классифицируется как что и с каким наказанием за первое нарушение?","options":["Простой дорожный проступок со штрафом $135","Гражданское нарушение без штрафа за первое нарушение","Преступление класса E (Class E) с минимальным штрафом $250","Преступление класса C (Class C) с обязательным тюремным заключением"],"explanation":"29-A MRSA Sec. 2308(6) квалифицирует нарушение подраздела 2 как преступление класса E (Class E), наказуемое минимальным штрафом $250 за первое нарушение, с обязательным приостановлением действия водительского удостоверения на 30 дней за 2-е нарушение в течение 3 лет. Источник: Maine Revised Statutes Title 29-A Sec. 2308(6)."},"70":{"q":"При отсутствии установленных знаков какую максимальную скорость закон штата Мэн устанавливает в деловом или жилом районе?","options":["20 mph","25 mph","30 mph","35 mph"],"explanation":"29-A MRSA Sec. 2074(1) устанавливает максимумы по умолчанию: 15 mph в школьной зоне, 25 mph в деловом или жилом районе либо в застроенной части и 45 mph на всех прочих дорогах общего пользования, каждое «если не установлено иное знаками». Источник: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"71":{"q":"Согласно установленным законом штата Мэн ограничениям скорости по умолчанию (там, где не установлено иное ограничение знаками), какова максимальная скорость на «всех прочих дорогах общего пользования»?","options":["55 mph","50 mph","40 mph","45 mph"],"explanation":"29-A MRSA Sec. 2074(1) устанавливает максимум по умолчанию 45 mph на всех прочих дорогах общего пользования, если не установлено иное знаками (деловой/жилой район — 25 mph; школьная зона — 15 mph). На большинстве пронумерованных автомагистралей установлены более высокие ограничения. Источник: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"72":{"q":"Каково максимальное ограничение скорости на платной автомагистрали штата Мэн (Maine Turnpike, I-95), установленное Управлением платных дорог штата Мэн (Maine Turnpike Authority)?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Правила Maine Turnpike Authority устанавливают общую максимальную скорость на платной автомагистрали 70 mph, с более низкими установленными ограничениями на отдельных южных и северных участках. Источник: Maine Turnpike Authority Policies & Rules."},"73":{"q":"На трёхполосных участках платной автомагистрали штата Мэн (Maine Turnpike) к югу от отметки Mile Marker 44 где разрешено движение грузовиков (включая седельные тягачи)?","options":["Только в одной крайней правой полосе","В любой полосе, включая левую полосу для обгона","Только в двух крайних правых полосах","Только в центральной полосе"],"explanation":"Для улучшения качества воздуха в южном Мэне правила Maine Turnpike Authority ограничивают движение грузовиков (включая седельные тягачи, исключая пикапы) двумя крайними правыми полосами на любом участке платной автомагистрали к югу от отметки Mile Marker 44, имеющем три полосы в каждом направлении. Источник: Maine Turnpike Authority Policies & Rules."},"74":{"q":"Если вы вынуждены остановить коммерческий автомобиль (CMV) на или рядом с дорогой с односторонним движением или разделённой автомагистралью в штате Мэн, Maine CDL Manual предписывает расставить три предупреждающих устройства на каком расстоянии в сторону приближающегося потока?","options":["10 feet, 50 feet и 150 feet","10 feet, 100 feet и 200 feet","25 feet, 100 feet и 300 feet","50 feet, 100 feet и 500 feet"],"explanation":"Maine CDL Manual (Sec. 2.5.1) предписывает при остановке на или рядом с дорогой с односторонним движением или разделённой автомагистралью расставлять предупреждающие устройства на 10 feet, 100 feet и 200 feet в сторону приближающегося потока. Источник: Maine CDL Manual, Section 2."},"75":{"q":"На двухполосной (двусторонней неразделённой) автомагистрали штата Мэн как следует расставлять три обязательных предупреждающих устройства при остановке коммерческого автомобиля (CMV)?","options":["10 feet, 100 feet и 200 feet, все позади автомобиля","На 50 feet, 200 feet и 300 feet только позади автомобиля","Одно устройство в пределах 10 feet и два устройства только на 500 feet позади","В пределах 10 feet от автомобиля, а также на 100 feet впереди и 100 feet позади автомобиля"],"explanation":"Maine CDL Manual (Sec. 2.5.2) предписывает разместить устройство в пределах 10 feet спереди или сзади для обозначения автомобиля, плюс одно на 100 feet позади и одно на 100 feet впереди, на обочине или в занятой полосе. Источник: Maine CDL Manual, Section 2."},"76":{"q":"После остановки коммерческого автомобиля (CMV) на дороге в штате Мэн в течение скольких минут вы должны установить аварийные предупреждающие устройства?","options":["10 минут","5 минут","15 минут","30 минут"],"explanation":"Maine CDL Manual (Sec. 2.5.1) указывает, что если вы вынуждены остановиться на дороге или обочине, вы должны выставить аварийные предупреждающие устройства в течение десяти минут. Источник: Maine CDL Manual, Section 2."},"77":{"q":"Если коммерческий автомобиль (CMV) остановлен сразу за подъёмом или поворотом в штате Мэн, Maine CDL Manual указывает, что заднее предупреждающее устройство следует переставить так, чтобы:","options":["Оно было размещено ровно в 200 feet от автомобиля независимо от поворота","Оно было убрано, поскольку аварийной сигнализации достаточно","Оно предупреждало водителей дальше по дороге, чтобы автомобиль был виден в пределах 500 feet","Оно было размещено на гребне подъёма ровно в 50 feet впереди"],"explanation":"Maine CDL Manual (Sec. 2.5.2) предписывает, что если подъём или поворот ограничивает обзор, нужно отодвинуть крайний задний треугольник дальше по дороге, чтобы обеспечить предупреждение и чтобы другие водители могли увидеть автомобиль в пределах 500 feet. Источник: Maine CDL Manual, Section 2."},"78":{"q":"В штате Мэн груз, превышающий какой из габаритов, как правило, требует разрешения на сверхнормативный (негабаритный) груз от Бюро транспортных средств (Bureau of Motor Vehicles) / MaineDOT?","options":["Ширину более 10 feet 0 inches или высоту более 15 feet 0 inches","Ширину более 8 feet 6 inches или высоту более 13 feet 6 inches","Ширину более 8 feet 0 inches или высоту более 12 feet 0 inches","Ширину более 9 feet 0 inches или высоту более 14 feet 6 inches"],"explanation":"Штат Мэн следует стандартным юридическим пределам 8 feet 6 inches в ширину и 13 feet 6 inches в высоту; грузы, превышающие эти значения, требуют разрешения на сверхнормативный (негабаритный) груз, выдаваемого через программу разрешений на сверхнормативные грузы Maine BMV/MaineDOT. Источник: Maine BMV Overlimit Permits / MaineDOT."},"79":{"q":"Какое ведомство штата Мэн выдаёт коммерческие водительские удостоверения (CDL) и проводит экзамены на CDL?","options":["Бюро транспортных средств штата Мэн (Maine BMV) в составе офиса Государственного секретаря","Департамент транспорта штата Мэн (MaineDOT)","Федеральное управление безопасности грузоперевозок (FMCSA)","Подразделение по контролю коммерческого транспорта полиции штата Мэн"],"explanation":"Бюро транспортных средств штата Мэн (Maine BMV), подразделение офиса Государственного секретаря, выдаёт все CDL штата Мэн и проводит экзамены на знания и навыки. MaineDOT занимается дорогами и разрешениями на негабаритные/сверхнормативные грузы, а не лицензированием. Источник: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv)."},"80":{"q":"В форме самосертификации CDL штата Мэн (MVE-64C) из скольких категорий типа эксплуатации может выбрать заявитель?","options":["Из четырёх","Из двух","Из трёх","Из шести"],"explanation":"Штат Мэн требует самосертификации по одной из ЧЕТЫРЁХ категорий: межштатные неосвобождённые (Non-Excepted Interstate), межштатные освобождённые (Excepted Interstate), внутриштатные неосвобождённые (Non-Excepted Intrastate) или внутриштатные освобождённые (Excepted Intrastate). Источник: Maine BMV CDL Medical Self-Certification Form MVE-64C; 49 CFR 383.71."},"81":{"q":"Водитель в штате Мэн самосертифицируется как «Non-Excepted Interstate» (межштатный неосвобождённый). Какой дополнительный документ должен иметься в досье BMV?","options":["Федеральный медицинский сертификат DOT (Medical Examiner's Certificate, медицинская карта)","Ничего, помимо формы самосертификации","Нотариально заверенное письмо-разрешение от работодателя","Разрешение Maine DOT на негабаритный/сверхнормативный груз"],"explanation":"Водители, самосертифицирующиеся как Non-Excepted Interstate, должны предоставить BMV действующий федеральный медицинский сертификат (Medical Examiner's Certificate, MCSA-5876 / медицинская карта). Освобождённые (Excepted) водители не обязаны его предоставлять. Источник: Maine BMV CDL self-certification guidance; 49 CFR 383.71."},"82":{"q":"Кто имеет право проводить медицинский осмотр DOT, по результатам которого выдаётся медицинский сертификат (Medical Examiner's Certificate) для заявителя на CDL в штате Мэн?","options":["Медицинский эксперт, внесённый в Национальный реестр сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners)","Любой лицензированный врач по выбору заявителя","Экзаменатор BMV на месте проведения экзаменов","Постоянный оптометрист заявителя"],"explanation":"Медицинский осмотр DOT должен проводиться медицинским экспертом, внесённым в Национальный реестр сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners). Источник: Maine BMV CDL medical requirements; 49 CFR 391.43."},"83":{"q":"Каков максимальный срок действия медицинского сертификата DOT (Medical Examiner's Certificate) для держателя CDL штата Мэн?","options":["2 года","1 год","3 года","5 лет"],"explanation":"Медицинский сертификат (Medical Examiner's Certificate) действителен максимум 2 года; эксперт может сертифицировать водителя на более короткий срок, если какое-либо состояние требует наблюдения. Новая карта должна быть в досье до истечения срока действия старой. Источник: Maine BMV CDL medical requirements; 49 CFR 391.45."},"84":{"q":"Как держатель CDL штата Мэн может подать форму самосертификации или медицинский сертификат в подразделение BMV по контролю CDL (CDL Compliance Unit)?","options":["По факсу, электронной почте или обычной почтой в BMV CDL Compliance Unit","Только лично в центральном офисе в Огасте (Augusta)","Только путём загрузки в FMCSA Training Provider Registry","Только через работодателя водителя или транспортную компанию"],"explanation":"Штат Мэн принимает форму самосертификации MVE-64C и медицинский сертификат по факсу, по электронной почте (PDF/Word) в CDL Compliance Unit либо обычной почтой в BMV CDL Compliance Unit в Огасте (Augusta). Источник: Maine BMV CDL Compliance Unit submission instructions."},"85":{"q":"Прежде чем человеку может быть выдано коммерческое ученическое удостоверение штата Мэн (CLP), какой экзамен на знания должен быть сдан как минимум?","options":["Экзамен на общие знания (General Knowledge)","Только экзамен на дополнительную категорию «Air Brakes» (пневматические тормоза)","Экзамен по опасным грузам (HazMat)","Практический экзамен по предрейсовому осмотру"],"explanation":"Для получения CLP необходимо сдать экзамен на общие знания (General Knowledge) (а также любые экзамены на дополнительные категории, на которые претендует заявитель). Maine BMV публикует официальное руководство CDL, на котором основаны эти экзамены. Источник: Maine CDL Manual; Maine BMV CDL Exam page."},"86":{"q":"Каков минимальный проходной балл на каждом экзамене на знания CDL в штате Мэн?","options":["80%","70%","75%","90%"],"explanation":"Водитель должен правильно ответить как минимум на 80% вопросов на каждом экзамене на знания, чтобы его сдать. Источник: Maine CDL Manual; 49 CFR 383.135."},"87":{"q":"Экзамен на навыки CDL в штате Мэн состоит из каких трёх частей и в каком порядке?","options":["Предрейсовый осмотр транспортного средства, базовое управление транспортным средством и вождение по дороге","Письменный экзамен на знания, проверка зрения и вождение по дороге","Проверка пневматических тормозов, движение задним ходом и письменный экзамен на дополнительную категорию","Базовое управление транспортным средством, параллельная парковка и собеседование по опасным грузам"],"explanation":"Экзамен на навыки CDL состоит из трёх частей, проводимых в таком порядке: предрейсовый осмотр транспортного средства, тест на базовое управление транспортным средством и тест на вождение по дороге. Источник: Maine CDL Manual; 49 CFR 383.113."},"88":{"q":"Какой компонент экзамена на навыки требует, чтобы заявитель в штате Мэн выполнил такие манёвры, как движение задним ходом по прямой, движение задним ходом со смещением и постановка к погрузочной площадке (alley docking)?","options":["Тест на базовое управление транспортным средством","Предрейсовый осмотр транспортного средства","Тест на вождение по дороге","Экзамен на общие знания (General Knowledge)"],"explanation":"Манёвры задним ходом, такие как движение задним ходом по прямой, движение задним ходом со смещением и постановка к погрузочной площадке (alley docking), оцениваются в части теста на базовое управление транспортным средством. Источник: Maine CDL Manual; 49 CFR 383.113."},"89":{"q":"Заявитель, впервые получающий CDL класса A в штате Мэн, должен пройти обучение водителей начального уровня (ELDT) у провайдера, который:","options":["Внесён в Реестр поставщиков обучения FMCSA (Training Provider Registry, TPR)","Одобрен только пулом экзаменаторов Maine BMV","Сертифицирован местной системой общественных колледжей","Зарегистрирован в офисе разрешений MaineDOT"],"explanation":"ELDT должно быть получено у провайдера, внесённого в Реестр поставщиков обучения FMCSA (Training Provider Registry); провайдер сообщает о завершении обучения в FMCSA в электронном виде. Источник: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"90":{"q":"Для чего из перечисленного штат Мэн требует прохождения ELDT перед экзаменом?","options":["Для впервые получаемого CDL класса A или B либо впервые получаемой категории P, S или H","Для каждого продления CDL независимо от класса","Только для заявителей на категорию по опасным грузам (H)","Только для водителей, повышающих класс с B до A"],"explanation":"ELDT требуется для впервые получаемого CDL класса A или класса B, для повышения до более высокого класса либо для впервые получаемой категории «пассажирские перевозки» (P), «школьный автобус» (S) или «опасные грузы» (H). Источник: Maine BMV ELDT page; 49 CFR Part 380."},"91":{"q":"Когда заявитель на CDL в штате Мэн должен пройти требуемое ELDT?","options":["До сдачи соответствующего экзамена на знания или навыки","После сдачи экзамена на навыки, но до печати удостоверения","В течение 30 дней после выдачи CDL","Только после истечения 14-дневного срока ожидания по CLP"],"explanation":"Теоретическая часть ELDT должна быть завершена до экзамена на знания для категории H, а обучение вождению — до экзамена на навыки для классов A/B и категорий P/S. Обучение должно предшествовать соответствующему экзамену. Источник: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"92":{"q":"После получения CLP сколько времени заявитель в штате Мэн должен владеть им, прежде чем ему будет разрешено сдавать экзамен на навыки CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Держатель CLP должен подождать минимум 14 дней после выдачи удостоверения, прежде чем сдавать экзамен на навыки. Источник: Maine BMV CDL pages; 49 CFR 383.25."},"93":{"q":"При управлении транспортным средством по CLP штата Мэн держатель удостоверения должен сопровождаться:","options":["Держателем CDL, действительного для класса и категорий данного транспортного средства, сидящим рядом с водителем","Любым лицензированным водителем в возрасте 21 года или старше","Только экзаменатором BMV","Никем, при условии что транспортное средство пустое"],"explanation":"Держатель CLP может управлять коммерческим транспортным средством только в сопровождении лица, имеющего действующий CDL для данного класса транспортного средства, сидящего на переднем сиденье рядом с держателем удостоверения. Источник: Maine CDL Manual; 49 CFR 383.25."},"94":{"q":"Для большинства держателей CDL штата Мэн в возрасте до 65 лет как часто необходимо продлевать CDL?","options":["Каждые 5 лет","Каждые 4 года","Каждые 6 лет","Каждые 8 лет"],"explanation":"CDL штата Мэн выдаётся на 5-летний цикл для держателей младше 65 лет. (Держатели в возрасте 65 лет и старше продлевают по 4-летнему циклу.) Источник: Maine BMV CDL renewal information."},"95":{"q":"Каков минимальный возраст для получения CDL штата Мэн для вождения только внутри штата (intrastate, в пределах штата Мэн)?","options":["18","21","19","16"],"explanation":"Заявителю должно быть не менее 18 лет для получения CDL штата Мэн для внутриштатного вождения; 21 год требуется для межштатного вождения, перевозки опасных грузов или перевозки пассажиров. Источник: Maine CDL Manual; Maine BMV CDL pages."},"96":{"q":"Какой набор документов обычно требуется заявителю в штате Мэн для подтверждения личности и права на получение CDL при подаче заявления?","options":["Подтверждение личности, законного пребывания в США, номер социального страхования и проживание в штате Мэн","Только действующее некоммерческое водительское удостоверение штата Мэн","Паспорт плюс разрешение MaineDOT на негабаритный груз","Только письмо от работодателя и регистрация транспортного средства"],"explanation":"Заявители должны документально подтвердить личность, законное пребывание в США, номер социального страхования и проживание в штате Мэн, в дополнение к выполнению медицинских требований и требований самосертификации. Источник: Maine BMV CDL application requirements."},"97":{"q":"Если водитель в штате Мэн допускает истечение срока действия требуемого медицинского сертификата, так что он больше не находится в досье BMV, каково вероятное последствие?","options":["Право на CDL водителя понижается (коммерческие привилегии аннулируются) до подачи действующего сертификата","Ничего не меняется до обычной даты продления CDL","CDL аннулируется навсегда без возможности восстановления","Выдаётся только письменное предупреждение без последствий для удостоверения"],"explanation":"Если срок действия медицинского сертификата неосвобождённого водителя истекает и он не обновлён в BMV, штат обязан понизить CDL, аннулировав привилегии на коммерческое вождение, до подачи действующего сертификата. Источник: Maine BMV CDL Compliance guidance; 49 CFR 383.73."}},"tr":{"0":{"q":"Maine'deki bir kamuya açık yolda, özel izin olmadan bir aracın izin verilen azami toplam genişliği nedir?","options":["96 inç (8 fit)","102 inç (8 fit 6 inç)","108 inç (9 fit)","120 inç (10 fit)"],"explanation":"29-A M.R.S. §2380 uyarınca, toplam genişliği 102 inçten (8'6\") fazla olan bir araç, izin olmadan Maine'deki bir kamuya açık yolda veya köprüde kullanılamaz. Kaynak: Maine Revised Statutes Title 29-A, §2380."},"1":{"q":"Maine'deki karayollarında, limit aşımı izni olmadan bir aracın azami yasal yapısal yüksekliği nedir?","options":["12 fit 6 inç","13 fit","13 fit 6 inç","14 fit"],"explanation":"29-A M.R.S. §2380, kalıcı veya geçici bir yapısal parçası 13 fit 6 inçten daha yüksek olan bir aracın kullanılmasını yasaklar. İndirgenemeyen bir yük bunun en fazla 6 inç üzerine çıkabilir, ancak yapısal limit 13'6\"tır. Kaynak: Maine Revised Statutes Title 29-A, §2380."},"2":{"q":"Maine'de, belirli yan ek parçalar (aynalar ve çamurluklar gibi) yalnızca aracın yanından ne kadardan fazla uzanmadıkları takdirde genişlik ölçümünden hariç tutulur?","options":["2 inç","3 inç","6 inç","9 inç"],"explanation":"29-A M.R.S. §2380, belirtilen ek parçaları (aynalar, kapı menteşeleri, yağmur olukları, çamurluklar vb.) aracın yanından 3 inçten fazla uzanmamaları şartıyla 102 inçlik genişlik ölçümünden hariç tutar. Kaynak: Maine Revised Statutes Title 29-A, §2380."},"3":{"q":"Standart ağırlık limitleri kapsamında, Maine'in genel (Eyaletlerarası olmayan) karayollarında beş veya daha fazla akslı bir kombinasyon aracın azami brüt ağırlığı nedir?","options":["69,000 pound","73,280 pound","80,000 pound","90,000 pound"],"explanation":"29-A M.R.S. §2353 uyarınca, beş veya daha fazla akslı bir kombinasyon için azami brüt ağırlık 80,000 pounddur (2 akslı bir araç 34,000, 3 akslı bir araç 54,000 ve 4 akslı bir araç 69,000 pound ile sınırlıdır). Kaynak: Maine Revised Statutes Title 29-A, §2353."},"4":{"q":"Maine'in §2353'teki standart (Eyaletlerarası olmayan) ağırlık limitleri kapsamında, tek bir aks üzerinde izin verilen azami ağırlık nedir?","options":["18,000 pound","20,000 pound","22,400 pound","24,000 pound"],"explanation":"29-A M.R.S. §2353, Maine'in genel karayolu sisteminde tek aks limitini 22,400 pound olarak belirler; bu, federal Eyaletlerarası tek aks değeri olan 20,000 pounddan daha yüksektir. Kaynak: Maine Revised Statutes Title 29-A, §2353."},"5":{"q":"Maine'in genel karayolu sisteminde (§2353), bir tandem aks ünitesi üzerinde izin verilen azami ağırlık nedir?","options":["34,000 pound","36,000 pound","38,000 pound","41,000 pound"],"explanation":"29-A M.R.S. §2353, Maine'in genel yollarında bir tandem aks ünitesi üzerinde 38,000 pounda izin verir; bu, §2355 uyarınca Eyaletlerarası Karayolu Sisteminde geçerli olan 34,000 poundluk tandem limitini aşar. Kaynak: Maine Revised Statutes Title 29-A, §2353."},"6":{"q":"Maine'deki Eyaletlerarası Karayolu Sisteminde, bir tandem aks ünitesi üzerinde izin verilen azami ağırlık nedir?","options":["32,000 pound","34,000 pound","38,000 pound","41,000 pound"],"explanation":"29-A M.R.S. §2355, Eyaletlerarası Karayolu Sisteminde bir tandem aks ünitesini federal standarda uygun olarak 34,000 pound ile sınırlar. Maine'in genel yolları, §2353 uyarınca daha yüksek bir 38,000 poundluk tandeme izin verir. Kaynak: Maine Revised Statutes Title 29-A, §2355."},"7":{"q":"Maine Eyaletlerarası sisteminde, brüt araç ağırlığı 73,280 pounddan fazla olan bir araç hangi tek aks ağırlığı ile sınırlıdır?","options":["18,000 pound","20,000 pound","22,000 pound","22,400 pound"],"explanation":"29-A M.R.S. §2355, Eyaletlerarası Karayolu Sisteminde GVW 73,280 poundu aştığında tek aksı 20,000 pound (ve GVW 73,280 pound veya daha az olduğunda 22,000 pound) ile sınırlar. Kaynak: Maine Revised Statutes Title 29-A, §2355."},"8":{"q":"Maine Eyaletlerarası sisteminde, brüt araç ağırlığı 73,280 pound veya daha az olan bir araç tek bir aks üzerinde azami ne kadar ağırlık taşıyabilir?","options":["20,000 pound","22,000 pound","22,400 pound","24,200 pound"],"explanation":"29-A M.R.S. §2355, Eyaletlerarasında GVW 73,280 pound veya daha az olduğunda tek bir aksta 22,000 pounda kadar izin verir; GVW 73,280 poundu aştığında bu değer 20,000 pounda düşer. Kaynak: Maine Revised Statutes Title 29-A, §2355."},"9":{"q":"Maine Eyaletlerarası sisteminde kullanılan federal köprü formülünde, W = 500(LN/(N-1) + 12N + 36), \"L\" değişkeni neyi temsil eder?","options":["Yükün fit cinsinden uzunluğu","Bir aks grubunun en uçtaki aksları arasındaki fit cinsinden mesafe","Aks başına bin pound cinsinden yasal ağırlık","Araç üzerindeki yüklü aksların sayısı"],"explanation":"29-A M.R.S. §2355 tarafından uygulanan federal Bridge Formula B'de, W bir aks grubu üzerindeki izin verilen brüt ağırlık, N gruptaki aks sayısı ve L o grubun en uçtaki (dıştaki) aksları arasındaki fit cinsinden mesafedir. Kaynak: Maine Revised Statutes Title 29-A, §2355 (federal köprü formülü)."},"10":{"q":"Maine'de altı akslı bir kombinasyon (tri-aks yarı römorklu 3 akslı çekici), tüm koşullar sağlandığında en fazla ne kadar azami brüt ağırlığa ulaşabilir?","options":["80,000 pound","90,000 pound","100,000 pound","120,000 pound"],"explanation":"29-A M.R.S. §2354, aralık ve diğer koşullar sağlandığında altı akslı bir kombinasyona (tri-aks yarı römorklu 3 akslı kamyon çekicisi) 100,000 pounda kadar izin verir; temel limit 90,000 pounddur. Kaynak: Maine Revised Statutes Title 29-A, §2354."},"11":{"q":"Maine'in altı akslı 100,000 poundluk kombinasyonu için, en uçtaki akslar arasındaki mesafe (direksiyon aksı hariç) en az kaç fit olmalıdır?","options":["30 fit","32 fit","36 fit","40 fit"],"explanation":"29-A M.R.S. §2354, en uçtaki akslar arasındaki mesafenin (direksiyon aksı hariç) 36 fitten az olmamasını gerektirir; mesafe 36 fitten az olduğunda her fit için azami brüt ağırlık 2,000 pound azaltılır. Kaynak: Maine Revised Statutes Title 29-A, §2354."},"12":{"q":"Maine'in altı aks ağırlık tüzüğü uyarınca, en uçtaki aks aralığının gerekli asgari değerin altına düştüğü her fit için azami brüt ağırlık ne kadar azaltılır?","options":["Fit başına 1,000 pound","Fit başına 1,500 pound","Fit başına 2,000 pound","Fit başına 2,500 pound"],"explanation":"29-A M.R.S. §2354, altı akslı bir kombinasyonun azami izin verilen brüt ağırlığını, en uçtaki aks mesafesinin gerekli 36 fitten az olduğu her fit için 2,000 pound azaltır. Kaynak: Maine Revised Statutes Title 29-A, §2354."},"13":{"q":"Maine'in ağırlık toleransı tüzüğü (§2357), uygun yüklerin (örneğin ahşap ürünleri, yol tuzu, çakıl) azami brüt ağırlığı ne kadar aşmasına izin verir?","options":["Azaminin %5'ine kadar","%10'a kadar (azaminin %110'u)","Azaminin %15'ine kadar","Azaminin 2,000 pound üzerine kadar"],"explanation":"29-A M.R.S. §2357, uygun bir aracın brüt araç ağırlığının §2353'teki azami brüt ağırlığın %110'unu (%10 fazlasını) aşmaması halinde, ahşap ürünleri, çakıl, yol tuzu ve benzeri dökme malzemeler gibi listelenen emtialar için ihlal sayılmayacağını öngörür. Kaynak: Maine Revised Statutes Title 29-A, §2357."},"14":{"q":"Maine'in belirli emtialar için %10 ağırlık toleransı (§2357) hangi yollarda geçerlidir?","options":["Yalnızca Eyaletlerarası Karayolu Sisteminde","Eyaletlerarası Karayolu Sistemi hariç Maine'in tüm yollarında","Yalnızca Maine Turnpike'ta","Eyaletlerarası dahil Maine'in tüm yollarında"],"explanation":"29-A M.R.S. §2357, ağırlık toleransının Eyaletlerarası Karayolu Sisteminde kullanılan bir araca uygulanmadığını açıkça belirtir; bu tolerans Maine'in genel (Eyaletlerarası olmayan) yollarında mevcuttur. Kaynak: Maine Revised Statutes Title 29-A, §2357."},"15":{"q":"Maine'de, Ulaştırma Komiseri'nin tavsiyesi doğrultusunda hareket ederek eyalet çapında limit aşımı (boyut aşımı/ağırlık aşımı) hareket izinleri veren makam kimdir?","options":["Eyalet Sekreteri (Secretary of State)","Maine Eyalet Polisi","Maine Turnpike Authority","Kamu Hizmetleri Komisyonu (Public Utilities Commission)"],"explanation":"29-A M.R.S. §2382 uyarınca, Eyalet Sekreteri (Motorlu Taşıtlar Bürosu aracılığıyla), Ulaştırma Komiseri'nin yönergeleri ve tavsiyesi doğrultusunda hareket ederek limit aşımı hareket izinleri verir; ilçeler ve belediyeler kendi yollarında seyahate izin verebilir. Kaynak: Maine Revised Statutes Title 29-A, §2382."},"16":{"q":"Maine'de, yasal boyut veya ağırlık limitlerini aşan ne tür bir yükü taşımak için limit aşımı (boyut aşımı/ağırlık aşımı) izni gereklidir?","options":["Ayrılabilir olsun ya da olmasın herhangi bir yük","Yalnızca yasal birimlere bölünebilen bölünebilir yükler","Yasal limitlere indirgenemeyen bölünemez bir nesne","Yalnızca Eyaletlerarası Karayolu Sisteminde taşınan yükler"],"explanation":"29-A M.R.S. §2381 ve §2382, bölünemez nesneler (yasal uzunluk, genişlik, yükseklik veya ağırlığa makul şekilde indirgenemeyenler) için izin verilmesine olanak tanır. Bölünebilir yükler, izin verilmek yerine yasal limitlere indirgenmelidir. Kaynak: Maine Revised Statutes Title 29-A, §§2381–2382."},"17":{"q":"Maine Eyalet Sekreteri'nin kamyonlar, çekiciler ve yarı römorklar için verebileceği uzun süreli bir limit aşımı izninin azami süresi nedir?","options":["30 gün","6 ay","Bir yıl","İki yıl"],"explanation":"29-A M.R.S. §2382, Eyalet Sekreteri'nin kamyonlar, kamyon çekicileri, yarı römorklar, ağır hizmet kurtarma araçları ve A Sınıfı özel hareketli ekipman için bir yıla kadar geçerli izinler vermesine olanak tanır; aksi takdirde tek seferlik izinler verilir. Kaynak: Maine Revised Statutes Title 29-A, §2382."},"18":{"q":"Maine'deki 53 fitlik bir yarı römork ulusal karayolu ağının dışında çalıştığında, aracın ve yükün toplam uzunluğu hangi toplam uzunluğu aşamaz?","options":["65 fit","69 fit","74 fit","80 fit"],"explanation":"29-A M.R.S. §2390, 48 fitten fazla ancak 53 fitten fazla olmayan bir yarı römorka izin verir (kingpin'den arka aksa mesafe en fazla 43 fit olmak üzere), ancak ulusal ağın dışında çalışırken toplam uzunluk 74 fiti aşamaz. Eyaletlerarası Karayolu Sisteminde toplam uzunluk limiti uygulanmaz. Kaynak: Maine Revised Statutes Title 29-A, §2390."},"19":{"q":"Maine yasalarına göre, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pound veya daha fazla olan ve çekilen araç(lar)ın 10,000 pound GVWR'yi aştığı herhangi bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Maine, Class A'yı, çekilen araç(lar)ın GVWR/brüt ağırlığının 10,000 poundu aşması şartıyla, GCWR'si 26,001 pound veya daha fazla olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"20":{"q":"Bir Maine sürücüsü, brüt araç ağırlık derecesi 30,000 pound olan tek bir düz kamyonu kullanmakta ve hiçbir römork çekmemektedir. Bu hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Maine'in Class B'si, GVWR'si 26,001 pound veya daha fazla olan herhangi bir tek aracı veya 10,000 poundu geçmeyen bir üniteyi çeken böyle bir aracı kapsar. 30,000 poundluk tek bir ünite Class B'dir. Kaynak: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"21":{"q":"Maine'de, Class A veya Class B ağırlık tanımlarını karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak üzere tasarlanmış veya plakart gerektiren tehlikeli madde taşıyan bir araç hangi CDL sınıfına girer?","options":["Class A","Class B","Class C","Class M"],"explanation":"Maine'in Class C'si, Class A/B'yi karşılamayan ve 16 veya daha fazla yolcu (sürücü dahil) taşımak üzere tasarlanmış veya plakart gerektiren tehlikeli madde taşıyan herhangi bir tek veya kombinasyon araçtır. Kaynak: Maine CDL Manual, 'Definitions of Classes' ve Figure 1.1; 29-A MRSA §1253."},"22":{"q":"Maine CDL Manual'a göre, yükün federal DOT düzenlemeleri uyarınca plakart gerektirmesi durumunda tehlikeli madde taşıyan araçları kullanmak için hangi onay (endorsement) gereklidir?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"Maine, federal DOT düzenlemesi uyarınca plakart gerektiğinde tehlikeli madde taşıyan araçların kullanımı için H onayını kullanır. X onayı, tank (N) ve hazmat (H) onaylarını birleştirir. Kaynak: Maine CDL Manual, 'Endorsements.'"},"23":{"q":"Bir Maine CDL'sinde, 'X' onayı neye yetki verir?","options":["Yalnızca tank araçlarının kullanımına","Tehlikeli madde taşıyan tank araçlarının kullanımına (N ve H'yi birleştirir)","İkili ve üçlü römorkların kullanımına","15'ten fazla yolcu taşıyan yolcu otobüslerinin kullanımına"],"explanation":"Maine'in X onayı, N (tank) ve H (hazmat) onaylarını tek bir onayda birleştirerek, tehlikeli madde taşıyan tank araçlarının kullanımı içindir. Kaynak: Maine CDL Manual, 'Endorsements.'"},"24":{"q":"Maine CDL Manual, 'T' (ikili/üçlü) onayıyla ilgili belirli bir kısıtlamaya dikkat çeker. Maine için hangi ifade doğrudur?","options":["Hem ikili hem de üçlü römorklar eyalet genelinde serbestçe kullanılabilir","Üçlü römorklara Maine'de izin verilmez","T onayı ayrıca tank araçlarına da yetki verir","İkili römorklar ayrı bir yolcu testi gerektirir"],"explanation":"Maine CDL Manual, T onayını 'yasaların izin verdiği yerlerde' ikili/üçlü römorklar için olarak tanımlar ve üçlü römorklara Maine'de izin verilmediğini açıkça belirtir. Kaynak: Maine CDL Manual, 'Endorsements.'"},"25":{"q":"Maine CDL Manual'a göre, N (tank aracı) onayı, kalıcı olarak monte edilmiş bir kargo tankında sıvı veya sıvılaştırılmış gaz taşımak için hangi asgari kapasitede gereklidir?","options":["100 galon veya daha fazla","119 galon veya daha fazla","1,000 galon veya daha fazla","450 galon veya daha fazla"],"explanation":"Maine, kalıcı olarak monte edilmiş, 119 galon veya daha fazla kapasiteli bir kargo tankında veya 1,000 galon veya daha fazla kapasiteli taşınabilir bir tankta sıvı veya sıvılaştırılmış gaz taşımak için tanker (N) testini/onayını gerektirir. Kaynak: Maine CDL Manual, '1.1.1 Knowledge Tests' ve tank aracı bölümü."},"26":{"q":"Maine'de, hangi onayı başarıyla almak, ek ücret veya başka bir sınav olmadan otomatik olarak 'P' (yolcu) onayını da kazandırır?","options":["H (Tehlikeli Maddeler)","N (Tank Aracı)","S (Okul Otobüsü)","T (İkili/Üçlü)"],"explanation":"Maine CDL Manual, S (okul otobüsü) onayını başarıyla almanın, ek ücret veya başka bir sınav olmadan P (yolcu) onayını da kazandırdığını belirtir. Kaynak: Maine CDL Manual, 'Endorsements.'"},"27":{"q":"Maine CDL Manual'a göre, hangi onaylar yalnızca bilgi (yazılı) testini geçmekle, ayrı bir beceri testi gerektirmeden verilir?","options":["P ve S","N, H, X ve T","Yalnızca H","Tüm onaylar bir beceri testi gerektirir"],"explanation":"Maine CDL Manual, N, H, X ve T onaylarının yalnızca bilgi sınavının başarıyla tamamlanmasıyla CDL sahibine verildiğini; P ve S'nin ise beceri testi dahil tam testi gerektirdiğini belirtir. Kaynak: Maine CDL Manual, 'Endorsements.'"},"28":{"q":"Maine, sürücünün bir CDL'ye sahip olmasını GEREKTİRMEYEN bir tür okul otobüsü kullanımı için '3' onayını tanır. Bu otobüs kaç yolcu taşımak üzere tasarlanmıştır?","options":["Sürücü dahil 16 veya daha fazla yolcu","Sürücü dahil 15 yolcu veya daha az","Tam olarak 24 yolcu","Sürücü hariç 15'ten fazla yolcu"],"explanation":"Maine CDL Manual, 15 yolcu veya daha az (sürücü dahil) taşımak üzere tasarlanmış bir okul otobüsü için '3' onayını tanımlar; bu, ticari olmayan bir ehliyete eklenebilir ve CDL gerektirmez. Kaynak: Maine CDL Manual, '\"3\" endorsement.'"},"29":{"q":"Maine'in CDL kuralları uyarınca, eyalet içi ticarette (yalnızca Maine içinde) ticari bir motorlu taşıtı kullanmak için asgari yaş nedir?","options":["16 yaş","18 yaş","21 yaş","19 yaş"],"explanation":"Maine'in eyalet içi CDL için asgari yaşı 18'dir. (Maine CDL Manual'ın eski metni bazı eyalet içi operasyonlar için 16 yaşına atıfta bulunur, ancak BMV eyalet içi CDL operasyonu için 18 yaşındaki federal alt sınırı uygular.) Kaynak: Maine BMV / FMCSA 49 CFR 391.11; Maine CDL Manual yaş hükümleri."},"30":{"q":"Maine'de, eyaletlerarası ticaret için (eyalet sınırlarını geçerek) geçerli bir CDL almak için asgari yaş nedir?","options":["18 yaş","19 yaş","21 yaş","25 yaş"],"explanation":"Bir sürücünün, eyaletlerarası ticarette bir CMV kullanmak, tehlikeli madde taşımak veya bir yolcu otobüsü sürmek için en az 21 yaşında olması gerekir. Kaynak: Maine CDL Manual yaş hükümleri; FMCSA 49 CFR 391.11."},"31":{"q":"29-A MRSA §1304(4-A) uyarınca, bir Maine ticari öğrenci ehliyeti (CLP) sahibi, ehliyetin ilk verilmesinden sonra hangi süre boyunca CDL beceri testine girmeye uygun DEĞİLDİR?","options":["İlk 7 gün","İlk 14 gün","İlk 30 gün","İlk 60 gün"],"explanation":"Maine yasası, bir CLP sahibinin, federal gereklilikle uyumlu olarak, CLP'nin ilk verilmesinden sonraki ilk 14 gün içinde CDL beceri testine girmeye uygun olmadığını öngörür. Kaynak: 29-A MRSA §1304(4-A)(I)."},"32":{"q":"29-A MRSA §1304 uyarınca, bir Maine ticari öğrenci ehliyeti (CLP), verildiği tarihten itibaren en fazla ne kadar süre geçerlidir?","options":["180 gün","Bir yıl","İki yıl","Beş yıl"],"explanation":"Maine yasası, ticari öğrenci ehliyetinin verildiği tarihten itibaren en fazla bir yıl geçerli olduğunu belirtir. Kaynak: 29-A MRSA §1304(4-A)(G)."},"33":{"q":"Bir Maine ticari öğrenci ehliyeti kapsamında bir CMV kullanırken, CLP sahibine, nerede konumlanmış bir CDL sahibi eşlik etmelidir?","options":["Araçta herhangi bir yerde","Ayrı bir araçta takip ederek","Fiziksel olarak CLP sahibinin yanında ön koltukta (veya bir yolcu aracında, doğrudan arkasında ya da sürücünün arkasındaki ilk sırada)","Operasyon sırasında telefonla ulaşılabilir durumda"],"explanation":"Maine yasası, eşlik eden CDL sahibinin, uygun sınıf ve onaylara sahip olarak, fiziksel olarak CLP sahibinin yanında ön koltukta veya bir yolcu aracında doğrudan arkasında ya da sürücünün arkasındaki ilk sırada bulunmasını gerektirir. Kaynak: 29-A MRSA §1304(4-A)(A)."},"34":{"q":"29-A MRSA §1304(4-A) uyarınca bir Maine ticari öğrenci ehliyeti sahibi için hangi faaliyet açıkça yasaklanmıştır?","options":["Tehlikeli madde taşıyan bir ticari motorlu taşıtı kullanmak","Gündüz saatlerinde araç sürmek","Bir Class B aracı kullanmak","Eyaletlerarası karayollarında pratik yapmak"],"explanation":"Maine yasası, bir CLP sahibinin 49 CFR §383.5'te tanımlanan tehlikeli maddeleri taşıyan bir CMV kullanmasını yasaklar. Kaynak: 29-A MRSA §1304(4-A)(F)."},"35":{"q":"29-A MRSA §1304(4-A) uyarınca, bir Maine CLP sahibinin bir yolcu (P) veya okul otobüsü (S) onayı için başvurabilmesi için asgari kaç yaşında olması gerekir?","options":["18 yaş","20 yaş","21 yaş","22 yaş"],"explanation":"Maine yasası, bir CLP sahibinin bir yolcu veya okul otobüsü onayı için başvurabilmesi için en az 21 yaşında olmasını gerektirir ve eşlik eden CDL sahibinin bir yolcu onayına sahip olması, en az bir yıl deneyimi olması ve en az 22 yaşında olması gerekir. Kaynak: 29-A MRSA §1304(4-A)(E)."},"36":{"q":"Yeni Maine CDL başvuru sahiplerine uygulanan Başlangıç Düzeyi Sürücü Eğitimi (ELDT) gerekliliği hangi sistem aracılığıyla doğrulanır?","options":["Maine BMV çevrimiçi portalı","FMCSA Training Provider Registry (TPR)","Ulusal Sürücü Sicili (National Driver Register)","TSA Secure Flight veritabanı"],"explanation":"7 Şubat 2022'den itibaren geçerli olmak üzere, FMCSA'nın ELDT kuralı, yeni CDL operatörleri ve belirli yükseltmeler için, FMCSA Training Provider Registry'de (tpr.fmcsa.dot.gov) listelenen ve kaydedilen bir sağlayıcı tarafından tamamlanan eğitimi gerektirir. Kaynak: Maine CDL Manual, 'Entry Level Driver Training (ELDT)'; FMCSA 49 CFR Part 380."},"37":{"q":"Bir Maine CDL'sine başvururken, başvuru sahibinin bir tür sürüş operasyonunu kendi beyanıyla onaylaması gerekir. Hangi grup, Maine tarafından kullanılan dört federal kendi beyanı kategorisini doğru şekilde listeler?","options":["Yerel, bölgesel, ulusal ve uluslararası","Muaf olmayan eyaletlerarası, muaf eyaletlerarası, muaf olmayan eyalet içi ve muaf eyalet içi","Ticari, özel, tarımsal ve acil durum","Class A, Class B, Class C ve Class D operasyonları"],"explanation":"Maine, 49 CFR §383.71'i izleyerek, CDL başvuru sahiplerinin dört kategoriden birini kendi beyanıyla onaylamasını gerektirir: muaf olmayan eyaletlerarası, muaf eyaletlerarası, muaf olmayan eyalet içi veya muaf eyalet içi. Muaf olmayan kategoriler geçerli bir tıbbi muayene memuru sertifikası gerektirir. Kaynak: FMCSA 49 CFR §383.71; Maine BMV."},"38":{"q":"Kimlik, ikamet ve yasal varlık belgelerinin ötesinde, ehliyet düzenlemesi için 29-A MRSA tarafından zorunlu kılındığı üzere, bir Maine CDL başvuru sahibinin hangi ek bilgiyi açıklaması gerekir?","options":["Bir pasaport numarası","Bir Sosyal Güvenlik numarası","Bir seçmen kayıt kartı","Bir araç tescil belgesi"],"explanation":"Maine CDL Manual'ın Sosyal Güvenlik Numarası Açıklama Beyanı, SSN'nin açıklanmasının zorunlu olduğunu ve bir ehliyete başvurmak veya yenilemek için 29-A MRSA tarafından gerekli kılındığını belirtir; BMV ayrıca kimlik, Maine ikameti ve yasal varlık kanıtı da ister. Kaynak: Maine CDL Manual, 'Social Security Number Disclosure Statement'; 29-A MRSA."},"39":{"q":"Maine CDL kuralları uyarınca, hangi kan alkol konsantrasyonunda (BAC) ticari bir motorlu taşıtı kullanmak yasa dışıdır?","options":["%0.04 veya daha fazla","%0.08 veya daha fazla","%0.02 veya daha fazla","%0.10 veya daha fazla"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), BAC'niz .04% veya daha fazla ise bir CMV kullanmanın yasa dışı olduğunu belirtir. Bu 0.04 limiti, sıradan sürücüler için olan 0.08 limitinin yarısıdır ve federal standart 49 CFR 383.51 ile uyumludur."},"40":{"q":"Maine'de ticari bir motorlu taşıtı kullanan bir sürücünün yasal olarak neyi yapmış sayıldığı kabul edilir?","options":["Bir savunma avukatı hakkından feragat ettiği","Alkol testine rıza gösterdiği","Herhangi bir zamanda araç aramasına izin verdiği","Haftalık rastgele uyuşturucu idrar testine rıza gösterdiği"],"explanation":"Maine CDL Manual (Bölüm 1.2.2) şunu belirtir: 'Bir CMV kullanırsanız, alkol testine rıza göstermiş sayılırsınız.' Bu, Maine'in CMV kullanımı için zımni rıza kuralıdır (ayrıca bkz. 29-A M.R.S. 2521)."},"41":{"q":"İlk büyük suç için (örneğin .04% veya daha yüksek BAC ile bir CMV kullanmak), bir Maine sürücüsü CDL'sini ne kadar süre kaybeder?","options":["En az 60 gün","En az 6 ay","En az 1 yıl","En az 90 gün"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), .04% veya daha yüksek BAC ile bir CMV kullanmak dahil olmak üzere ilk büyük suç için CDL'nizi en az bir yıl kaybedeceğinizi belirtir. Bu, federal standart 49 CFR 383.51 ile uyumludur."},"42":{"q":"Maine'de, bir CMV kullanırken gerektiğinde kan alkol testinden geçmeyi reddeden bir CDL sahibine ne olur (ilk suç)?","options":["Diskalifiye olmadan bir uyarı","30 gün CDL kaybı","120 gün CDL kaybı","En az 1 yıl CDL kaybı"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), 'kan alkol testinden geçmeyi reddetmeyi' ilk büyük suç olarak listeler; bu, en az bir yıl CDL kaybı taşır (tehlikeli madde için plakartlıysa 3 yıl)."},"43":{"q":"Bir ilk büyük suç (örneğin alkol veya uyuşturucu etkisi altında araç kullanmak), bir Maine sürücüsü tehlikeli madde için plakartlı bir CMV kullanırken meydana gelirse, CDL en az ne kadar süre kaybedilir?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), bir ilk büyük suç, tehlikeli madde için plakartlı bir CMV kullanırken meydana gelirse, 49 CFR 383.51 uyarınca CDL'nizi en az üç yıl kaybedeceğinizi belirtir."},"44":{"q":"Maine'de ikinci bir büyük suçun (örneğin bir CMV'de ikinci bir DUI) sonucu nedir?","options":["10 yıl CDL kaybı","Ömür boyu CDL kaybı","3 yıl CDL kaybı","5 yıl CDL kaybı"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), ikinci bir büyük suç için CDL'nizi ömür boyu kaybedeceğinizi belirtir. Bu ömür boyu diskalifiye, federal standart 49 CFR 383.51 izler."},"45":{"q":"Maine kuralları uyarınca, kontrollü maddeleri içeren bir suç işlemek için bir CMV kullanmanın cezası nedir?","options":["1 yıl CDL kaybı","3 yıl CDL kaybı","Ömür boyu CDL kaybı","120 gün CDL kaybı"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), kontrollü maddeleri içeren bir suç işlemek için bir CMV kullanırsanız CDL'nizi ömür boyu kaybedeceğinizi belirtir. Bu suç için yeniden tesis edilme olanağı yoktur."},"46":{"q":"Maine'de, bir CMV kullanırken .04% altında tespit edilebilir miktarda alkol bulunan bir sürücü:","options":["60 gün diskalifiye edilir","$5,000 para cezasına çarptırılır","Otomatik olarak OUI'den tutuklanır","24 saat hizmet dışı bırakılır"],"explanation":"Maine CDL Manual (Bölüm 1.2.2), .04% altında herhangi bir tespit edilebilir miktarda alkolünüz varsa 24 saat hizmet dışı bırakılacağınızı belirtir. Tam bir diskalifiye, .04% veya daha fazla BAC gerektirir."},"47":{"q":"Aşağıdakilerden hangisi Maine CDL Manual'da 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Aşırı hız (belirtilen limitin 15 mph veya daha fazla üzerinde)","Belirtilen limitin 5 mph üzerinde araç kullanmak","Süresi dolmuş bir araç tescili","Tek bir park ihlali"],"explanation":"Maine CDL Manual (Bölüm 1.2.3), aşırı hızı belirtilen limitin 15 mph veya daha fazla üzerinde olarak tanımlar ve onu dikkatsiz araç kullanma, uygunsuz şerit değiştirmeler ve çok yakından takip etmeyle birlikte ciddi bir trafik ihlali olarak listeler."},"48":{"q":"Bir Maine sürücüsü, üç yıllık bir süre içinde bir CMV'de İKİ ciddi trafik ihlali işlemekten CDL'sini ne kadar süre kaybeder?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"Maine CDL Manual (Bölüm 1.2.3), bir CMV içeren üç yıllık bir süre içinde iki ciddi trafik ihlali için 49 CFR 383.51 uyarınca CDL'nizi en az 60 gün kaybedeceğinizi belirtir."},"49":{"q":"Bir Maine sürücüsü, üç yıllık bir süre içinde bir CMV'de ÜÇ veya daha fazla ciddi trafik ihlali işlemekten CDL'sini ne kadar süre kaybeder?","options":["En az 60 gün","En az 90 gün","En az 120 gün","En az 1 yıl"],"explanation":"Maine CDL Manual (Bölüm 1.2.3), bir CMV içeren üç yıllık bir süre içinde üç veya daha fazla ciddi trafik ihlali için 49 CFR 383.51 uyarınca CDL'nizi en az 120 gün kaybedeceğinizi belirtir."},"50":{"q":"Bunlardan hangisi Maine CDL Manual'daki ciddi trafik ihlalleri arasında listelenmiştir?","options":["Bir otoparkta dönüş sinyali kullanmamak","Bir farı yanmayan halde araç kullanmak","500 poundun altında sabitlenmemiş bir yük taşımak","Bir CDL almadan veya yanınızda bulundurmadan bir CMV kullanmak"],"explanation":"Maine CDL Manual (Bölüm 1.2.3), bir CDL almadan, CDL'yi yanında bulundurmadan veya uygun sınıf/onaylar olmadan bir CMV kullanmayı ciddi trafik ihlalleri olarak listeler."},"51":{"q":"Maine'de benimsenen federal kurallar uyarınca, bir CMV kullanırken mesaj atmak ve elde tutulan bir cep telefonu kullanmak nasıl ele alınır?","options":["Ciddi trafik ihlalleri","1 yıl diskalifiyeli büyük suçlar","Hizmet dışı emri ihlalleri","Diskalifiye gerektirmeyen ihlaller"],"explanation":"49 CFR 383.51 uyarınca, bir CMV kullanırken mesaj atmak (49 CFR 392.80) ve elde tutulan cep telefonu kullanmak (49 CFR 392.82) ciddi trafik ihlalleridir. Üç yılda iki tanesi 60 günlük bir diskalifiye getirir; üç tanesi 120 gün getirir. Maine bu federal standartları benimser."},"52":{"q":"Maine CDL sürücülerine uygulanan federal elde tutulan telefon kuralları uyarınca, tek bir mesaj atma veya elde tutulan telefon mahkumiyeti, ayrıca sürücüye en fazla ne kadar idari para cezası getirebilir?","options":["$500","$2,750","$11,000","$250"],"explanation":"Maine'de geçerli FMCSA kuralları (49 CFR 392.80/392.82) uyarınca, bir sürücü her mesaj atma veya elde tutulan telefon ihlali başına en fazla $2,750 idari para cezasıyla karşı karşıya kalır; buna izin veren işverenler en fazla $11,000 ceza ile karşı karşıya kalır. Üç yılda iki bu tür mahkumiyet ayrıca CDL'yi 60 gün diskalifiye eder."},"53":{"q":"Maine CDL Manual'a göre, bir sürücü hizmet dışı emrinin İLK ihlali için CDL'sini ne kadar süre kaybeder?","options":["En az 60 gün","En az 30 gün","En az 90 gün","En az 1 yıl"],"explanation":"Maine CDL Manual (Bölüm 1.2.4), ilk hizmet dışı emri ihlali için CDL'nizi en az 90 gün kaybedeceğinizi belirtir. (Güncel federal 49 CFR 383.51 Tablo 4, 180 günlük bir asgari süre belirler, ancak Maine'in yayımlanan kılavuzu 90 gün belirtir.)"},"54":{"q":"Maine CDL Manual'a göre, bir sürücü on yıllık bir süre içinde İKİ hizmet dışı emri ihlali için CDL'sini ne kadar süre kaybeder?","options":["En az 90 gün","En az 6 ay","En az 3 yıl","En az 1 yıl"],"explanation":"Maine CDL Manual (Bölüm 1.2.4), on yıllık bir süre içinde iki hizmet dışı emri ihlali için CDL'nizi en az bir yıl kaybedeceğinizi belirtir. On yıl içinde üçüncüsü en az üç yıl getirir."},"55":{"q":"Maine CDL Manual'a göre, bir sürücü on yıllık bir süre içinde ÜÇ veya daha fazla hizmet dışı emri ihlali için CDL'sini ne kadar süre kaybeder?","options":["En az 3 yıl","En az 1 yıl","Ömür boyu","En az 120 gün"],"explanation":"Maine CDL Manual (Bölüm 1.2.4), on yıllık bir süre içinde üç veya daha fazla hizmet dışı emri ihlali için CDL'nizi en az üç yıl kaybedeceğinizi belirtir."},"56":{"q":"Maine CDL Manual'a göre, bir sürücü İLK demiryolu-karayolu hemzemin geçit ihlali için CDL'sini ne kadar süre kaybeder?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"Maine CDL Manual (Bölüm 1.2.5), ilk demiryolu-karayolu hemzemin geçit ihlali için 49 CFR 383.51 uyarınca CDL'nizi en az 60 gün kaybedeceğinizi belirtir."},"57":{"q":"Maine CDL Manual'a göre, üç yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["En az 120 gün","En az 60 gün","En az 1 yıl","En az 90 gün"],"explanation":"Maine CDL Manual (Bölüm 1.2.5), üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için CDL'nizi en az bir yıl kaybedeceğinizi belirtir (ilki 60 gün, ikincisi 120 gündür)."},"58":{"q":"Maine'de, bir CDL sahibinin kişisel araç sürüş ayrıcalığı bir alkol, kontrollü madde veya suç ihlali nedeniyle iptal edilir, feshedilir veya askıya alınırsa, CDL'ye ne olur?","options":["Hiçbir etkisi yok, çünkü kişisel bir araçta meydana geldi","Yalnızca 60 gün CDL kaybı","İlk ihlalde anında ömür boyu diskalifiye","1 yıl CDL kaybı (bu tür ikinci bir ihlal için ömür boyu)"],"explanation":"Maine CDL Manual (Bölüm 1.2.7), Motor Carrier Safety Improvement Act'i yansıtarak, kişisel araç ayrıcalığınızın alkol, kontrollü madde veya suç ihlalleri nedeniyle iptal edilmesi/feshedilmesi/askıya alınması halinde CDL'nizi 1 yıl ve bu tür ikinci bir ihlalde ömür boyu kaybedeceğinizi belirtir. Hardship CDL mevcut değildir."},"59":{"q":"Maine'in Yana Çekil (Move Over) yasası uyarınca, çok şeritli bir yolda yanıp sönen ışıklarını yakmış, duran bir acil durum veya servis aracına yaklaştığınızda, güvenli bir şekilde yapılabiliyorsa İLK olarak yapmanız gereken nedir?","options":["Duran araca komşu olan şeritten çıkıp komşu olmayan bir şeride geçmek","Acil durum aracı olay yerinden ayrılana kadar tamamen durmak","Korna çalıp belirlenen hız sınırında devam etmek","Sağ banketine çekilip geçmeniz için işaret edilmesini beklemek"],"explanation":"Maine'in Yana Çekil yasası (29-A MRSA Sec. 2054(9) ve duran/arızalı araçlar için Sec. 2070(8)), mümkünse sürücünün duran araca komşu OLMAYAN bir şeritte geçmesini gerektirir; yalnızca şerit değiştirmek imkansız veya güvensizse, dikkatli ve makul bir şekilde düşürülmüş hızda geçebilirsiniz. Kaynak: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070."},"60":{"q":"Komşu olmayan bir şeride geçmenin imkansız olduğu iki şeritli bir yolda, Maine'in Yana Çekil yasası, duran bir acil durum veya arızalı araçtan geçen bir sürücünün ne yapmasını gerektirir?","options":["Aracı geçmeden önce tamamen durmak","En azından belirlenen asgari hız sınırını korumak","Aracı güvenli bir şekilde geçmek için makul olan dikkatli ve ihtiyatlı bir hızda geçmek","Hızı belirlenen sınırın tam olarak 20 mph altına düşürmek"],"explanation":"Şerit değiştirmek mümkün olmadığında veya güvensiz olduğunda, 29-A MRSA Sec. 2070(8)(B) (ve Sec. 2054), 'aracı güvenli bir şekilde geçmek için makul olan dikkatli ve ihtiyatlı bir hızda' geçilmesini gerektirir. Maine kesin bir mph değeri belirtmez. Kaynak: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"61":{"q":"Maine'in Yana Çekil yasası 2023'te genişletildi. Yetkili acil durum ve kamu hizmeti araçlarına ek olarak, yana çekilme veya yavaşlama yükümlülüğü artık şunların yanından geçerken de geçerlidir:","options":["Yalnızca işaretli polis araçları ve ambulanslar","Makul bir kişinin arızalı olduğu sonucuna varacağı veya yanıp sönen ışıkları kullanan herhangi bir duran araç","Yalnızca çekiciler ve karayolu bakım araçları","Yalnızca kırmızı uyarı bayrağı sergileyen araçlar"],"explanation":"PL 2023 c. 122 ile yürürlüğe giren 29-A MRSA Sec. 2070(8), yana çekilme/yavaşlama yükümlülüğünü, makul bir kişinin arızalı olduğu sonucuna varacağı veya varlığını uyarmak için yanıp sönen ışıkları kullanan herhangi bir duran araca genişletir. Kaynak: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"62":{"q":"Maine'in yana çekilme / duran araçtan geçme gerekliliğini ihlal etmenin asgari para cezası nedir?","options":["$135","$500","$1,000","$275"],"explanation":"29-A MRSA Sec. 2070(8), ihlalin, en az $275 para cezası verilmesi gereken bir trafik kabahati olduğunu öngörür. Kaynak: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"63":{"q":"Bir Maine demiryolu geçidinde, üzerinde beyaz dur çizgisi boyanmamış bir çapraz işaret (cross-buck) bulunduğunda, durması gereken plakalı bir tehlikeli madde aracı veya otobüs, en yakın raydan hangi mesafe içinde durmalıdır?","options":["15 feet'ten az olmamak ve 50 feet'ten fazla olmamak üzere","5 feet'ten az olmamak ve 25 feet'ten fazla olmamak üzere","25 feet'ten az olmamak ve 75 feet'ten fazla olmamak üzere","10 feet'ten az olmamak ve 100 feet'ten fazla olmamak üzere"],"explanation":"29-A MRSA Sec. 2076(3), yolcu taşıyan otobüslerin ve plakalı/işaretli tehlikeli madde ile kargo tankı araçlarının en yakın raydan 15 feet'ten az ve 50 feet'ten fazla olmamak üzere durmasını gerektirir. Maine CDL Kılavuzu (Sec. 2.15) aynı 15 ile 50 feet aralığını belirtir. Kaynak: Maine Revised Statutes Title 29-A Sec. 2076; Maine CDL Manual."},"64":{"q":"Aşağıdaki demiryolu geçitlerinin hangisinde bir Maine otobüsü veya plakalı tehlikeli madde aracının durması GEREKMEZ?","options":["Bir iş bölgesinin dışında bulunan herhangi bir geçit","Etkin olmayan yanıp sönen kırmızı ışıkları olan bir geçit","Yalnızca endüstriyel manevra için kullanılan rayların geçidi veya 'muaf' (exempt) tabelasıyla işaretlenmiş bir geçit","45 mph veya daha düşük hızla belirlenmiş herhangi bir yoldaki geçit"],"explanation":"29-A MRSA Sec. 2076, zorunlu durmaya ilişkin istisnaları sıralar; bunlar arasında tramvay geçitleri, yalnızca endüstriyel manevra için kullanılan raylar, bir memur veya işaretçi tarafından devam etmesi yönlendirildiğinde, terk edildiği belirtilen geçitler ve 'muaf' (exempt) tabelasıyla işaretlenmiş geçitler bulunur. Kaynak: Maine Revised Statutes Title 29-A Sec. 2076."},"65":{"q":"Maine yasası (29-A Sec. 2306), bir demiryolu hemzemin geçidine yaklaşan bir okul otobüsü sürücüsüne tamamen durmasını ve ardından geçmeden önce ne yapmasını emreder?","options":["Koşullar ne olursa olsun tam 30 saniye beklemek","Kornayı iki kez çalıp ardından devam etmek","Bir yolcunun inip işaretçi olarak görev yapmasını sağlamak","Ray üzerinde yaklaşan bir tren olmadığından makul şüphenin ötesinde emin olmak"],"explanation":"29-A MRSA Sec. 2306, okul otobüsü sürücüsünün tamamen durmasını (en yakın raydan 50 feet'ten fazla ve 15 feet'ten az olmamak üzere) ve geçmeden önce hiçbir tren, lokomotif veya taşıtın yaklaşmadığından makul şüphenin ötesinde emin olmasını gerektirir. Kaynak: Maine Revised Statutes Title 29-A Sec. 2306."},"66":{"q":"Bir Maine okul otobüsü, yolcuları indirmek için kırmızı ışıkları yanıp sönerken iki şeritli bir yolda durur. KARŞI yönden yaklaşan bir aracın sürücüsü ne yapmalıdır?","options":["15 mph'e yavaşlayıp dikkatle geçmek","Aracı otobüse ulaşmadan önce durdurmak ve otobüs hareket edene veya işaret verene kadar devam etmemek","Karşı yönden gelen trafik muaf olduğu için normal şekilde devam etmek","Yalnızca çocuklar gözle görülür şekilde yolu geçiyorsa durmak"],"explanation":"29-A MRSA Sec. 2308(2), kırmızı ışıkları yanıp sönerek duran bir okul otobüsüyle her iki yönden karşılaşan VEYA onu geçen bir aracın sürücüsünün, otobüse ulaşmadan önce durmasını ve otobüs hareketine devam edene veya sürücü işaret verene kadar ilerlememesini gerektirir. Kaynak: Maine Revised Statutes Title 29-A Sec. 2308(2)."},"67":{"q":"Maine'in okul otobüsü yasası uyarınca, bir sürücünün karşı tarafta duran bir okul otobüsü için durması GEREKMEYEN yol türü hangisidir?","options":["Bordür veya başka bir fiziksel bariyerle ayrılmış bir yol; o bariyerle ayrılmış bir şeritteki bir otobüs için","Boyalı çift sarı orta çizgisi olan herhangi bir yol","Her yönde iki veya daha fazla şeridi olan herhangi bir yol","Belirlenen sınırı 50 mph veya daha yüksek olan herhangi bir yol"],"explanation":"29-A MRSA Sec. 2308(3), bir sürücüyü durma yükümlülüğünden yalnızca yol bordür veya başka bir fiziksel bariyerle ayrılmışsa (o bariyerle ayrılmış bir şeritteki bir otobüs için) ya da yayaların geçemeyeceği sınırlı erişimli bir karayolunda muaf tutar. Yalnızca boyalı bir çizgi bu istisnayı oluşturMAZ. Kaynak: Maine Revised Statutes Title 29-A Sec. 2308(3)."},"68":{"q":"Maine, bir okul otobüsü sürücüsünün, yolcu almak veya indirmek için durmadan en az ne kadar önce otobüsün yanıp sönen uyarı ışıklarını yakmasını gerektirir?","options":["50 feet","200 feet","300 feet","100 feet"],"explanation":"29-A MRSA Sec. 2308(1), bir okul otobüsü sürücüsünün, yolcu almak veya indirmek için durmadan en az 100 feet önce yanıp sönen ışıkları yakmasını ve yolcular alınana veya indirilene kadar bunları açık tutmasını gerektirir. Kaynak: Maine Revised Statutes Title 29-A Sec. 2308(1)."},"69":{"q":"Maine'de, kırmızı ışıkları yanıp sönen, duran bir okul otobüsünü yasadışı şekilde geçmek ne olarak sınıflandırılır ve ilk suç için cezası nedir?","options":["$135 para cezalı basit bir trafik kabahati","İlk suç için para cezası olmayan bir hukuki ihlal","$250 asgari para cezalı bir Class E suçu","Zorunlu hapis cezalı bir Class C suçu"],"explanation":"29-A MRSA Sec. 2308(6), 2. fıkranın ihlalini, ilk suç için $250 asgari para cezasıyla cezalandırılan bir Class E suçu yapar; 3 yıl içinde 2. suç için zorunlu 30 günlük ehliyet askıya alma uygulanır. Kaynak: Maine Revised Statutes Title 29-A Sec. 2308(6)."},"70":{"q":"Tabela olmadığında, Maine yasası bir iş veya konut bölgesinde azami hızı kaç olarak belirler?","options":["20 mph","25 mph","30 mph","35 mph"],"explanation":"29-A MRSA Sec. 2074(1), her biri 'aksi belirtilmedikçe' olmak üzere varsayılan azami değerleri okul bölgesinde 15 mph, iş veya konut bölgesinde ya da yapılaşmış kesimde 25 mph ve diğer tüm kamu yollarında 45 mph olarak belirler. Kaynak: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"71":{"q":"Maine'in varsayılan yasal hız sınırları uyarınca (başka bir sınır belirtilmediğinde), 'diğer tüm kamu yollarındaki' azami hız nedir?","options":["55 mph","50 mph","40 mph","45 mph"],"explanation":"29-A MRSA Sec. 2074(1), aksi belirtilmedikçe diğer tüm kamu yollarında varsayılan azami değeri 45 mph olarak belirler (iş/konut 25 mph; okul bölgesi 15 mph). Çoğu numaralı karayolu daha yüksek belirlenmiş sınırlar taşır. Kaynak: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"72":{"q":"Maine Turnpike Authority tarafından belirlenen Maine Turnpike (I-95) üzerindeki azami hız sınırı nedir?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Maine Turnpike Authority kuralları, Turnpike üzerindeki genel azami hızı 70 mph olarak belirler; belirli güney ve kuzey kesimlerinde daha düşük belirlenmiş sınırlar bulunur. Kaynak: Maine Turnpike Authority Policies & Rules."},"73":{"q":"Maine Turnpike'ın Mile Marker 44'ün güneyindeki üç şeritli kesimlerinde, kamyonların (kamyon çekicileri dahil) hangi şeritte çalışmasına izin verilir?","options":["Yalnızca en sağdaki tek şeritte","Sol geçiş şeridi dahil herhangi bir şeritte","Yalnızca en sağdaki iki şeritte","Yalnızca orta şeritte"],"explanation":"Güney Maine'in hava kalitesini iyileştirmek için, Maine Turnpike Authority kuralları, Turnpike'ın her yönde üç şeridi olan ve Mile Marker 44'ün güneyinde kalan herhangi bir kesiminde kamyonları (kamyon çekicileri dahil, pikaplar hariç) en sağdaki iki şeritle sınırlar. Kaynak: Maine Turnpike Authority Policies & Rules."},"74":{"q":"Maine'de bir CMV'yi tek yönlü veya bölünmüş bir karayolunun üzerinde ya da yanında durdurmanız gerekirse, Maine CDL Kılavuzu, üç uyarı cihazınızı yaklaşan trafiğe doğru hangi mesafelere yerleştirmenizi söyler?","options":["10 feet, 50 feet ve 150 feet","10 feet, 100 feet ve 200 feet","25 feet, 100 feet ve 300 feet","50 feet, 100 feet ve 500 feet"],"explanation":"Maine CDL Kılavuzu (Sec. 2.5.1), tek yönlü veya bölünmüş bir karayolunun üzerinde ya da yanında durulduğunda uyarı cihazlarının yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafelere yerleştirilmesini yönlendirir. Kaynak: Maine CDL Manual, Section 2."},"75":{"q":"İki şeritli (iki yönlü bölünmemiş) bir Maine karayolunda, bir CMV durduğunda gerekli üç uyarı cihazı nasıl yerleştirilmelidir?","options":["Hepsi aracın arkasında olmak üzere 10 feet, 100 feet ve 200 feet","Yalnızca aracın arkasında 50 feet, 200 feet ve 300 feet","Bir cihaz 10 feet içinde ve iki cihaz yalnızca 500 feet arkada","Aracın 10 feet içinde ve aracın 100 feet önünde ve 100 feet arkasında"],"explanation":"Maine CDL Kılavuzu (Sec. 2.5.2), aracı işaretlemek için ön veya arkanın 10 feet içine bir cihaz, ayrıca bankette veya işgal edilen şeritte 100 feet arkaya bir ve 100 feet öne bir cihaz yerleştirmeyi yönlendirir. Kaynak: Maine CDL Manual, Section 2."},"76":{"q":"Bir Maine yolunda bir CMV'yi durdurduktan sonra, acil durum uyarı cihazlarınızı kaç dakika içinde yerleştirmiş olmanız gerekir?","options":["10 dakika","5 dakika","15 dakika","30 dakika"],"explanation":"Maine CDL Kılavuzu (Sec. 2.5.1), bir yolda veya bankette durmanız gerekirse, acil durum uyarı cihazlarını on dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: Maine CDL Manual, Section 2."},"77":{"q":"Maine'de bir CMV bir tepenin veya virajın hemen ötesinde durdurulursa, Maine CDL Kılavuzu, arka uyarı cihazının şu şekilde yeniden konumlandırılmasını söyler:","options":["Virajdan bağımsız olarak araçtan tam olarak 200 feet uzağa yerleştirilir","Tehlike ışıkları yeterli olduğu için kaldırılır","Sürücülere yol boyunca geriye doğru uyarı verir, böylece araç 500 feet içinde görünür hale gelir","Tepenin zirvesine, tam olarak 50 feet ileriye yerleştirilir"],"explanation":"Maine CDL Kılavuzu (Sec. 2.5.2), bir tepe veya viraj görüş hattını engelliyorsa, uyarı sağlanması ve diğer sürücülerin aracı 500 feet içinde görebilmesi için en arkadaki üçgeni yol boyunca geriye taşımayı yönlendirir. Kaynak: Maine CDL Manual, Section 2."},"78":{"q":"Maine'de, hangi boyutu aşan bir yük genellikle Bureau of Motor Vehicles / MaineDOT'tan bir aşırı boyut (oversize) izni gerektirir?","options":["10 feet 0 inç'ten büyük bir genişlik veya 15 feet 0 inç'ten büyük bir yükseklik","8 feet 6 inç'ten büyük bir genişlik veya 13 feet 6 inç'ten büyük bir yükseklik","8 feet 0 inç'ten büyük bir genişlik veya 12 feet 0 inç'ten büyük bir yükseklik","9 feet 0 inç'ten büyük bir genişlik veya 14 feet 6 inç'ten büyük bir yükseklik"],"explanation":"Maine, 8 feet 6 inç genişlik ve 13 feet 6 inç yükseklik standart yasal sınırlarını izler; bunları aşan yükler, Maine BMV/MaineDOT aşırı boyut izin programı aracılığıyla verilen bir aşırı boyut (oversize) izni gerektirir. Kaynak: Maine BMV Overlimit Permits / MaineDOT."},"79":{"q":"Hangi Maine kurumu Ticari Sürücü Belgelerini (CDL) düzenler ve CDL sınavlarını yönetir?","options":["Secretary of State ofisi bünyesindeki Maine Bureau of Motor Vehicles (BMV)","Maine Department of Transportation (MaineDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Maine State Police Commercial Vehicle Enforcement Unit"],"explanation":"Secretary of State ofisinin bir birimi olan Maine Bureau of Motor Vehicles (BMV), tüm Maine CDL'lerini düzenler ve bilgi ile beceri sınavlarını yönetir. MaineDOT, lisanslamayı değil, yolları ve aşırı boyut/ağırlık izinlerini ele alır. Kaynak: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv)."},"80":{"q":"Maine CDL öz beyan formunda (MVE-64C), bir başvuru sahibi kaç işletme türü kategorisi arasından seçim yapabilir?","options":["Dört","İki","Üç","Altı"],"explanation":"Maine, DÖRT kategoriden birine öz beyan gerektirir: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate veya Excepted Intrastate. Kaynak: Maine BMV CDL Medical Self-Certification Form MVE-64C; 49 CFR 383.71."},"81":{"q":"Bir Maine sürücüsü 'Non-Excepted Interstate' olarak öz beyanda bulunur. BMV'nin dosyasında hangi ek belgenin bulunması gerekir?","options":["Federal bir DOT Medical Examiner's Certificate (sağlık kartı)","Öz beyan formunun ötesinde hiçbir şey","Noter onaylı bir işveren yetki mektubu","Bir Maine DOT aşırı boyut/ağırlık izni"],"explanation":"Non-Excepted Interstate olarak öz beyanda bulunan sürücüler, BMV'ye geçerli bir federal Medical Examiner's Certificate (MCSA-5876 / sağlık kartı) sağlamalıdır. Excepted sürücülerin bunu sunması gerekmez. Kaynak: Maine BMV CDL self-certification guidance; 49 CFR 383.71."},"82":{"q":"Maine'de bir CDL başvuru sahibinin Medical Examiner's Certificate'ını üreten DOT fizik muayenesini yapmaya kim yetkilidir?","options":["FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayene uzmanı","Başvuru sahibinin seçtiği herhangi bir lisanslı hekim","Sınav merkezindeki bir BMV sınav görevlisi","Başvuru sahibinin düzenli göz doktoru"],"explanation":"DOT fizik muayenesi, FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: Maine BMV CDL medical requirements; 49 CFR 391.43."},"83":{"q":"Bir Maine CDL sahibi için bir DOT Medical Examiner's Certificate'ın geçerli olabileceği azami süre nedir?","options":["2 yıl","1 yıl","3 yıl","5 yıl"],"explanation":"Bir Medical Examiner's Certificate azami 2 yıl geçerlidir; bir muayene uzmanı, bir durumun izlenmesi gerekiyorsa bir sürücüyü daha kısa bir süre için onaylayabilir. Eskisi sona ermeden önce dosyada yeni bir kart bulunmalıdır. Kaynak: Maine BMV CDL medical requirements; 49 CFR 391.45."},"84":{"q":"Bir Maine CDL sahibi, bir öz beyan formunu veya sağlık sertifikasını BMV'nin CDL Compliance Unit'ine nasıl gönderebilir?","options":["BMV CDL Compliance Unit'e faks, e-posta veya posta yoluyla","Yalnızca Augusta merkez ofisinde şahsen","Yalnızca FMCSA Training Provider Registry'ye yükleyerek","Yalnızca sürücünün işvereni veya taşıyıcısı aracılığıyla"],"explanation":"Maine, MVE-64C öz beyanını ve sağlık sertifikasını faks yoluyla, CDL Compliance Unit'e e-posta (PDF/Word) yoluyla veya Augusta'daki BMV CDL Compliance Unit'e posta yoluyla kabul eder. Kaynak: Maine BMV CDL Compliance Unit submission instructions."},"85":{"q":"Bir kişiye Maine Commercial Learner's Permit (CLP) verilmeden önce, asgari olarak hangi bilgi sınavı geçilmelidir?","options":["General Knowledge sınavı","Yalnızca Air Brakes onay sınavı","Hazardous Materials sınavı","Sefer öncesi muayene beceri sınavı"],"explanation":"Bir CLP almak için General Knowledge sınavı (artı başvuru sahibinin istediği herhangi bir onay sınavı) geçilmelidir. Maine BMV, bu sınavların dayandığı resmi CDL kılavuzunu yayımlar. Kaynak: Maine CDL Manual; Maine BMV CDL Exam page."},"86":{"q":"Her Maine CDL bilgi sınavında asgari geçer not nedir?","options":["80%","70%","75%","90%"],"explanation":"Bir sürücü, geçmek için her bilgi sınavındaki soruların en az 80%'ini doğru yanıtlamalıdır. Kaynak: Maine CDL Manual; 49 CFR 383.135."},"87":{"q":"Maine CDL beceri sınavı, sırasıyla hangi üç bölümden oluşur?","options":["Sefer öncesi araç muayenesi, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Hava freni kontrolü, geri gitme ve yazılı bir onay sınavı","Temel araç kontrolü, paralel park ve bir hazmat mülakatı"],"explanation":"CDL beceri sınavının bu sırayla uygulanan üç bölümü vardır: sefer öncesi araç muayenesi, temel araç kontrol sınavı ve yolda sürüş sınavı. Kaynak: Maine CDL Manual; 49 CFR 383.113."},"88":{"q":"Hangi beceri sınavı bileşeni, bir Maine başvuru sahibinin düz çizgide geri gitme, ofset geri gitme ve dar yola yanaşma (alley docking) gibi manevraları gerçekleştirmesini gerektirir?","options":["Temel araç kontrol sınavı","Sefer öncesi araç muayenesi","Yolda sürüş sınavı","General Knowledge sınavı"],"explanation":"Düz çizgide geri gitme, ofset geri gitme ve dar yola yanaşma (alley docking) gibi geri gitme manevraları, beceri sınavının temel araç kontrol bölümünde değerlendirilir. Kaynak: Maine CDL Manual; 49 CFR 383.113."},"89":{"q":"Maine'de ilk kez Class A CDL başvurusunda bulunan biri, Entry-Level Driver Training (ELDT) eğitimini şu özellikteki bir sağlayıcıdan tamamlamalıdır:","options":["FMCSA Training Provider Registry'de (TPR) listelenen","Yalnızca Maine BMV sınav görevlisi havuzu tarafından onaylanan","Yerel topluluk koleji sistemi tarafından sertifikalandırılan","MaineDOT'un izin ofisine kayıtlı olan"],"explanation":"ELDT, FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan alınmalıdır; sağlayıcı, tamamlanmayı elektronik olarak FMCSA'ya bildirir. Kaynak: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"90":{"q":"Aşağıdakilerden hangisi için Maine, sınavdan önce ELDT gerektirir?","options":["İlk kez bir Class A veya B CDL ya da ilk kez bir P, S veya H onayı","Sınıfa bakılmaksızın her CDL yenilemesi","Yalnızca Hazardous Materials (H) onayı başvuru sahipleri","Yalnızca Class B'den Class A'ya yükseltme yapan sürücüler"],"explanation":"ELDT, ilk kez bir Class A veya Class B CDL almak, daha yüksek bir sınıfa yükseltmek ya da ilk kez bir yolcu (P), okul otobüsü (S) veya tehlikeli madde (H) onayı almak için gereklidir. Kaynak: Maine BMV ELDT page; 49 CFR Part 380."},"91":{"q":"Bir Maine CDL başvuru sahibi, gerekli ELDT'yi ne zaman tamamlamalıdır?","options":["İlgili bilgi veya beceri sınavına girmeden önce","Beceri sınavını geçtikten sonra ancak ehliyet basılmadan önce","CDL düzenlendikten sonraki 30 gün içinde","Yalnızca CLP'nin 14 günlük bekleme süresi dolduktan sonra"],"explanation":"Bir H onayı için ELDT teorisi bilgi sınavından önce ve Class A/B ile P/S onayları için direksiyon başında eğitim beceri sınavından önce tamamlanmalıdır. Eğitim, ilgili sınavdan önce gelmelidir. Kaynak: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"92":{"q":"Bir CLP aldıktan sonra, bir Maine başvuru sahibinin CDL beceri sınavına girmesine izin verilmeden önce CLP'yi ne kadar süre elinde tutması gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Bir CLP sahibi, beceri sınavına girmeden önce, izin düzenlendikten sonra en az 14 gün beklemelidir. Kaynak: Maine BMV CDL pages; 49 CFR 383.25."},"93":{"q":"Bir Maine CLP ile araç kullanırken, izin sahibine şu kişi eşlik etmelidir:","options":["O aracın sınıfı ve onayları için geçerli, sürücünün yanında oturan bir CDL sahibi","21 yaşında veya daha büyük herhangi bir lisanslı sürücü","Yalnızca bir BMV sınav görevlisi","Araç boş olduğu sürece hiç kimse"],"explanation":"Bir CLP sahibi, yalnızca o araç sınıfı için geçerli bir CDL'ye sahip olan ve izin sahibinin yanında ön koltukta oturan bir kişi eşlik ettiğinde ticari bir motorlu taşıt kullanabilir. Kaynak: Maine CDL Manual; 49 CFR 383.25."},"94":{"q":"65 yaşın altındaki çoğu Maine CDL sahibi için, CDL ne sıklıkla yenilenmelidir?","options":["Her 5 yılda bir","Her 4 yılda bir","Her 6 yılda bir","Her 8 yılda bir"],"explanation":"Bir Maine CDL, 65 yaşın altındaki sahipler için 5 yıllık bir döngü için düzenlenir. (65 yaş ve üzeri sahipler 4 yıllık bir döngüde yeniler.) Kaynak: Maine BMV CDL renewal information."},"95":{"q":"Yalnızca eyalet içinde (Maine içinde) araç kullanmak üzere bir Maine CDL alabilmek için asgari yaş nedir?","options":["18","21","19","16"],"explanation":"Bir başvuru sahibi, eyalet içi sürüş için bir Maine CDL almak üzere en az 18 yaşında olmalıdır; eyaletler arası sürüş, tehlikeli madde taşıma veya yolcu taşıma için 21 yaş gereklidir. Kaynak: Maine CDL Manual; Maine BMV CDL pages."},"96":{"q":"Bir Maine başvuru sahibinin, bir CDL için başvururken kimliği ve uygunluğu belgelemek için tipik olarak hangi belge setine ihtiyacı olur?","options":["Kimlik kanıtı, ABD'de yasal bulunma, Social Security numarası ve Maine ikametgahı","Yalnızca güncel bir Maine ticari olmayan sürücü belgesi","Bir pasaport artı bir MaineDOT aşırı boyut izni","Yalnızca bir işveren mektubu ve bir araç tescili"],"explanation":"Başvuru sahipleri, tıbbi ve öz beyan gerekliliklerini karşılamanın yanı sıra kimliği, ABD'de yasal bulunmayı, bir Social Security numarasını ve Maine ikametgahını belgelemelidir. Kaynak: Maine BMV CDL application requirements."},"97":{"q":"Bir Maine sürücüsü, gerekli sağlık sertifikasının BMV dosyasında artık bulunmayacak şekilde süresinin geçmesine izin verirse, muhtemel sonuç nedir?","options":["Geçerli bir sertifika dosyalanana kadar sürücünün CDL ayrıcalığı düşürülür (ticari ayrıcalıklar kaldırılır)","CDL'nin normal yenileme tarihine kadar hiçbir şey değişmez","CDL, yeniden geçerli kılma yolu olmaksızın kalıcı olarak iptal edilir","Yalnızca ehliyet üzerinde hiçbir etkisi olmayan yazılı bir uyarı verilir"],"explanation":"Non-excepted bir sürücünün sağlık sertifikasının süresi geçer ve BMV ile güncellenmezse, eyalet, güncel bir sertifika sunulana kadar ticari sürüş ayrıcalıklarını kaldırarak CDL'yi düşürmelidir. Kaynak: Maine BMV CDL Compliance guidance; 49 CFR 383.73."}},"es":{"0":{"q":"En una vía pública de Maine, ¿cuál es el ancho total máximo permitido para un vehículo sin un permiso especial?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"Conforme a 29-A M.R.S. §2380, un vehículo con un ancho total mayor a 102 pulgadas (8'6\") no puede circular por una vía pública o un puente de Maine sin un permiso. Fuente: Estatutos Revisados de Maine, Título 29-A, §2380."},"1":{"q":"¿Cuál es la altura estructural máxima legal de un vehículo en las carreteras de Maine sin un permiso de sobredimensión?","options":["12 pies 6 pulgadas","13 pies","13 pies 6 pulgadas","14 pies"],"explanation":"29-A M.R.S. §2380 prohíbe operar un vehículo con una parte estructural permanente o temporal de más de 13 pies 6 pulgadas de alto. Una carga no reducible puede sobresalir hasta 6 pulgadas por encima de eso, pero el límite estructural es de 13'6\". Fuente: Estatutos Revisados de Maine, Título 29-A, §2380."},"2":{"q":"En Maine, ciertos accesorios laterales (como los espejos y los guardabarros) se excluyen de la medición del ancho solo si no sobresalen del costado del vehículo más de cuánto?","options":["2 pulgadas","3 pulgadas","6 pulgadas","9 pulgadas"],"explanation":"29-A M.R.S. §2380 excluye accesorios específicos (espejos, bisagras de puertas, canaletas de lluvia, guardabarros, etc.) de la medición de ancho de 102 pulgadas, siempre que no sobresalgan más de 3 pulgadas del costado del vehículo. Fuente: Estatutos Revisados de Maine, Título 29-A, §2380."},"3":{"q":"¿Cuál es el peso bruto máximo de un vehículo combinado de cinco o más ejes en las carreteras generales (no interestatales) de Maine bajo los límites de peso estándar?","options":["69,000 libras","73,280 libras","80,000 libras","90,000 libras"],"explanation":"Conforme a 29-A M.R.S. §2353, el peso bruto máximo para una combinación de cinco o más ejes es de 80,000 libras (un vehículo de 2 ejes está limitado a 34,000, uno de 3 ejes a 54,000 y uno de 4 ejes a 69,000). Fuente: Estatutos Revisados de Maine, Título 29-A, §2353."},"4":{"q":"Bajo los límites de peso estándar (no interestatales) de Maine en §2353, ¿cuál es el peso máximo permitido sobre un solo eje?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"29-A M.R.S. §2353 establece el límite de un solo eje en 22,400 libras en el sistema de carreteras generales de Maine, lo cual es mayor que la cifra federal interestatal de 20,000 libras por eje único. Fuente: Estatutos Revisados de Maine, Título 29-A, §2353."},"5":{"q":"En el sistema de carreteras generales de Maine (§2353), ¿cuál es el peso máximo permitido sobre una unidad de ejes en tándem?","options":["34,000 libras","36,000 libras","38,000 libras","41,000 libras"],"explanation":"29-A M.R.S. §2353 permite 38,000 libras sobre una unidad de ejes en tándem en las vías generales de Maine, lo cual excede el límite de tándem de 34,000 libras que aplica en el Sistema de Carreteras Interestatales bajo §2355. Fuente: Estatutos Revisados de Maine, Título 29-A, §2353."},"6":{"q":"En el Sistema de Carreteras Interestatales en Maine, ¿cuál es el peso máximo permitido sobre una unidad de ejes en tándem?","options":["32,000 libras","34,000 libras","38,000 libras","41,000 libras"],"explanation":"29-A M.R.S. §2355 limita una unidad de ejes en tándem a 34,000 libras en el Sistema de Carreteras Interestatales, igualando el estándar federal. Las vías generales de Maine permiten un tándem mayor de 38,000 libras bajo §2353. Fuente: Estatutos Revisados de Maine, Título 29-A, §2355."},"7":{"q":"En el sistema interestatal de Maine, un vehículo con un peso bruto vehicular mayor a 73,280 libras está limitado a qué peso por eje único?","options":["18,000 libras","20,000 libras","22,000 libras","22,400 libras"],"explanation":"29-A M.R.S. §2355 limita el eje único a 20,000 libras cuando el peso bruto vehicular excede las 73,280 libras (y a 22,000 libras cuando el peso bruto vehicular es de 73,280 o menos) en el Sistema de Carreteras Interestatales. Fuente: Estatutos Revisados de Maine, Título 29-A, §2355."},"8":{"q":"En el sistema interestatal de Maine, un vehículo con un peso bruto vehicular de 73,280 libras o menos puede llevar qué peso máximo sobre un solo eje?","options":["20,000 libras","22,000 libras","22,400 libras","24,200 libras"],"explanation":"29-A M.R.S. §2355 permite un eje único de hasta 22,000 libras cuando el peso bruto vehicular es de 73,280 libras o menos en la interestatal, reduciéndose a 20,000 libras cuando el peso bruto vehicular excede las 73,280. Fuente: Estatutos Revisados de Maine, Título 29-A, §2355."},"9":{"q":"En la fórmula federal de puentes usada en el sistema interestatal de Maine, W = 500(LN/(N-1) + 12N + 36), ¿qué representa la variable \"L\"?","options":["La longitud de la carga en pies","La distancia en pies entre los ejes extremos de un grupo","El peso legal por eje en miles de libras","El número de ejes cargados del vehículo"],"explanation":"En la Fórmula B de Puentes federal aplicada por 29-A M.R.S. §2355, W es el peso bruto permitido sobre un grupo de ejes, N es el número de ejes del grupo y L es la distancia en pies entre los ejes extremos (exteriores) de ese grupo. Fuente: Estatutos Revisados de Maine, Título 29-A, §2355 (fórmula federal de puentes)."},"10":{"q":"Una combinación de seis ejes en Maine (tractor de 3 ejes con semirremolque de tres ejes) puede alcanzar un peso bruto máximo de hasta qué cantidad cuando se cumplen todas las condiciones?","options":["80,000 libras","90,000 libras","100,000 libras","120,000 libras"],"explanation":"29-A M.R.S. §2354 permite que una combinación de seis ejes (tractocamión de 3 ejes con semirremolque de tres ejes) alcance hasta 100,000 libras cuando se cumplen el espaciamiento y otras condiciones; el límite base es de 90,000 libras. Fuente: Estatutos Revisados de Maine, Título 29-A, §2354."},"11":{"q":"Para la combinación de seis ejes y 100,000 libras de Maine, la distancia entre los ejes extremos (excluyendo el eje de dirección) debe ser de al menos cuántos pies?","options":["30 pies","32 pies","36 pies","40 pies"],"explanation":"29-A M.R.S. §2354 exige que la distancia entre los ejes extremos (excluyendo el eje de dirección) no sea menor a 36 pies; el peso bruto máximo se reduce en 2,000 libras por cada pie que la distancia sea menor a 36 pies. Fuente: Estatutos Revisados de Maine, Título 29-A, §2354."},"12":{"q":"Bajo el estatuto de peso de seis ejes de Maine, ¿en cuánto se reduce el peso bruto máximo por cada pie que el espaciamiento de los ejes extremos quede por debajo del mínimo requerido?","options":["1,000 libras por pie","1,500 libras por pie","2,000 libras por pie","2,500 libras por pie"],"explanation":"29-A M.R.S. §2354 reduce el peso bruto máximo permitido de una combinación de seis ejes en 2,000 libras por cada pie que la distancia entre los ejes extremos sea menor a los 36 pies requeridos. Fuente: Estatutos Revisados de Maine, Título 29-A, §2354."},"13":{"q":"El estatuto de tolerancia de peso de Maine (§2357) permite que las cargas que califican (por ejemplo, productos de madera, sal de carretera, grava) excedan el peso bruto máximo en qué cantidad?","options":["Hasta un 5% por encima del máximo","Hasta un 10% (110% del máximo)","Hasta un 15% por encima del máximo","Hasta 2,000 libras por encima del máximo"],"explanation":"29-A M.R.S. §2357 dispone que un vehículo que califica no incurre en infracción si su peso bruto vehicular no excede el 110% (10% por encima) del peso bruto máximo establecido en §2353, para productos enumerados como productos de madera, grava, sal de carretera y materiales a granel similares. Fuente: Estatutos Revisados de Maine, Título 29-A, §2357."},"14":{"q":"La tolerancia de peso del 10% de Maine para ciertos productos (§2357) aplica en cuáles caminos?","options":["Solo en el Sistema de Carreteras Interestatales","En todas las vías de Maine excepto el Sistema de Carreteras Interestatales","Solo en la Maine Turnpike","En todos los caminos de Maine, incluida la interestatal"],"explanation":"29-A M.R.S. §2357 establece expresamente que la tolerancia de peso no aplica a un vehículo que circula por el Sistema de Carreteras Interestatales; está disponible en las vías generales (no interestatales) de Maine. Fuente: Estatutos Revisados de Maine, Título 29-A, §2357."},"15":{"q":"¿Quién es la autoridad que otorga los permisos de circulación de sobredimensión/sobrepeso a nivel estatal en Maine, actuando bajo el consejo del Comisionado de Transporte?","options":["El Secretario de Estado","La Policía Estatal de Maine","La Maine Turnpike Authority","La Comisión de Servicios Públicos"],"explanation":"Conforme a 29-A M.R.S. §2382, el Secretario de Estado (a través de la Oficina de Vehículos Motorizados), actuando bajo las directrices y el consejo del Comisionado de Transporte, otorga los permisos de circulación de sobredimensión; los condados y municipios pueden autorizar la circulación por sus propias vías. Fuente: Estatutos Revisados de Maine, Título 29-A, §2382."},"16":{"q":"En Maine, se requiere un permiso de sobredimensión/sobrepeso para mover qué tipo de carga que excede los límites legales de dimensión o peso?","options":["Cualquier carga, ya sea que pueda separarse o no","Solo cargas divisibles que pueden dividirse en unidades legales","Un objeto no divisible que no puede reducirse a los límites legales","Solo cargas transportadas en el Sistema de Carreteras Interestatales"],"explanation":"29-A M.R.S. §2381 y §2382 autorizan permisos para objetos no divisibles (aquellos que no pueden razonablemente reducirse a la longitud, ancho, altura o peso legal). Las cargas divisibles deben descomponerse hasta los límites legales en lugar de obtener un permiso. Fuente: Estatutos Revisados de Maine, Título 29-A, §§2381–2382."},"17":{"q":"¿Cuál es la duración máxima de un permiso de sobredimensión de largo plazo que el Secretario de Estado de Maine puede emitir para camiones, tractores y semirremolques?","options":["30 días","6 meses","Un año","Dos años"],"explanation":"29-A M.R.S. §2382 permite que el Secretario de Estado otorgue permisos válidos por hasta un año para camiones, tractocamiones, semirremolques, vehículos de recuperación de servicio pesado y equipo móvil especial Clase A; de lo contrario, se emiten permisos de un solo viaje. Fuente: Estatutos Revisados de Maine, Título 29-A, §2382."},"18":{"q":"Cuando un semirremolque de 53 pies de Maine circula fuera de la red nacional de carreteras, la longitud total del vehículo y la carga no puede exceder qué longitud total?","options":["65 pies","69 pies","74 pies","80 pies"],"explanation":"29-A M.R.S. §2390 permite un semirremolque de más de 48 pies pero no más de 53 pies (con una distancia del pivote (kingpin) al eje trasero no mayor a 43 pies), pero al circular fuera de la red nacional la longitud total no puede exceder los 74 pies. En el Sistema de Carreteras Interestatales el límite de longitud total no aplica. Fuente: Estatutos Revisados de Maine, Título 29-A, §2390."},"19":{"q":"Bajo la ley de Maine, ¿qué clase de CDL se requiere para operar cualquier combinación de vehículos con una capacidad de peso bruto combinado (GCWR) de 26,001 libras o más, donde el o los vehículos remolcados exceden las 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Maine define la Clase A como cualquier combinación de vehículos con un GCWR de 26,001 libras o más, siempre que el GVWR/peso bruto del o los vehículos remolcados exceda las 10,000 libras. Fuente: Manual de CDL de Maine, 'Definiciones de Clases'; 29-A MRSA §1253."},"20":{"q":"Un conductor de Maine opera un solo camión rígido con una capacidad de peso bruto vehicular de 30,000 libras y no remolca ningún remolque. ¿Qué clase de CDL requiere esto?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"La Clase B de Maine cubre cualquier vehículo único con un GVWR de 26,001 libras o más, o dicho vehículo remolcando una unidad de no más de 10,000 libras. Una unidad única de 30,000 libras es Clase B. Fuente: Manual de CDL de Maine, 'Definiciones de Clases'; 29-A MRSA §1253."},"21":{"q":"En Maine, un vehículo que no cumple con las definiciones de peso de Clase A o Clase B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor), o que transporta materiales peligrosos con rótulo, ¿en qué clase de CDL queda clasificado?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"La Clase C de Maine es cualquier vehículo único o combinado que no cumple con la Clase A/B y que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos con rótulo. Fuente: Manual de CDL de Maine, 'Definiciones de Clases' y Figura 1.1; 29-A MRSA §1253."},"22":{"q":"Según el Manual de CDL de Maine, ¿qué endoso se requiere para operar vehículos que transportan materiales peligrosos cuando la carga debe llevar rótulo bajo las regulaciones federales del DOT?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"Maine usa el endoso H para la operación de vehículos que transportan materiales peligrosos cuando se requiere que lleven rótulo según la regulación federal del DOT. El endoso X combina el de tanque (N) y el de materiales peligrosos (H). Fuente: Manual de CDL de Maine, 'Endosos'."},"23":{"q":"En una CDL de Maine, ¿qué autoriza el endoso 'X'?","options":["La operación únicamente de vehículos cisterna","La operación de vehículos cisterna que transportan materiales peligrosos (combina N y H)","La operación de remolques dobles y triples","La operación de autobuses de pasajeros de más de 15 pasajeros"],"explanation":"El endoso X de Maine es para la operación de vehículos cisterna que transportan materiales peligrosos, combinando los endosos N (tanque) y H (materiales peligrosos) en uno solo. Fuente: Manual de CDL de Maine, 'Endosos'."},"24":{"q":"El Manual de CDL de Maine señala una restricción específica respecto al endoso 'T' (dobles/triples). ¿Qué afirmación es correcta para Maine?","options":["Tanto los remolques dobles como los triples pueden operarse libremente en todo el estado","Los remolques triples no están permitidos en Maine","El endoso T también autoriza vehículos cisterna","Los remolques dobles requieren una prueba de pasajeros aparte"],"explanation":"El Manual de CDL de Maine describe el endoso T como para remolques dobles/triples 'donde lo permita la ley' y afirma claramente que los remolques triples no están permitidos en Maine. Fuente: Manual de CDL de Maine, 'Endosos'."},"25":{"q":"Según el Manual de CDL de Maine, el endoso N (vehículo cisterna) se requiere para transportar un líquido o gas licuado en un tanque de carga montado de forma permanente con una capacidad mínima de cuánto?","options":["100 galones o más","119 galones o más","1,000 galones o más","450 galones o más"],"explanation":"Maine requiere la prueba/endoso de cisterna (N) para transportar líquido o gas licuado en un tanque de carga montado de forma permanente con una capacidad de 119 galones o más, o un tanque portátil con una capacidad de 1,000 galones o más. Fuente: Manual de CDL de Maine, '1.1.1 Pruebas de Conocimiento' y la sección de vehículos cisterna."},"26":{"q":"En Maine, calificar exitosamente para cuál endoso también otorga automáticamente el endoso 'P' (pasajeros) sin cargo adicional ni examen adicional?","options":["H (Materiales Peligrosos)","N (Vehículo Cisterna)","S (Autobús Escolar)","T (Dobles/Triples)"],"explanation":"El Manual de CDL de Maine establece que la calificación exitosa para el endoso S (autobús escolar) también otorga el endoso P (pasajeros) sin un cargo adicional ni examen adicional. Fuente: Manual de CDL de Maine, 'Endosos'."},"27":{"q":"Según el Manual de CDL de Maine, ¿cuáles endosos se otorgan al aprobar únicamente la prueba de conocimiento (escrita), sin requerir una prueba de habilidades aparte?","options":["P y S","N, H, X y T","Solo H","Todos los endosos requieren una prueba de habilidades"],"explanation":"El Manual de CDL de Maine establece que los endosos N, H, X y T se otorgan al titular de la CDL al completar exitosamente solo el examen de conocimiento; P y S requieren la prueba completa, incluida la prueba de habilidades. Fuente: Manual de CDL de Maine, 'Endosos'."},"28":{"q":"Maine reconoce un endoso '3' para un tipo de operación de autobús escolar que NO requiere que el conductor tenga una CDL. ¿Para cuántos pasajeros está diseñado ese autobús?","options":["16 o más pasajeros incluido el conductor","15 pasajeros o menos incluido el conductor","Exactamente 24 pasajeros","Más de 15 pasajeros excluido el conductor"],"explanation":"El Manual de CDL de Maine describe un endoso '3' para un autobús escolar diseñado para transportar 15 pasajeros o menos (incluido el conductor); puede adjuntarse a una licencia no comercial y no requiere una CDL. Fuente: Manual de CDL de Maine, 'endoso \"3\"'."},"29":{"q":"Bajo las reglas de CDL de Maine, ¿cuál es la edad mínima para operar un vehículo motorizado comercial en el comercio intraestatal (solo dentro de Maine)?","options":["16 años","18 años","21 años","19 años"],"explanation":"La edad mínima de Maine para una CDL intraestatal es 18. (El texto más antiguo del Manual de CDL de Maine menciona la edad de 16 para algunas operaciones intraestatales, pero el BMV aplica el piso federal de 18 para la operación de CDL intraestatal). Fuente: Maine BMV / FMCSA 49 CFR 391.11; disposiciones de edad del Manual de CDL de Maine."},"30":{"q":"¿Cuál es la edad mínima en Maine para obtener una CDL válida para el comercio interestatal (cruzar líneas estatales)?","options":["18 años","19 años","21 años","25 años"],"explanation":"Un conductor debe tener al menos 21 años de edad para operar un CMV en el comercio interestatal, para transportar materiales peligrosos o para conducir un autobús de pasajeros. Fuente: disposiciones de edad del Manual de CDL de Maine; FMCSA 49 CFR 391.11."},"31":{"q":"Según 29-A MRSA §1304(4-A), un titular de un permiso de aprendiz comercial (CLP) de Maine NO es elegible para tomar la prueba de habilidades de la CDL durante qué periodo después de la emisión inicial del permiso?","options":["Los primeros 7 días","Los primeros 14 días","Los primeros 30 días","Los primeros 60 días"],"explanation":"La ley de Maine dispone que un titular de un CLP no es elegible para tomar la prueba de habilidades de la CDL durante los primeros 14 días después de la emisión inicial del CLP, lo cual coincide con el requisito federal. Fuente: 29-A MRSA §1304(4-A)(I)."},"32":{"q":"Bajo 29-A MRSA §1304, un permiso de aprendiz comercial (CLP) de Maine es válido por no más de cuánto tiempo a partir de la fecha de emisión?","options":["180 días","Un año","Dos años","Cinco años"],"explanation":"La ley de Maine establece que el permiso de aprendiz comercial es válido por no más de un año a partir de la fecha de emisión. Fuente: 29-A MRSA §1304(4-A)(G)."},"33":{"q":"Mientras opera un CMV bajo un permiso de aprendiz comercial de Maine, el titular del CLP debe estar acompañado por un titular de CDL ubicado ¿dónde?","options":["En cualquier lugar del vehículo","Siguiéndolo en un vehículo separado","Físicamente presente en el asiento delantero junto al titular del CLP (o, en un vehículo de pasajeros, directamente detrás o en la primera fila detrás del conductor)","Disponible por teléfono durante la operación"],"explanation":"La ley de Maine requiere que el titular de CDL acompañante esté físicamente presente en el asiento delantero junto al titular del CLP, o en un vehículo de pasajeros directamente detrás o en la primera fila detrás del conductor, con la clase y los endosos adecuados. Fuente: 29-A MRSA §1304(4-A)(A)."},"34":{"q":"¿Cuál actividad está expresamente prohibida para un titular de un permiso de aprendiz comercial de Maine bajo 29-A MRSA §1304(4-A)?","options":["Operar un vehículo motorizado comercial que transporta materiales peligrosos","Conducir durante las horas de luz del día","Operar un vehículo de Clase B","Practicar en carreteras interestatales"],"explanation":"La ley de Maine prohíbe que un titular de CLP opere un CMV que transporta materiales peligrosos según se definen en 49 CFR §383.5. Fuente: 29-A MRSA §1304(4-A)(F)."},"35":{"q":"Según 29-A MRSA §1304(4-A), ¿qué edad mínima debe tener un titular de un CLP de Maine para poder solicitar un endoso de pasajeros (P) o de autobús escolar (S)?","options":["18 años","20 años","21 años","22 años"],"explanation":"La ley de Maine requiere que un titular de CLP tenga al menos 21 años de edad para solicitar un endoso de pasajeros o de autobús escolar, y el titular de CDL acompañante debe tener un endoso de pasajeros, al menos un año de experiencia y tener al menos 22 años. Fuente: 29-A MRSA §1304(4-A)(E)."},"36":{"q":"El requisito de Capacitación de Conductores de Nivel Inicial (ELDT) aplicable a los nuevos solicitantes de CDL de Maine se verifica a través de cuál sistema?","options":["El portal en línea del Maine BMV","El Registro de Proveedores de Capacitación (TPR) de la FMCSA","El Registro Nacional de Conductores","La base de datos Secure Flight de la TSA"],"explanation":"A partir del 7 de febrero de 2022, la regla ELDT de la FMCSA requiere capacitación para los nuevos operadores de CDL y ciertas mejoras de categoría, completada por un proveedor inscrito y registrado en el Registro de Proveedores de Capacitación (TPR) de la FMCSA (tpr.fmcsa.dot.gov). Fuente: Manual de CDL de Maine, 'Capacitación de Conductores de Nivel Inicial (ELDT)'; FMCSA 49 CFR Parte 380."},"37":{"q":"Al solicitar una CDL de Maine, un solicitante debe autocertificar un tipo de operación de conducción. ¿Cuál conjunto enumera correctamente las cuatro categorías federales de autocertificación usadas por Maine?","options":["Local, regional, nacional e internacional","Interestatal no exenta, interestatal exenta, intraestatal no exenta e intraestatal exenta","Comercial, privada, agrícola y de emergencia","Operaciones de Clase A, Clase B, Clase C y Clase D"],"explanation":"Maine, siguiendo 49 CFR §383.71, requiere que los solicitantes de CDL autocertifiquen una de cuatro categorías: interestatal no exenta, interestatal exenta, intraestatal no exenta o intraestatal exenta. Las categorías no exentas requieren un certificado válido del examinador médico. Fuente: FMCSA 49 CFR §383.71; Maine BMV."},"38":{"q":"Además de los documentos de identidad, residencia y presencia legal, ¿qué elemento adicional debe revelar un solicitante de CDL de Maine, según lo exige 29-A MRSA para la emisión de la licencia de conducir?","options":["Un número de pasaporte","Un número de Seguro Social","Una tarjeta de registro de votante","Un título de vehículo"],"explanation":"La Declaración de Divulgación del Número de Seguro Social del Manual de CDL de Maine señala que la divulgación del número de Seguro Social es obligatoria y exigida por 29-A MRSA para solicitar o renovar una licencia de conducir; el BMV también requiere comprobante de identidad, residencia en Maine y presencia legal. Fuente: Manual de CDL de Maine, 'Declaración de Divulgación del Número de Seguro Social'; 29-A MRSA."},"39":{"q":"Bajo las reglas de CDL de Maine, ¿a partir de qué concentración de alcohol en la sangre (BAC) es ilegal operar un vehículo motorizado comercial?","options":["0.04% o más","0.08% o más","0.02% o más","0.10% o más"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que es ilegal operar un CMV si su BAC es de .04% o más. Este límite de 0.04 es la mitad del límite de 0.08 para conductores comunes y coincide con el estándar federal 49 CFR 383.51."},"40":{"q":"Al operar un vehículo motorizado comercial en Maine, se considera legalmente que un conductor ha hecho ¿qué?","options":["Renunciado al derecho a un abogado defensor","Dado su consentimiento para las pruebas de alcohol","Aceptado un registro del vehículo en cualquier momento","Consentido a un análisis de orina aleatorio de drogas semanalmente"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece: 'Si usted opera un CMV, se considerará que ha dado su consentimiento para las pruebas de alcohol'. Esta es la regla de consentimiento implícito de Maine para la operación de CMV (véase también 29-A M.R.S. 2521)."},"41":{"q":"Por una primera infracción grave (como conducir un CMV con un BAC de .04% o más), ¿por cuánto tiempo perderá un conductor de Maine su CDL?","options":["Al menos 60 días","Al menos 6 meses","Al menos 1 año","Al menos 90 días"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que perderá su CDL por al menos un año por una primera infracción grave, incluyendo conducir un CMV con un BAC de .04% o más. Esto coincide con el estándar federal 49 CFR 383.51."},"42":{"q":"En Maine, ¿qué le sucede a un titular de CDL que se niega a someterse a una prueba de alcohol en la sangre cuando se le requiere mientras opera un CMV (primera infracción)?","options":["Una advertencia sin descalificación","Pérdida de la CDL por 30 días","Pérdida de la CDL por 120 días","Pérdida de la CDL por al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) enumera 'negarse a someterse a una prueba de alcohol en la sangre' como una primera infracción grave, que conlleva la pérdida de la CDL por al menos un año (3 años si lleva rótulo de materiales peligrosos)."},"43":{"q":"Si una primera infracción grave (por ejemplo, conducir bajo la influencia) ocurre mientras un conductor de Maine opera un CMV con rótulo de materiales peligrosos, ¿por cuánto tiempo como mínimo se pierde la CDL?","options":["3 años","1 año","5 años","De por vida"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que perderá su CDL por al menos tres años si una primera infracción grave ocurre mientras opera un CMV con rótulo de materiales peligrosos, según 49 CFR 383.51."},"44":{"q":"¿Cuál es la consecuencia en Maine por una segunda infracción grave (como un segundo DUI en un CMV)?","options":["Pérdida de la CDL por 10 años","Pérdida de la CDL de por vida","Pérdida de la CDL por 3 años","Pérdida de la CDL por 5 años"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que perderá su CDL de por vida por una segunda infracción grave. Esta descalificación de por vida sigue el estándar federal 49 CFR 383.51."},"45":{"q":"Bajo las reglas de Maine, ¿cuál es la sanción por usar un CMV para cometer un delito grave que involucra sustancias controladas?","options":["Pérdida de la CDL por 1 año","Pérdida de la CDL por 3 años","Pérdida de la CDL de por vida","Pérdida de la CDL por 120 días"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que perderá su CDL de por vida si usa un CMV para cometer un delito grave que involucra sustancias controladas. No hay posibilidad de restablecimiento por esta infracción."},"46":{"q":"En Maine, un conductor con una cantidad detectable de alcohol por debajo de .04% mientras opera un CMV será:","options":["Descalificado por 60 días","Multado con $5,000","Arrestado por OUI automáticamente","Puesto fuera de servicio por 24 horas"],"explanation":"El Manual de CDL de Maine (Sección 1.2.2) establece que será puesto fuera de servicio por 24 horas si tiene cualquier cantidad detectable de alcohol por debajo de .04%. Una descalificación completa requiere un BAC de .04% o más."},"47":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' en el Manual de CDL de Maine?","options":["Exceso de velocidad excesivo (15 mph o más por encima del límite señalado)","Conducir 5 mph por encima del límite señalado","Un registro vehicular vencido","Una sola infracción de estacionamiento"],"explanation":"El Manual de CDL de Maine (Sección 1.2.3) define el exceso de velocidad excesivo como 15 mph o más por encima del límite señalado, y lo enumera como una infracción de tránsito grave junto con la conducción imprudente, los cambios de carril indebidos y seguir demasiado de cerca."},"48":{"q":"¿Por cuánto tiempo perderá un conductor de Maine su CDL por cometer DOS infracciones de tránsito graves en un CMV dentro de un periodo de tres años?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.3) establece que perderá su CDL por al menos 60 días por dos infracciones de tránsito graves dentro de un periodo de tres años que involucren un CMV, según 49 CFR 383.51."},"49":{"q":"¿Por cuánto tiempo perderá un conductor de Maine su CDL por cometer TRES o más infracciones de tránsito graves en un CMV dentro de un periodo de tres años?","options":["Al menos 60 días","Al menos 90 días","Al menos 120 días","Al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.3) establece que perderá su CDL por al menos 120 días por tres o más infracciones de tránsito graves dentro de un periodo de tres años que involucren un CMV, según 49 CFR 383.51."},"50":{"q":"¿Cuál de estas se enumera entre las infracciones de tránsito graves en el Manual de CDL de Maine?","options":["No usar una señal de giro en un estacionamiento","Conducir con un faro fundido","Llevar una carga sin asegurar de menos de 500 libras","Conducir un CMV sin haber obtenido una CDL o sin tenerla en su posesión"],"explanation":"El Manual de CDL de Maine (Sección 1.2.3) enumera conducir un CMV sin haber obtenido una CDL, sin tener la CDL en su posesión, o sin la clase/endosos adecuados como infracciones de tránsito graves."},"51":{"q":"Bajo las reglas federales adoptadas en Maine, enviar mensajes de texto mientras se conduce un CMV y usar un teléfono móvil de mano se tratan como:","options":["Infracciones de tránsito graves","Infracciones mayores con una descalificación de 1 año","Violaciones de una orden de fuera de servicio","Infracciones que no descalifican"],"explanation":"Según 49 CFR 383.51, enviar mensajes de texto (49 CFR 392.80) y usar un teléfono móvil de mano (49 CFR 392.82) mientras se conduce un CMV son infracciones de tránsito graves. Dos en tres años conllevan una descalificación de 60 días; tres conllevan 120 días. Maine adopta estos estándares federales."},"52":{"q":"Bajo las reglas federales sobre teléfonos de mano que aplican a los conductores de CDL de Maine, una sola condena por mensajes de texto o por teléfono de mano también puede conllevar una sanción civil para el conductor de hasta:","options":["$500","$2,750","$11,000","$250"],"explanation":"Bajo las reglas de la FMCSA (49 CFR 392.80/392.82) aplicables en Maine, un conductor enfrenta una sanción civil de hasta $2,750 por cada infracción de mensajes de texto o de teléfono de mano; los empleadores que lo permitan enfrentan sanciones de hasta $11,000. Dos de tales condenas en 3 años también descalifican la CDL por 60 días."},"53":{"q":"Según el Manual de CDL de Maine, ¿por cuánto tiempo perderá un conductor su CDL por una PRIMERA violación de una orden de fuera de servicio?","options":["Al menos 60 días","Al menos 30 días","Al menos 90 días","Al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.4) establece que perderá su CDL por al menos 90 días por una primera violación de una orden de fuera de servicio. (El actual 49 CFR 383.51 Tabla 4 federal establece un mínimo de 180 días, pero el manual publicado de Maine indica 90 días)."},"54":{"q":"Según el Manual de CDL de Maine, ¿por cuánto tiempo perderá un conductor su CDL por DOS violaciones de orden de fuera de servicio dentro de un periodo de diez años?","options":["Al menos 90 días","Al menos 6 meses","Al menos 3 años","Al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.4) establece que perderá su CDL por al menos un año por dos violaciones de orden de fuera de servicio en un periodo de diez años. Una tercera dentro de diez años conlleva al menos tres años."},"55":{"q":"Según el Manual de CDL de Maine, ¿por cuánto tiempo perderá un conductor su CDL por TRES o más violaciones de orden de fuera de servicio dentro de un periodo de diez años?","options":["Al menos 3 años","Al menos 1 año","De por vida","Al menos 120 días"],"explanation":"El Manual de CDL de Maine (Sección 1.2.4) establece que perderá su CDL por al menos tres años por tres o más violaciones de orden de fuera de servicio dentro de un periodo de diez años."},"56":{"q":"Según el Manual de CDL de Maine, ¿por cuánto tiempo perderá un conductor su CDL por una PRIMERA violación en un cruce a nivel de ferrocarril y carretera?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"El Manual de CDL de Maine (Sección 1.2.5) establece que perderá su CDL por al menos 60 días por una primera violación en un cruce a nivel de ferrocarril y carretera, según 49 CFR 383.51."},"57":{"q":"Según el Manual de CDL de Maine, ¿cuál es la descalificación por una TERCERA violación en un cruce a nivel de ferrocarril y carretera dentro de un periodo de tres años?","options":["Al menos 120 días","Al menos 60 días","Al menos 1 año","Al menos 90 días"],"explanation":"El Manual de CDL de Maine (Sección 1.2.5) establece que perderá su CDL por al menos un año por una tercera violación en un cruce a nivel de ferrocarril y carretera dentro de un periodo de tres años (la primera es de 60 días, la segunda es de 120 días)."},"58":{"q":"En Maine, si el privilegio de conducir un vehículo personal de un titular de CDL es revocado, cancelado o suspendido debido a una infracción de alcohol, sustancias controladas o un delito grave, ¿qué le sucede a la CDL?","options":["Ningún efecto, porque ocurrió en un vehículo personal","Pérdida de la CDL por 60 días únicamente","Una descalificación de por vida inmediata en la primera infracción","Pérdida de la CDL por 1 año (de por vida por una segunda infracción de este tipo)"],"explanation":"El Manual de CDL de Maine (Sección 1.2.7), que refleja la Ley de Mejora de la Seguridad de los Transportistas Motorizados (Motor Carrier Safety Improvement Act), establece que si su privilegio de vehículo personal es revocado/cancelado/suspendido por infracciones de alcohol, sustancias controladas o delitos graves, pierde su CDL por 1 año, y de por vida por una segunda infracción de este tipo. No hay una CDL por dificultad económica (hardship) disponible."},"59":{"q":"Según la ley de Maine de 'Cambiar de carril' (Move Over), cuando se aproxima a un vehículo de emergencia o de servicio detenido que muestra luces intermitentes en una carretera de varios carriles, ¿cuál es su PRIMERA acción obligatoria si puede hacerse de manera segura?","options":["Salir del carril contiguo al vehículo detenido y pasar a un carril no contiguo","Detenerse por completo hasta que el vehículo de emergencia abandone el lugar","Tocar la bocina y continuar al límite de velocidad indicado","Orillarse en el acotamiento derecho y esperar a que le hagan señas para pasar"],"explanation":"La ley de 'Cambiar de carril' de Maine (29-A MRSA Sec. 2054(9), y Sec. 2070(8) para vehículos detenidos/averiados) exige que el conductor pase por un carril NO contiguo al vehículo detenido si es posible; solo si cambiar de carril es imposible o inseguro puede pasar a una velocidad reducida, cuidadosa y prudente. Fuente: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070."},"60":{"q":"En una carretera de dos carriles donde es imposible cambiar a un carril no contiguo, la ley de 'Cambiar de carril' de Maine exige que el conductor que pasa junto a un vehículo de emergencia o averiado detenido haga ¿qué?","options":["Detenerse por completo antes de pasar junto al vehículo","Mantener al menos el límite mínimo de velocidad indicado","Pasar a una velocidad cuidadosa y prudente, razonable para pasar de manera segura","Reducir la velocidad a exactamente 20 mph por debajo del límite indicado"],"explanation":"Cuando no es posible o es inseguro cambiar de carril, la 29-A MRSA Sec. 2070(8)(B) (y la Sec. 2054) exige pasar a 'una velocidad cuidadosa y prudente, razonable para pasar junto al vehículo de manera segura'. Maine no especifica una cifra exacta de mph. Fuente: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"61":{"q":"La ley de 'Cambiar de carril' de Maine se amplió en 2023. Además de los vehículos de emergencia y de servicio público autorizados, el deber de cambiar de carril o reducir la velocidad ahora también se aplica al pasar junto a:","options":["Solo patrullas de policía y ambulancias rotuladas","Cualquier vehículo detenido que una persona razonable concluiría que está averiado o que está usando luces intermitentes","Solo grúas y vehículos de mantenimiento de carreteras","Solo vehículos que muestran una bandera roja de advertencia"],"explanation":"La 29-A MRSA Sec. 2070(8), promulgada por la PL 2023 c. 122, extiende el deber de cambiar de carril o reducir la velocidad a cualquier vehículo detenido que una persona razonable concluiría que está averiado o que está usando luces intermitentes para advertir de su presencia. Fuente: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"62":{"q":"¿Cuál es la multa mínima impuesta por infringir el requisito de Maine de cambiar de carril o pasar junto a un vehículo detenido?","options":["$135","$500","$1,000","$275"],"explanation":"La 29-A MRSA Sec. 2070(8) establece que una infracción es una falta de tránsito por la cual debe imponerse una multa no menor de $275. Fuente: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"63":{"q":"Cuando un cruce ferroviario de Maine tiene un aspa de advertencia (cross-buck) sin una línea de alto blanca pintada, un vehículo con materiales peligrosos rotulado o un autobús que está obligado a detenerse debe detenerse dentro de qué distancia del riel más cercano?","options":["No menos de 15 pies y no más de 50 pies","No menos de 5 pies y no más de 25 pies","No menos de 25 pies y no más de 75 pies","No menos de 10 pies y no más de 100 pies"],"explanation":"La 29-A MRSA Sec. 2076(3) exige que los autobuses que transportan pasajeros y los vehículos con materiales peligrosos y cisternas de carga rotulados/marcados se detengan no menos de 15 pies y no más de 50 pies del riel más cercano. El Maine CDL Manual (Sec. 2.15) indica el mismo rango de 15 a 50 pies. Fuente: Maine Revised Statutes Title 29-A Sec. 2076; Maine CDL Manual."},"64":{"q":"¿En cuál de los siguientes cruces ferroviarios NO está obligado a detenerse un autobús de Maine o un vehículo con materiales peligrosos rotulado?","options":["Cualquier cruce ubicado fuera de un distrito comercial","Un cruce con luces rojas intermitentes que no están activadas","Un cruce de vías usadas exclusivamente para maniobras industriales, o uno marcado con un letrero de 'exento' (exempt)","Cualquier cruce en una vía con límite indicado de 45 mph o menos"],"explanation":"La 29-A MRSA Sec. 2076 enumera excepciones al alto obligatorio, incluyendo cruces de tranvías, vías usadas exclusivamente para maniobras industriales, cuando un oficial o señalero indica avanzar, cruces abandonados así marcados, y cruces señalizados con un letrero de 'exento' (exempt). Fuente: Maine Revised Statutes Title 29-A Sec. 2076."},"65":{"q":"La ley de Maine (29-A Sec. 2306) ordena que un operador de autobús escolar que se aproxima a un cruce ferroviario a nivel haga un alto total y luego ¿qué haga antes de cruzar?","options":["Esperar 30 segundos completos sin importar las condiciones","Tocar la bocina dos veces y luego avanzar","Hacer que un pasajero baje y actúe como señalero","Cerciorarse más allá de toda duda razonable de que ningún tren se aproxima por la vía"],"explanation":"La 29-A MRSA Sec. 2306 exige que el operador del autobús escolar haga un alto total (a no más de 50 pies ni menos de 15 pies del riel más cercano) y se cerciore más allá de toda duda razonable de que ningún tren, locomotora o vehículo se aproxima antes de cruzar. Fuente: Maine Revised Statutes Title 29-A Sec. 2306."},"66":{"q":"Un autobús escolar de Maine se detiene en una carretera de dos carriles con sus luces rojas intermitentes encendidas para descargar pasajeros. ¿Qué debe hacer el conductor de un vehículo que se aproxima desde la dirección OPUESTA?","options":["Reducir a 15 mph y pasar con precaución","Detener el vehículo antes de llegar al autobús y no avanzar hasta que el autobús se mueva o haga una señal","Continuar normalmente porque el tránsito en sentido contrario está exento","Detenerse solo si hay niños cruzando la carretera de forma visible"],"explanation":"La 29-A MRSA Sec. 2308(2) exige que el operador de un vehículo que se cruza con O alcanza a un autobús escolar desde cualquier dirección, cuando el autobús está detenido con las luces rojas intermitentes encendidas, se detenga antes de llegar al autobús y no avance hasta que el autobús reanude la marcha o el operador haga una señal. Fuente: Maine Revised Statutes Title 29-A Sec. 2308(2)."},"67":{"q":"Según la ley de autobuses escolares de Maine, ¿en qué tipo de vía un conductor NO necesita detenerse por un autobús escolar que está detenido del otro lado?","options":["Una vía separada por un bordillo u otra barrera física, para un autobús en un carril separado por esa barrera","Cualquier vía con una línea central doble amarilla pintada","Cualquier vía con dos o más carriles en cada dirección","Cualquier vía con un límite indicado de 50 mph o más"],"explanation":"La 29-A MRSA Sec. 2308(3) exime al conductor de detenerse solo cuando la vía está separada por un bordillo u otra barrera física (para un autobús en un carril separado por esa barrera), o en una autopista de acceso limitado donde los peatones no pueden cruzar. Una línea pintada por sí sola NO genera la excepción. Fuente: Maine Revised Statutes Title 29-A Sec. 2308(3)."},"68":{"q":"Maine exige que un operador de autobús escolar active las luces de advertencia intermitentes del autobús al menos a qué distancia antes de detenerse para recoger o descargar pasajeros?","options":["50 pies","200 pies","300 pies","100 pies"],"explanation":"La 29-A MRSA Sec. 2308(1) exige que un operador de autobús escolar active las luces intermitentes al menos 100 pies antes de hacer un alto para recoger o descargar pasajeros, y que las mantenga encendidas hasta que se recojan o descarguen los pasajeros. Fuente: Maine Revised Statutes Title 29-A Sec. 2308(1)."},"69":{"q":"En Maine, pasar ilegalmente junto a un autobús escolar detenido que tiene sus luces rojas intermitentes encendidas se clasifica como ¿qué, y con qué sanción por primera infracción?","options":["Una simple falta de tránsito con una multa de $135","Una violación civil sin multa por una primera infracción","Un delito de Clase E con una multa mínima de $250","Un delito de Clase C con tiempo de cárcel obligatorio"],"explanation":"La 29-A MRSA Sec. 2308(6) convierte una infracción de la subsección 2 en un delito de Clase E castigado con una multa mínima de $250 por una primera infracción, con una suspensión obligatoria de la licencia por 30 días para una 2.ª infracción dentro de 3 años. Fuente: Maine Revised Statutes Title 29-A Sec. 2308(6)."},"70":{"q":"En ausencia de letreros indicados, ¿qué establece la ley de Maine como la velocidad máxima en un distrito comercial o residencial?","options":["20 mph","25 mph","30 mph","35 mph"],"explanation":"La 29-A MRSA Sec. 2074(1) fija máximos predeterminados de 15 mph en una zona escolar, 25 mph en un distrito comercial o residencial o zona urbanizada, y 45 mph en todas las demás vías públicas, cada uno 'a menos que se indique lo contrario'. Fuente: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"71":{"q":"Según los límites de velocidad legales predeterminados de Maine (donde no se indica ningún otro límite), ¿cuál es la velocidad máxima en 'todas las demás vías públicas'?","options":["55 mph","50 mph","40 mph","45 mph"],"explanation":"La 29-A MRSA Sec. 2074(1) fija el máximo predeterminado en 45 mph en todas las demás vías públicas a menos que se indique lo contrario (comercial/residencial es 25 mph; zona escolar es 15 mph). La mayoría de las carreteras numeradas tienen límites indicados más altos. Fuente: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"72":{"q":"¿Cuál es el límite de velocidad máximo en la Maine Turnpike (I-95) según lo establecido por la Maine Turnpike Authority?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Las reglas de la Maine Turnpike Authority fijan la velocidad máxima general en la Turnpike en 70 mph, con límites indicados más bajos en ciertos tramos del sur y del norte. Fuente: Maine Turnpike Authority Policies & Rules."},"73":{"q":"En los tramos de tres carriles de la Maine Turnpike al sur del Mile Marker 44, ¿dónde se permite que circulen los camiones (incluidos los tractocamiones)?","options":["Solo en el único carril más a la derecha","En cualquier carril, incluido el carril izquierdo de rebase","Solo en los dos carriles más a la derecha","Solo en el carril central"],"explanation":"Para mejorar la calidad del aire del sur de Maine, las reglas de la Maine Turnpike Authority restringen a los camiones (incluidos los tractocamiones, excluyendo las camionetas pickup) a los dos carriles más a la derecha en cualquier tramo de la Turnpike al sur del Mile Marker 44 que tenga tres carriles en cada dirección. Fuente: Maine Turnpike Authority Policies & Rules."},"74":{"q":"Si debe detener un CMV sobre o junto a una carretera de un solo sentido o dividida en Maine, el Maine CDL Manual indica colocar sus tres dispositivos de advertencia a qué distancias hacia el tránsito que se aproxima?","options":["10 pies, 50 pies y 150 pies","10 pies, 100 pies y 200 pies","25 pies, 100 pies y 300 pies","50 pies, 100 pies y 500 pies"],"explanation":"El Maine CDL Manual (Sec. 2.5.1) indica que, cuando se detiene sobre o junto a una carretera de un solo sentido o dividida, los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima. Fuente: Maine CDL Manual, Section 2."},"75":{"q":"En una carretera de Maine de dos carriles (de dos sentidos sin dividir), ¿cómo deben colocarse los tres dispositivos de advertencia requeridos cuando un CMV está detenido?","options":["10 pies, 100 pies y 200 pies, todos detrás del vehículo","A 50 pies, 200 pies y 300 pies solo detrás del vehículo","Un dispositivo dentro de 10 pies y dos dispositivos solo 500 pies detrás","Dentro de 10 pies del vehículo, y 100 pies adelante y 100 pies detrás del vehículo"],"explanation":"El Maine CDL Manual (Sec. 2.5.2) indica colocar un dispositivo dentro de 10 pies del frente o la parte trasera para marcar el vehículo, más uno 100 pies detrás y uno 100 pies adelante, en el acotamiento o en el carril ocupado. Fuente: Maine CDL Manual, Section 2."},"76":{"q":"Después de detener un CMV en una vía de Maine, ¿dentro de cuántos minutos debe tener colocados sus dispositivos de advertencia de emergencia?","options":["10 minutos","5 minutos","15 minutos","30 minutos"],"explanation":"El Maine CDL Manual (Sec. 2.5.1) indica que si debe detenerse en una carretera o acotamiento, debe colocar los dispositivos de advertencia de emergencia dentro de diez minutos. Fuente: Maine CDL Manual, Section 2."},"77":{"q":"Si un CMV se detiene justo después de una colina o curva en Maine, el Maine CDL Manual indica que el dispositivo de advertencia trasero debe reubicarse de modo que:","options":["Se coloque exactamente a 200 pies del vehículo sin importar la curva","Se retire porque las luces de emergencia son suficientes","Dé advertencia a los conductores carretera atrás, de modo que el vehículo sea visible dentro de 500 pies","Se coloque en la cima de la colina exactamente 50 pies adelante"],"explanation":"El Maine CDL Manual (Sec. 2.5.2) indica que si una colina o curva obstruye la línea de visión, mueva el triángulo trasero carretera atrás para que se brinde advertencia y otros conductores puedan ver el vehículo dentro de 500 pies. Fuente: Maine CDL Manual, Section 2."},"78":{"q":"En Maine, una carga que excede cuál dimensión generalmente requiere un permiso de sobredimensión (overlimit) del Bureau of Motor Vehicles / MaineDOT?","options":["Un ancho mayor de 10 feet 0 inches o una altura mayor de 15 feet 0 inches","Un ancho mayor de 8 feet 6 inches o una altura mayor de 13 feet 6 inches","Un ancho mayor de 8 feet 0 inches o una altura mayor de 12 feet 0 inches","Un ancho mayor de 9 feet 0 inches o una altura mayor de 14 feet 6 inches"],"explanation":"Maine sigue los límites legales estándar de 8 feet 6 inches de ancho y 13 feet 6 inches de altura; las cargas que exceden estos requieren un permiso de sobredimensión (overlimit) emitido a través del programa de permisos de sobredimensión del Maine BMV/MaineDOT. Fuente: Maine BMV Overlimit Permits / MaineDOT."},"79":{"q":"¿Qué agencia de Maine emite las licencias de conducir comercial (CDL) y administra los exámenes de CDL?","options":["El Maine Bureau of Motor Vehicles (BMV), dentro de la oficina del Secretary of State","El Maine Department of Transportation (MaineDOT)","La Federal Motor Carrier Safety Administration (FMCSA)","La Maine State Police Commercial Vehicle Enforcement Unit"],"explanation":"El Maine Bureau of Motor Vehicles (BMV), una división de la oficina del Secretary of State, emite todas las CDL de Maine y administra los exámenes de conocimientos y habilidades. MaineDOT se encarga de las carreteras y los permisos de sobredimensión/sobrepeso, no de las licencias. Fuente: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv)."},"80":{"q":"En el formulario de autocertificación de CDL de Maine (MVE-64C), ¿entre cuántas categorías de tipo de operación puede elegir un solicitante?","options":["Cuatro","Dos","Tres","Seis"],"explanation":"Maine exige la autocertificación en una de CUATRO categorías: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate o Excepted Intrastate. Fuente: Maine BMV CDL Medical Self-Certification Form MVE-64C; 49 CFR 383.71."},"81":{"q":"Un conductor de Maine se autocertifica como 'Non-Excepted Interstate'. ¿Qué documento adicional debe tener el BMV en archivo?","options":["Un Medical Examiner's Certificate (tarjeta médica) federal del DOT","Nada más allá del formulario de autocertificación","Una carta de autorización del empleador notariada","Un permiso de sobredimensión/sobrepeso del Maine DOT"],"explanation":"Los conductores que se autocertifican como Non-Excepted Interstate deben proporcionar al BMV un Medical Examiner's Certificate federal válido (MCSA-5876 / tarjeta médica). Los conductores exceptuados (excepted) no están obligados a presentar uno. Fuente: Maine BMV CDL self-certification guidance; 49 CFR 383.71."},"82":{"q":"¿Quién está calificado para realizar el examen físico del DOT que produce el Medical Examiner's Certificate de un solicitante de CDL en Maine?","options":["Un examinador médico que figure en el FMCSA National Registry of Certified Medical Examiners","Cualquier médico con licencia que elija el solicitante","Un examinador del BMV en el sitio de pruebas","El optometrista habitual del solicitante"],"explanation":"El examen físico del DOT debe ser realizado por un examinador médico que figure en el FMCSA National Registry of Certified Medical Examiners. Fuente: Maine BMV CDL medical requirements; 49 CFR 391.43."},"83":{"q":"¿Cuál es el periodo máximo de tiempo durante el cual puede ser válido un Medical Examiner's Certificate del DOT para un titular de CDL de Maine?","options":["2 años","1 año","3 años","5 años"],"explanation":"Un Medical Examiner's Certificate es válido por un máximo de 2 años; un examinador puede certificar a un conductor por un periodo más corto si una condición requiere monitoreo. Una nueva tarjeta debe estar en archivo antes de que venza la anterior. Fuente: Maine BMV CDL medical requirements; 49 CFR 391.45."},"84":{"q":"¿Cómo puede un titular de CDL de Maine presentar un formulario de autocertificación o un certificado médico a la CDL Compliance Unit del BMV?","options":["Por fax, correo electrónico o correo postal a la BMV CDL Compliance Unit","Solo en persona en la oficina central de Augusta","Solo subiéndolo al FMCSA Training Provider Registry","Solo a través del empleador o transportista del conductor"],"explanation":"Maine acepta la autocertificación MVE-64C y el certificado médico por fax, por correo electrónico (PDF/Word) a la CDL Compliance Unit, o por correo postal a la BMV CDL Compliance Unit en Augusta. Fuente: Maine BMV CDL Compliance Unit submission instructions."},"85":{"q":"Antes de que se pueda emitir a una persona un Commercial Learner's Permit (CLP) de Maine, ¿qué examen de conocimientos debe aprobarse como mínimo?","options":["El examen de General Knowledge","Solo el examen de la certificación de Air Brakes","El examen de Hazardous Materials","El examen de habilidades de inspección previaje (pre-trip)"],"explanation":"El examen de General Knowledge (más cualquier examen de certificación que el solicitante busque) debe aprobarse para obtener un CLP. El Maine BMV publica el manual oficial de CDL en el que se basan estos exámenes. Fuente: Maine CDL Manual; Maine BMV CDL Exam page."},"86":{"q":"¿Cuál es la puntuación mínima para aprobar cada examen de conocimientos de CDL de Maine?","options":["80%","70%","75%","90%"],"explanation":"Un conductor debe responder correctamente al menos el 80% de las preguntas de cada examen de conocimientos para aprobar. Fuente: Maine CDL Manual; 49 CFR 383.135."},"87":{"q":"El examen de habilidades de CDL de Maine consta de cuáles tres partes, ¿en qué orden?","options":["Inspección previaje del vehículo, control básico del vehículo y conducción en carretera","Conocimientos por escrito, examen de visión y conducción en carretera","Verificación de frenos de aire, retroceso y un examen escrito de certificación","Control básico del vehículo, estacionamiento en paralelo y una entrevista de hazmat"],"explanation":"El examen de habilidades de CDL tiene tres partes administradas en este orden: la inspección previaje del vehículo, el examen de control básico del vehículo y el examen de conducción en carretera. Fuente: Maine CDL Manual; 49 CFR 383.113."},"88":{"q":"¿Qué componente del examen de habilidades requiere que un solicitante de Maine realice maniobras como el retroceso en línea recta, el retroceso desplazado (offset) y el estacionamiento en muelle de callejón (alley docking)?","options":["El examen de control básico del vehículo","La inspección previaje del vehículo","El examen de conducción en carretera","El examen de General Knowledge"],"explanation":"Las maniobras de retroceso como el retroceso en línea recta, el retroceso desplazado (offset) y el estacionamiento en muelle de callejón (alley docking) se evalúan en la parte de control básico del vehículo del examen de habilidades. Fuente: Maine CDL Manual; 49 CFR 383.113."},"89":{"q":"Un solicitante de CDL Clase A por primera vez en Maine debe completar el Entry-Level Driver Training (ELDT) de un proveedor que esté:","options":["Incluido en el FMCSA Training Provider Registry (TPR)","Aprobado únicamente por el grupo de examinadores del Maine BMV","Certificado por el sistema local de community colleges","Registrado en la oficina de permisos de MaineDOT"],"explanation":"El ELDT debe obtenerse de un proveedor incluido en el FMCSA Training Provider Registry; el proveedor reporta la finalización electrónicamente a la FMCSA. Fuente: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"90":{"q":"¿Para cuál de los siguientes exige Maine el ELDT antes de hacer el examen?","options":["Una CDL Clase A o B por primera vez, o una certificación P, S o H por primera vez","Cada renovación de CDL sin importar la clase","Solo los solicitantes de la certificación de Hazardous Materials (H)","Solo los conductores que ascienden de Clase B a Clase A"],"explanation":"El ELDT se requiere para obtener una CDL Clase A o Clase B por primera vez, ascender a una clase superior, u obtener una certificación de pasajeros (P), autobús escolar (S) o materiales peligrosos (H) por primera vez. Fuente: Maine BMV ELDT page; 49 CFR Part 380."},"91":{"q":"¿Cuándo debe un solicitante de CDL de Maine completar el ELDT requerido?","options":["Antes de hacer el examen de conocimientos o de habilidades correspondiente","Después de aprobar el examen de habilidades pero antes de que se imprima la licencia","Dentro de los 30 días posteriores a la emisión de la CDL","Solo después de que venza el periodo de espera de 14 días del CLP"],"explanation":"La teoría del ELDT debe completarse antes del examen de conocimientos para una certificación H, y el entrenamiento al volante antes del examen de habilidades para la Clase A/B y las certificaciones P/S. El entrenamiento debe preceder al examen correspondiente. Fuente: Maine BMV ELDT page; 49 CFR Part 380 Subpart F."},"92":{"q":"Después de recibir un CLP, ¿cuánto tiempo debe conservarlo un solicitante de Maine antes de poder hacer el examen de habilidades de CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Un titular de CLP debe esperar un mínimo de 14 días después de que se emite el permiso antes de hacer el examen de habilidades. Fuente: Maine BMV CDL pages; 49 CFR 383.25."},"93":{"q":"Al operar bajo un CLP de Maine, el titular del permiso debe ir acompañado de:","options":["Un titular de CDL, válida para la clase y certificaciones de ese vehículo, sentado junto al conductor","Cualquier conductor con licencia de 21 años o más","Solo un examinador del BMV","Nadie, siempre que el vehículo esté vacío"],"explanation":"Un titular de CLP puede operar un vehículo motorizado comercial solo cuando va acompañado de una persona que tiene una CDL válida para esa clase de vehículo, sentada en el asiento delantero junto al titular del permiso. Fuente: Maine CDL Manual; 49 CFR 383.25."},"94":{"q":"Para la mayoría de los titulares de CDL de Maine menores de 65 años, ¿con qué frecuencia debe renovarse la CDL?","options":["Cada 5 años","Cada 4 años","Cada 6 años","Cada 8 años"],"explanation":"Una CDL de Maine se emite por un ciclo de 5 años para los titulares menores de 65 años. (Los titulares de 65 años o más renuevan en un ciclo de 4 años). Fuente: Maine BMV CDL renewal information."},"95":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Maine para conducir solo intraestatal (dentro de Maine)?","options":["18","21","19","16"],"explanation":"Un solicitante debe tener al menos 18 años para obtener una CDL de Maine para conducción intraestatal; se requieren 21 años para conducción interestatal, transportar materiales peligrosos o llevar pasajeros. Fuente: Maine CDL Manual; Maine BMV CDL pages."},"96":{"q":"¿Qué conjunto de documentos necesitaría típicamente un solicitante de Maine para establecer identidad y elegibilidad al solicitar una CDL?","options":["Comprobante de identidad, presencia legal en EE. UU., número de Seguro Social y residencia en Maine","Solo una licencia de conducir no comercial de Maine vigente","Un pasaporte más un permiso de sobredimensión de MaineDOT","Solo una carta del empleador y un registro del vehículo"],"explanation":"Los solicitantes deben documentar identidad, presencia legal en EE. UU., un número de Seguro Social y residencia en Maine, además de cumplir con los requisitos médicos y de autocertificación. Fuente: Maine BMV CDL application requirements."},"97":{"q":"Si un conductor de Maine deja que el certificado médico requerido caduque de modo que ya no esté en archivo con el BMV, ¿cuál es la consecuencia probable?","options":["El privilegio de CDL del conductor se degrada (se retiran los privilegios comerciales) hasta que se presente un certificado válido","Nada cambia hasta la fecha de renovación normal de la CDL","La CDL se revoca permanentemente sin posibilidad de reinstalación","Solo se emite una advertencia por escrito sin efecto sobre la licencia"],"explanation":"Si el certificado médico de un conductor no exceptuado (non-excepted) vence y no se actualiza con el BMV, el estado debe degradar la CDL retirando los privilegios de conducción comercial hasta que se presente un certificado vigente. Fuente: Maine BMV CDL Compliance guidance; 49 CFR 383.73."}},"hi":{"0":{"q":"मेन की किसी सार्वजनिक सड़क (public way) पर, बिना किसी विशेष परमिट के किसी वाहन की अधिकतम कुल चौड़ाई कितनी हो सकती है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"29-A M.R.S. §2380 के अंतर्गत, 102 inches (8'6\") से अधिक कुल चौड़ाई वाले वाहन को बिना परमिट के मेन की किसी सार्वजनिक सड़क या पुल पर नहीं चलाया जा सकता। स्रोत: Maine Revised Statutes Title 29-A, §2380."},"1":{"q":"मेन के राजमार्गों पर बिना ओवरलिमिट परमिट के किसी वाहन की अधिकतम कानूनी संरचनात्मक ऊंचाई कितनी हो सकती है?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"29-A M.R.S. §2380 ऐसे वाहन को चलाने पर रोक लगाता है जिसका कोई स्थायी या अस्थायी संरचनात्मक भाग 13 feet 6 inches से अधिक ऊंचा हो। एक गैर-घटाने योग्य (nonreducible) भार उससे 6 inches ऊपर तक जा सकता है, परंतु संरचनात्मक सीमा 13'6\" है। स्रोत: Maine Revised Statutes Title 29-A, §2380."},"2":{"q":"मेन में, कुछ साइड उपांग (जैसे शीशे और मड फ्लैप) चौड़ाई के माप से तभी बाहर रखे जाते हैं जब वे वाहन के किनारे से कितने से अधिक बाहर न निकलें?","options":["2 inches","3 inches","6 inches","9 inches"],"explanation":"29-A M.R.S. §2380 निर्दिष्ट उपांगों (शीशे, दरवाजे के कब्जे, रेन गटर, मड फ्लैप आदि) को 102-inch चौड़ाई के माप से बाहर रखता है, बशर्ते वे वाहन के किनारे से 3 inches से अधिक बाहर न निकलें। स्रोत: Maine Revised Statutes Title 29-A, §2380."},"3":{"q":"मानक भार सीमाओं के तहत मेन के सामान्य (गैर-Interstate) राजमार्गों पर पांच या अधिक एक्सल वाले संयोजन वाहन का अधिकतम सकल भार (gross weight) कितना होता है?","options":["69,000 pounds","73,280 pounds","80,000 pounds","90,000 pounds"],"explanation":"29-A M.R.S. §2353 के अंतर्गत, पांच या अधिक एक्सल वाले संयोजन के लिए अधिकतम सकल भार 80,000 pounds है (एक 2-एक्सल वाहन 34,000 तक, 3-एक्सल 54,000 तक, और 4-एक्सल 69,000 तक सीमित है)। स्रोत: Maine Revised Statutes Title 29-A, §2353."},"4":{"q":"§2353 में मेन की मानक (गैर-Interstate) भार सीमाओं के तहत, एक एकल एक्सल पर अनुमत अधिकतम भार कितना है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"29-A M.R.S. §2353 मेन की सामान्य राजमार्ग प्रणाली पर एकल-एक्सल सीमा 22,400 pounds निर्धारित करता है, जो 20,000-pound के संघीय Interstate एकल-एक्सल आंकड़े से अधिक है। स्रोत: Maine Revised Statutes Title 29-A, §2353."},"5":{"q":"मेन की सामान्य राजमार्ग प्रणाली (§2353) पर, एक टैंडम-एक्सल यूनिट पर अनुमत अधिकतम भार कितना है?","options":["34,000 pounds","36,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"29-A M.R.S. §2353 मेन की सामान्य सड़कों पर एक टैंडम-एक्सल यूनिट पर 38,000 pounds की अनुमति देता है, जो §2355 के तहत Interstate Highway System पर लागू होने वाली 34,000-pound टैंडम सीमा से अधिक है। स्रोत: Maine Revised Statutes Title 29-A, §2353."},"6":{"q":"मेन में Interstate Highway System पर, एक टैंडम-एक्सल यूनिट पर अनुमत अधिकतम भार कितना है?","options":["32,000 pounds","34,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"29-A M.R.S. §2355 Interstate Highway System पर एक टैंडम-एक्सल यूनिट को 34,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। मेन की सामान्य सड़कें §2353 के तहत 38,000-pound की अधिक टैंडम सीमा की अनुमति देती हैं। स्रोत: Maine Revised Statutes Title 29-A, §2355."},"7":{"q":"मेन की Interstate प्रणाली पर, 73,280 pounds से अधिक सकल वाहन भार (gross vehicle weight) वाला वाहन किस एकल-एक्सल भार तक सीमित होता है?","options":["18,000 pounds","20,000 pounds","22,000 pounds","22,400 pounds"],"explanation":"29-A M.R.S. §2355 Interstate Highway System पर जब GVW 73,280 pounds से अधिक हो तो एकल एक्सल को 20,000 pounds तक सीमित करता है (और जब GVW 73,280 या उससे कम हो तो 22,000 pounds तक)। स्रोत: Maine Revised Statutes Title 29-A, §2355."},"8":{"q":"मेन की Interstate प्रणाली पर, 73,280 pounds या उससे कम सकल वाहन भार वाला वाहन एक एकल एक्सल पर अधिकतम कितना भार ले जा सकता है?","options":["20,000 pounds","22,000 pounds","22,400 pounds","24,200 pounds"],"explanation":"29-A M.R.S. §2355 Interstate पर जब GVW 73,280 pounds या उससे कम हो तो एकल एक्सल को 22,000 pounds तक की अनुमति देता है, और जब GVW 73,280 से अधिक हो जाए तो यह घटकर 20,000 pounds हो जाता है। स्रोत: Maine Revised Statutes Title 29-A, §2355."},"9":{"q":"मेन की Interstate प्रणाली पर प्रयुक्त संघीय ब्रिज फॉर्मूला W = 500(LN/(N-1) + 12N + 36) में, चर \"L\" किसका प्रतिनिधित्व करता है?","options":["भार की लंबाई feet में","किसी समूह के सबसे बाहरी एक्सलों के बीच की दूरी feet में","प्रति एक्सल कानूनी भार हजार pounds में","वाहन पर लदे एक्सलों की संख्या"],"explanation":"29-A M.R.S. §2355 द्वारा लागू संघीय Bridge Formula B में, W एक्सलों के समूह पर अनुमत सकल भार है, N समूह में एक्सलों की संख्या है, और L उस समूह के सबसे बाहरी (बाहरी) एक्सलों के बीच की दूरी feet में है। स्रोत: Maine Revised Statutes Title 29-A, §2355 (federal bridge formula)."},"10":{"q":"मेन में एक छह-एक्सल संयोजन (3-एक्सल ट्रैक्टर के साथ तीन-एक्सल वाला सेमीट्रेलर) सभी शर्तें पूरी होने पर अधिकतम कितने सकल भार तक पहुंच सकता है?","options":["80,000 pounds","90,000 pounds","100,000 pounds","120,000 pounds"],"explanation":"29-A M.R.S. §2354 एक छह-एक्सल संयोजन (3-एक्सल ट्रक ट्रैक्टर के साथ तीन-एक्सल सेमीट्रेलर) को स्पेसिंग और अन्य शर्तें पूरी होने पर 100,000 pounds तक की अनुमति देता है; आधार सीमा 90,000 pounds है। स्रोत: Maine Revised Statutes Title 29-A, §2354."},"11":{"q":"मेन के छह-एक्सल 100,000-pound संयोजन के लिए, सबसे बाहरी एक्सलों के बीच की दूरी (स्टीयरिंग एक्सल को छोड़कर) कम से कम कितने feet होनी चाहिए?","options":["30 feet","32 feet","36 feet","40 feet"],"explanation":"29-A M.R.S. §2354 के अनुसार सबसे बाहरी एक्सलों के बीच की दूरी (स्टीयरिंग एक्सल को छोड़कर) 36 feet से कम नहीं होनी चाहिए; जितने feet यह दूरी 36 feet से कम होती है, हर foot के लिए अधिकतम सकल भार 2,000 pounds घटा दिया जाता है। स्रोत: Maine Revised Statutes Title 29-A, §2354."},"12":{"q":"मेन के छह-एक्सल भार कानून के तहत, सबसे बाहरी एक्सलों की स्पेसिंग आवश्यक न्यूनतम से जितने feet कम होती है, उसके प्रत्येक foot के लिए अधिकतम सकल भार कितना घटा दिया जाता है?","options":["1,000 pounds प्रति foot","1,500 pounds प्रति foot","2,000 pounds प्रति foot","2,500 pounds प्रति foot"],"explanation":"29-A M.R.S. §2354 एक छह-एक्सल संयोजन के अधिकतम अनुमत सकल भार को, सबसे बाहरी एक्सलों की दूरी आवश्यक 36 feet से जितने feet कम होती है, प्रत्येक foot के लिए 2,000 pounds घटा देता है। स्रोत: Maine Revised Statutes Title 29-A, §2354."},"13":{"q":"मेन का भार-सहनशीलता (weight-tolerance) कानून (§2357) योग्य भारों (जैसे लकड़ी के उत्पाद, सड़क नमक, बजरी) को अधिकतम सकल भार से कितना अधिक होने की अनुमति देता है?","options":["अधिकतम से 5% तक अधिक","10% तक (अधिकतम का 110%)","अधिकतम से 15% तक अधिक","अधिकतम से 2,000 pounds तक अधिक"],"explanation":"29-A M.R.S. §2357 यह प्रावधान करता है कि एक योग्य वाहन उल्लंघन में नहीं माना जाएगा यदि उसका सकल वाहन भार §2353 में दिए गए अधिकतम सकल भार के 110% (10% अधिक) से अधिक न हो, जैसे लकड़ी के उत्पाद, बजरी, सड़क नमक और इसी प्रकार की थोक सामग्रियों के लिए। स्रोत: Maine Revised Statutes Title 29-A, §2357."},"14":{"q":"कुछ वस्तुओं के लिए मेन की 10% भार सहनशीलता (§2357) किन सड़कों पर लागू होती है?","options":["केवल Interstate Highway System पर","Interstate Highway System को छोड़कर मेन की सभी सड़कों पर","केवल Maine Turnpike पर","Interstate सहित मेन की सभी सड़कों पर"],"explanation":"29-A M.R.S. §2357 स्पष्ट रूप से कहता है कि भार सहनशीलता Interstate Highway System पर चलने वाले वाहन पर लागू नहीं होती; यह मेन की सामान्य (गैर-Interstate) सड़कों पर उपलब्ध है। स्रोत: Maine Revised Statutes Title 29-A, §2357."},"15":{"q":"मेन में Commissioner of Transportation की सलाह पर कार्य करते हुए राज्यव्यापी ओवरलिमिट (अधिक आकार/अधिक भार) आवागमन परमिट कौन सा प्राधिकरण जारी करता है?","options":["Secretary of State","Maine State Police","Maine Turnpike Authority","Public Utilities Commission"],"explanation":"29-A M.R.S. §2382 के अंतर्गत, Secretary of State (Bureau of Motor Vehicles के माध्यम से), Commissioner of Transportation के दिशानिर्देशों और सलाह पर कार्य करते हुए, ओवरलिमिट आवागमन परमिट जारी करते हैं; काउंटी और नगरपालिकाएं अपनी स्वयं की सड़कों पर यात्रा की अनुमति दे सकती हैं। स्रोत: Maine Revised Statutes Title 29-A, §2382."},"16":{"q":"मेन में, कानूनी आयाम या भार सीमाओं से अधिक किस प्रकार के भार को ले जाने के लिए ओवरलिमिट (अधिक आकार/अधिक भार) परमिट आवश्यक होता है?","options":["कोई भी भार, चाहे उसे अलग किया जा सके या नहीं","केवल विभाज्य भार जिन्हें कानूनी इकाइयों में बांटा जा सके","एक अविभाज्य वस्तु जिसे कानूनी सीमाओं तक नहीं घटाया जा सकता","केवल Interstate Highway System पर ले जाए जाने वाले भार"],"explanation":"29-A M.R.S. §2381 और §2382 अविभाज्य वस्तुओं (जिन्हें उचित रूप से कानूनी लंबाई, चौड़ाई, ऊंचाई या भार तक नहीं घटाया जा सकता) के लिए परमिट को अधिकृत करते हैं। विभाज्य भारों को परमिट देने के बजाय कानूनी सीमाओं तक तोड़ा जाना चाहिए। स्रोत: Maine Revised Statutes Title 29-A, §§2381–2382."},"17":{"q":"ट्रकों, ट्रैक्टरों और सेमीट्रेलरों के लिए Maine Secretary of State द्वारा जारी किए जा सकने वाले दीर्घकालिक ओवरलिमिट परमिट की अधिकतम अवधि कितनी है?","options":["30 days","6 months","One year","Two years"],"explanation":"29-A M.R.S. §2382 Secretary of State को ट्रकों, ट्रक ट्रैक्टरों, सेमीट्रेलरों, हैवी-ड्यूटी रिकवरी वाहनों और Class A विशेष मोबाइल उपकरण के लिए एक वर्ष तक मान्य परमिट जारी करने की अनुमति देता है; अन्यथा एकल-यात्रा (single-trip) परमिट जारी किए जाते हैं। स्रोत: Maine Revised Statutes Title 29-A, §2382."},"18":{"q":"जब मेन का 53-foot सेमीट्रेलर राजमार्गों के राष्ट्रीय नेटवर्क से बाहर चलता है, तो वाहन और भार की कुल लंबाई किस कुल लंबाई से अधिक नहीं हो सकती?","options":["65 feet","69 feet","74 feet","80 feet"],"explanation":"29-A M.R.S. §2390 48 feet से अधिक परंतु 53 feet से अधिक न होने वाले सेमीट्रेलर की अनुमति देता है (किंगपिन-से-रियर-एक्सल दूरी 43 feet से अधिक न हो), परंतु राष्ट्रीय नेटवर्क से बाहर चलते समय कुल लंबाई 74 feet से अधिक नहीं हो सकती। Interstate Highway System पर कुल लंबाई सीमा लागू नहीं होती। स्रोत: Maine Revised Statutes Title 29-A, §2390."},"19":{"q":"मेन के कानून के तहत, 26,001 pounds या उससे अधिक सकल संयोजन भार रेटिंग (GCWR) वाले किसी भी वाहन संयोजन को चलाने के लिए, जहां खींचा जाने वाला वाहन 10,000 pounds GVWR से अधिक हो, किस श्रेणी के CDL की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class D"],"explanation":"मेन Class A को 26,001 या अधिक pounds की GCWR वाले किसी भी वाहन संयोजन के रूप में परिभाषित करता है, बशर्ते खींचे जाने वाले वाहन का GVWR/सकल भार 10,000 pounds से अधिक हो। स्रोत: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"20":{"q":"एक मेन ड्राइवर 30,000 pounds सकल वाहन भार रेटिंग वाला एक एकल सीधा ट्रक (straight truck) चलाता है और कोई ट्रेलर नहीं खींचता। इसके लिए किस CDL श्रेणी की आवश्यकता है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"मेन का Class B 26,001 या अधिक pounds की GVWR वाले किसी भी एकल वाहन को, या ऐसे वाहन को जो 10,000 pounds से अधिक न होने वाली इकाई खींचता हो, कवर करता है। 30,000-pound की एकल इकाई Class B है। स्रोत: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"21":{"q":"मेन में, एक वाहन जो Class A या Class B भार परिभाषाओं को पूरा नहीं करता परंतु 16 या अधिक यात्रियों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किया गया है, या प्लैकार्ड किए गए खतरनाक पदार्थ ले जाता है, किस CDL श्रेणी में आता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"मेन का Class C कोई भी एकल या संयोजन वाहन है जो Class A/B को पूरा नहीं करता और जो 16 या अधिक यात्रियों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लैकार्ड किए गए खतरनाक पदार्थ ले जाता है। स्रोत: Maine CDL Manual, 'Definitions of Classes' and Figure 1.1; 29-A MRSA §1253."},"22":{"q":"Maine CDL Manual के अनुसार, जब भार को संघीय DOT नियमों के तहत प्लैकार्ड किया जाना आवश्यक हो, तो खतरनाक पदार्थ ले जाने वाले वाहनों को चलाने के लिए किस एंडोर्समेंट की आवश्यकता होती है?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"मेन उन वाहनों के संचालन के लिए H endorsement का उपयोग करता है जो खतरनाक पदार्थ ले जाते हैं जब संघीय DOT नियम द्वारा प्लैकार्ड किया जाना आवश्यक हो। X endorsement टैंक (N) और हैज़मैट (H) को जोड़ता है। स्रोत: Maine CDL Manual, 'Endorsements.'"},"23":{"q":"मेन के CDL पर, 'X' endorsement क्या अधिकृत करता है?","options":["केवल टैंक वाहनों का संचालन","खतरनाक पदार्थ ले जाने वाले टैंक वाहनों का संचालन (N और H को जोड़ता है)","डबल और ट्रिपल ट्रेलरों का संचालन","15 से अधिक यात्रियों वाली पैसेंजर बसों का संचालन"],"explanation":"मेन का X endorsement खतरनाक पदार्थ ले जाने वाले टैंक वाहनों के संचालन के लिए है, जो N (टैंक) और H (हैज़मैट) एंडोर्समेंट को एक में जोड़ता है। स्रोत: Maine CDL Manual, 'Endorsements.'"},"24":{"q":"Maine CDL Manual 'T' (डबल/ट्रिपल) endorsement के संबंध में एक विशिष्ट प्रतिबंध का उल्लेख करता है। मेन के लिए कौन सा कथन सही है?","options":["डबल और ट्रिपल दोनों ट्रेलर पूरे राज्य में स्वतंत्र रूप से चलाए जा सकते हैं","ट्रिपल ट्रेलर मेन में अनुमत नहीं हैं","T endorsement टैंक वाहनों को भी अधिकृत करता है","डबल ट्रेलरों के लिए एक अलग पैसेंजर परीक्षा आवश्यक है"],"explanation":"Maine CDL Manual T endorsement को डबल/ट्रिपल ट्रेलरों के लिए 'where allowed by law' के रूप में वर्णित करता है और स्पष्ट रूप से कहता है कि ट्रिपल ट्रेलर मेन में अनुमत नहीं हैं। स्रोत: Maine CDL Manual, 'Endorsements.'"},"25":{"q":"Maine CDL Manual के अनुसार, किसी स्थायी रूप से लगे कार्गो टैंक में तरल या तरल गैस ले जाने के लिए N (टैंक वाहन) endorsement की आवश्यकता तब होती है जब टैंक की न्यूनतम क्षमता कितनी रेटेड हो?","options":["100 gallons या अधिक","119 gallons या अधिक","1,000 gallons या अधिक","450 gallons या अधिक"],"explanation":"मेन में 119 gallons या अधिक रेटेड स्थायी रूप से लगे कार्गो टैंक में, या 1,000 gallons या अधिक रेटेड पोर्टेबल टैंक में तरल या तरल गैस ले जाने के लिए टैंकर (N) परीक्षा/endorsement आवश्यक है। स्रोत: Maine CDL Manual, '1.1.1 Knowledge Tests' and tank vehicle section."},"26":{"q":"मेन में, किस endorsement के लिए सफलतापूर्वक योग्य होने पर बिना किसी अतिरिक्त शुल्क या आगे की परीक्षा के स्वतः ही 'P' (पैसेंजर) endorsement भी मिल जाता है?","options":["H (Hazardous Materials)","N (Tank Vehicle)","S (School Bus)","T (Doubles/Triples)"],"explanation":"Maine CDL Manual में कहा गया है कि S (स्कूल बस) endorsement के लिए सफल योग्यता पर बिना किसी अतिरिक्त शुल्क या आगे की परीक्षा के P (पैसेंजर) endorsement भी मिल जाता है। स्रोत: Maine CDL Manual, 'Endorsements.'"},"27":{"q":"Maine CDL Manual के अनुसार, कौन से एंडोर्समेंट केवल नॉलेज (लिखित) परीक्षा पास करने पर, बिना किसी अलग स्किल्स परीक्षा की आवश्यकता के, प्रदान किए जाते हैं?","options":["P और S","N, H, X, और T","केवल H","सभी एंडोर्समेंट के लिए स्किल्स परीक्षा आवश्यक है"],"explanation":"Maine CDL Manual में कहा गया है कि N, H, X, और T एंडोर्समेंट CDL धारक को केवल नॉलेज परीक्षा के सफल समापन पर प्रदान किए जाते हैं; P और S के लिए स्किल्स परीक्षण सहित पूरी परीक्षा आवश्यक है। स्रोत: Maine CDL Manual, 'Endorsements.'"},"28":{"q":"मेन एक प्रकार के स्कूल बस संचालन के लिए '3' endorsement को मान्यता देता है जिसके लिए ड्राइवर को CDL रखने की आवश्यकता नहीं होती। वह बस कितने यात्रियों को ले जाने के लिए डिज़ाइन की गई होती है?","options":["ड्राइवर सहित 16 या अधिक यात्री","ड्राइवर सहित 15 या उससे कम यात्री","ठीक 24 यात्री","ड्राइवर को छोड़कर 15 से अधिक यात्री"],"explanation":"Maine CDL Manual एक '3' endorsement का वर्णन करता है जो 15 या उससे कम यात्रियों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन की गई स्कूल बस के लिए है; इसे एक गैर-वाणिज्यिक लाइसेंस पर लगाया जा सकता है और इसके लिए CDL की आवश्यकता नहीं होती। स्रोत: Maine CDL Manual, '\"3\" endorsement.'"},"29":{"q":"मेन के CDL नियमों के तहत, राज्य के भीतर वाणिज्य (केवल मेन के भीतर / intrastate commerce) में एक वाणिज्यिक मोटर वाहन चलाने के लिए न्यूनतम आयु क्या है?","options":["16 years","18 years","21 years","19 years"],"explanation":"मेन में intrastate CDL के लिए न्यूनतम आयु 18 है। (Maine CDL Manual का पुराना पाठ कुछ intrastate संचालन के लिए आयु 16 का संदर्भ देता है, परंतु BMV intrastate CDL संचालन के लिए 18 की संघीय न्यूनतम सीमा लागू करता है।) स्रोत: Maine BMV / FMCSA 49 CFR 391.11; Maine CDL Manual age provisions."},"30":{"q":"मेन में अंतरराज्यीय वाणिज्य (राज्य की सीमाएं पार करना / interstate commerce) के लिए मान्य CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years","19 years","21 years","25 years"],"explanation":"interstate commerce में CMV चलाने, खतरनाक पदार्थ ले जाने, या पैसेंजर बस चलाने के लिए ड्राइवर की आयु कम से कम 21 वर्ष होनी चाहिए। स्रोत: Maine CDL Manual age provisions; FMCSA 49 CFR 391.11."},"31":{"q":"29-A MRSA §1304(4-A) के अनुसार, एक मेन कमर्शियल लर्नर्स परमिट (CLP) धारक परमिट के प्रारंभिक जारी होने के बाद किस अवधि के दौरान CDL स्किल्स परीक्षा देने के योग्य नहीं होता?","options":["पहले 7 days","पहले 14 days","पहले 30 days","पहले 60 days"],"explanation":"मेन का कानून प्रावधान करता है कि एक CLP धारक CLP के प्रारंभिक जारी होने के बाद पहले 14 days में CDL स्किल्स परीक्षा देने के योग्य नहीं होता, जो संघीय आवश्यकता के अनुरूप है। स्रोत: 29-A MRSA §1304(4-A)(I)."},"32":{"q":"29-A MRSA §1304 के अंतर्गत, एक मेन कमर्शियल लर्नर्स परमिट (CLP) जारी होने की तारीख से अधिकतम कितने समय के लिए मान्य होता है?","options":["180 days","One year","Two years","Five years"],"explanation":"मेन का कानून कहता है कि कमर्शियल लर्नर्स परमिट जारी होने की तारीख से अधिकतम एक वर्ष के लिए मान्य होता है। स्रोत: 29-A MRSA §1304(4-A)(G)."},"33":{"q":"मेन कमर्शियल लर्नर्स परमिट के तहत CMV चलाते समय, CLP धारक के साथ एक CDL धारक होना चाहिए जो कहां स्थित हो?","options":["वाहन में कहीं भी","एक अलग वाहन में पीछे चलते हुए","CLP धारक के बगल में फ्रंट सीट पर शारीरिक रूप से उपस्थित (या, एक पैसेंजर वाहन में, ड्राइवर के ठीक पीछे या ड्राइवर के पीछे पहली पंक्ति में)","संचालन के दौरान फोन पर उपलब्ध"],"explanation":"मेन का कानून आवश्यक करता है कि साथ में मौजूद CDL धारक CLP धारक के बगल में फ्रंट सीट पर शारीरिक रूप से उपस्थित हो, या एक पैसेंजर वाहन में ड्राइवर के ठीक पीछे या ड्राइवर के पीछे पहली पंक्ति में हो, और उसके पास उचित श्रेणी और एंडोर्समेंट हों। स्रोत: 29-A MRSA §1304(4-A)(A)."},"34":{"q":"29-A MRSA §1304(4-A) के तहत मेन कमर्शियल लर्नर्स परमिट धारक के लिए कौन सी गतिविधि स्पष्ट रूप से निषिद्ध है?","options":["खतरनाक पदार्थ ले जाने वाला वाणिज्यिक मोटर वाहन चलाना","दिन के उजाले के घंटों में गाड़ी चलाना","Class B वाहन चलाना","इंटरस्टेट राजमार्गों पर अभ्यास करना"],"explanation":"मेन का कानून एक CLP धारक को 49 CFR §383.5 में परिभाषित खतरनाक पदार्थ ले जाने वाला CMV चलाने से रोकता है। स्रोत: 29-A MRSA §1304(4-A)(F)."},"35":{"q":"29-A MRSA §1304(4-A) के अनुसार, पैसेंजर (P) या स्कूल बस (S) endorsement के लिए आवेदन करने हेतु एक मेन CLP धारक की न्यूनतम आयु कितनी होनी चाहिए?","options":["18 years","20 years","21 years","22 years"],"explanation":"मेन का कानून आवश्यक करता है कि एक CLP धारक की आयु पैसेंजर या स्कूल बस endorsement के लिए आवेदन करने हेतु कम से कम 21 वर्ष हो, और साथ में मौजूद CDL धारक के पास पैसेंजर endorsement हो, कम से कम एक वर्ष का अनुभव हो, और आयु कम से कम 22 हो। स्रोत: 29-A MRSA §1304(4-A)(E)."},"36":{"q":"नए मेन CDL आवेदकों पर लागू Entry-Level Driver Training (ELDT) आवश्यकता को किस प्रणाली के माध्यम से सत्यापित किया जाता है?","options":["Maine BMV ऑनलाइन पोर्टल","FMCSA Training Provider Registry (TPR)","National Driver Register","TSA Secure Flight database"],"explanation":"February 7, 2022 से प्रभावी, FMCSA का ELDT नियम नए CDL ऑपरेटरों और कुछ अपग्रेड के लिए प्रशिक्षण आवश्यक करता है, जो FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) में सूचीबद्ध और दर्ज किसी प्रदाता द्वारा पूरा किया गया हो। स्रोत: Maine CDL Manual, 'Entry Level Driver Training (ELDT)'; FMCSA 49 CFR Part 380."},"37":{"q":"मेन CDL के लिए आवेदन करते समय, एक आवेदक को एक प्रकार के ड्राइविंग संचालन के लिए स्व-प्रमाणित (self-certify) करना होता है। कौन सा सेट मेन द्वारा उपयोग की जाने वाली चार संघीय स्व-प्रमाणन श्रेणियों को सही ढंग से सूचीबद्ध करता है?","options":["स्थानीय, क्षेत्रीय, राष्ट्रीय, और अंतरराष्ट्रीय","Non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate","वाणिज्यिक, निजी, कृषि, और आपातकालीन","Class A, Class B, Class C, और Class D संचालन"],"explanation":"मेन, 49 CFR §383.71 का पालन करते हुए, CDL आवेदकों को चार श्रेणियों में से एक के लिए स्व-प्रमाणित करना आवश्यक करता है: non-excepted interstate, excepted interstate, non-excepted intrastate, या excepted intrastate। Non-excepted श्रेणियों के लिए एक मान्य मेडिकल एग्ज़ामिनर सर्टिफिकेट आवश्यक है। स्रोत: FMCSA 49 CFR §383.71; Maine BMV."},"38":{"q":"पहचान, निवास, और कानूनी-उपस्थिति दस्तावेजों के अलावा, मेन CDL आवेदक को कौन सी अतिरिक्त वस्तु प्रकट करनी होती है, जैसा कि ड्राइवर लाइसेंस जारी करने हेतु 29-A MRSA द्वारा अनिवार्य है?","options":["एक पासपोर्ट नंबर","एक Social Security number","एक मतदाता पंजीकरण कार्ड","एक वाहन टाइटल"],"explanation":"Maine CDL Manual का Social Security Number Disclosure Statement नोट करता है कि SSN का प्रकटीकरण अनिवार्य है और ड्राइवर लाइसेंस के लिए आवेदन या नवीनीकरण हेतु 29-A MRSA द्वारा आवश्यक है; BMV पहचान, मेन निवास, और कानूनी उपस्थिति के प्रमाण की भी आवश्यकता रखता है। स्रोत: Maine CDL Manual, 'Social Security Number Disclosure Statement'; 29-A MRSA."},"39":{"q":"मेन CDL नियमों के तहत, किस रक्त अल्कोहल सांद्रता (BAC) पर एक वाणिज्यिक मोटर वाहन चलाना अवैध है?","options":["0.04% या अधिक","0.08% या अधिक","0.02% या अधिक","0.10% या अधिक"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि यदि आपका BAC .04% या अधिक है तो CMV चलाना अवैध है। यह 0.04 सीमा सामान्य ड्राइवरों के लिए 0.08 सीमा की आधी है और संघीय मानक 49 CFR 383.51 के अनुरूप है।"},"40":{"q":"मेन में एक वाणिज्यिक मोटर वाहन चलाकर, एक ड्राइवर को कानूनी रूप से क्या किया हुआ माना जाता है?","options":["बचाव वकील के अधिकार का त्याग किया","अल्कोहल परीक्षण के लिए सहमति दी","किसी भी समय वाहन की तलाशी के लिए सहमत हुआ","साप्ताहिक रैंडम ड्रग यूरिनालिसिस के लिए सहमत हुआ"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है: 'If you operate a CMV, you shall be deemed to have given your consent to alcohol testing.' यह CMV संचालन के लिए मेन का निहित-सहमति (implied-consent) नियम है (29-A M.R.S. 2521 भी देखें)।"},"41":{"q":"पहले बड़े अपराध (major offense) (जैसे .04% या अधिक BAC के साथ CMV चलाना) के लिए, एक मेन ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 60 days","कम से कम 6 months","कम से कम 1 year","कम से कम 90 days"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि पहले बड़े अपराध के लिए, जिसमें .04% या अधिक BAC के साथ CMV चलाना शामिल है, आप कम से कम एक वर्ष के लिए अपना CDL खो देंगे। यह संघीय मानक 49 CFR 383.51 के अनुरूप है।"},"42":{"q":"मेन में, CMV चलाते समय आवश्यक होने पर रक्त अल्कोहल परीक्षण कराने से इनकार करने वाले CDL धारक के साथ क्या होता है (पहला अपराध)?","options":["बिना किसी अयोग्यता के एक चेतावनी","30 days के लिए CDL की हानि","120 days के लिए CDL की हानि","कम से कम 1 year के लिए CDL की हानि"],"explanation":"Maine CDL Manual (Section 1.2.2) 'रक्त अल्कोहल परीक्षण कराने से इनकार करना' को पहले बड़े अपराध के रूप में सूचीबद्ध करता है, जिसमें कम से कम एक वर्ष के लिए CDL की हानि होती है (यदि खतरनाक पदार्थों के लिए प्लैकार्ड किया गया हो तो 3 वर्ष)।"},"43":{"q":"यदि कोई पहला बड़ा अपराध (जैसे नशे में गाड़ी चलाना) तब होता है जब एक मेन ड्राइवर खतरनाक पदार्थों के लिए प्लैकार्ड किया गया CMV चला रहा हो, तो CDL कम से कम कितने समय के लिए खो जाता है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि यदि कोई पहला बड़ा अपराध तब होता है जब आप खतरनाक पदार्थों के लिए प्लैकार्ड किया गया CMV चला रहे हों, तो 49 CFR 383.51 के अनुसार आप कम से कम तीन वर्ष के लिए अपना CDL खो देंगे।"},"44":{"q":"मेन में दूसरे बड़े अपराध (जैसे CMV में दूसरा DUI) के लिए क्या परिणाम होता है?","options":["10 years के लिए CDL की हानि","आजीवन CDL की हानि","3 years के लिए CDL की हानि","5 years के लिए CDL की हानि"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि दूसरे बड़े अपराध के लिए आप आजीवन अपना CDL खो देंगे। यह आजीवन अयोग्यता संघीय मानक 49 CFR 383.51 का पालन करती है।"},"45":{"q":"मेन के नियमों के तहत, नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) को करने के लिए CMV का उपयोग करने पर क्या दंड है?","options":["1-year CDL की हानि","3-year CDL की हानि","आजीवन CDL की हानि","120-day CDL की हानि"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि यदि आप नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) को करने के लिए CMV का उपयोग करते हैं तो आप आजीवन अपना CDL खो देंगे। इस अपराध के लिए पुनर्बहाली की कोई संभावना नहीं है।"},"46":{"q":"मेन में, CMV चलाते समय .04% से कम पता लगाने योग्य मात्रा में अल्कोहल वाले ड्राइवर को:","options":["60 days के लिए अयोग्य ठहराया जाएगा","$5,000 का जुर्माना लगाया जाएगा","स्वतः ही OUI के लिए गिरफ्तार किया जाएगा","24 घंटे के लिए सेवा से बाहर (out-of-service) कर दिया जाएगा"],"explanation":"Maine CDL Manual (Section 1.2.2) कहता है कि यदि आपके पास .04% से कम कोई भी पता लगाने योग्य मात्रा में अल्कोहल है तो आपको 24 घंटे के लिए सेवा से बाहर कर दिया जाएगा। पूर्ण अयोग्यता के लिए .04% या अधिक BAC आवश्यक है।"},"47":{"q":"निम्नलिखित में से किसे Maine CDL Manual में 'गंभीर यातायात उल्लंघन' (serious traffic violation) के रूप में वर्गीकृत किया गया है?","options":["अत्यधिक तेज़ गति (पोस्ट की गई सीमा से 15 mph या अधिक ऊपर)","पोस्ट की गई सीमा से 5 mph ऊपर गाड़ी चलाना","एक समाप्त वाहन पंजीकरण","एक एकल पार्किंग उल्लंघन"],"explanation":"Maine CDL Manual (Section 1.2.3) अत्यधिक तेज़ गति को पोस्ट की गई सीमा से 15 mph या अधिक ऊपर के रूप में परिभाषित करता है, और इसे लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, और बहुत पास से चलने के साथ एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है।"},"48":{"q":"तीन साल की अवधि के भीतर CMV में दो गंभीर यातायात उल्लंघन करने के लिए एक मेन ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"Maine CDL Manual (Section 1.2.3) कहता है कि 49 CFR 383.51 के अनुसार, तीन साल की अवधि के भीतर CMV से जुड़े दो गंभीर यातायात उल्लंघनों के लिए आप कम से कम 60 days के लिए अपना CDL खो देंगे।"},"49":{"q":"तीन साल की अवधि के भीतर CMV में तीन या अधिक गंभीर यातायात उल्लंघन करने के लिए एक मेन ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 60 days","कम से कम 90 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"Maine CDL Manual (Section 1.2.3) कहता है कि 49 CFR 383.51 के अनुसार, तीन साल की अवधि के भीतर CMV से जुड़े तीन या अधिक गंभीर यातायात उल्लंघनों के लिए आप कम से कम 120 days के लिए अपना CDL खो देंगे।"},"50":{"q":"इनमें से कौन सा Maine CDL Manual में गंभीर यातायात उल्लंघनों में सूचीबद्ध है?","options":["पार्किंग लॉट में टर्न सिग्नल का उपयोग न करना","एक हेडलाइट बंद होने पर गाड़ी चलाना","500 pounds से कम का असुरक्षित भार ले जाना","CDL प्राप्त किए बिना या अपने पास रखे बिना CMV चलाना"],"explanation":"Maine CDL Manual (Section 1.2.3) CDL प्राप्त किए बिना, CDL को अपने पास रखे बिना, या उचित श्रेणी/एंडोर्समेंट के बिना CMV चलाने को गंभीर यातायात उल्लंघनों के रूप में सूचीबद्ध करता है।"},"51":{"q":"मेन में अपनाए गए संघीय नियमों के तहत, CMV चलाते समय टेक्स्टिंग और हाथ में पकड़े जाने वाले मोबाइल टेलीफोन का उपयोग करना किस रूप में माना जाता है:","options":["गंभीर यातायात उल्लंघन","1-year अयोग्यता वाले बड़े अपराध","सेवा-से-बाहर आदेश उल्लंघन","गैर-अयोग्यकारी उल्लंघन"],"explanation":"49 CFR 383.51 के अनुसार, CMV चलाते समय टेक्स्टिंग (49 CFR 392.80) और हाथ में पकड़े जाने वाले मोबाइल फोन का उपयोग (49 CFR 392.82) गंभीर यातायात उल्लंघन हैं। तीन साल में दो से 60-day अयोग्यता आती है; तीन से 120 days आते हैं। मेन इन संघीय मानकों को अपनाता है।"},"52":{"q":"मेन CDL ड्राइवरों पर लागू होने वाले संघीय हैंडहेल्ड-फोन नियमों के तहत, एक एकल टेक्स्टिंग या हाथ में पकड़े गए फोन की दोषसिद्धि भी ड्राइवर पर अधिकतम कितने तक का दीवानी दंड (civil penalty) ला सकती है:","options":["$500","$2,750","$11,000","$250"],"explanation":"मेन में लागू FMCSA नियमों (49 CFR 392.80/392.82) के तहत, एक ड्राइवर को प्रति टेक्स्टिंग या हाथ में पकड़े गए फोन उल्लंघन के लिए अधिकतम $2,750 तक का दीवानी दंड भुगतना पड़ता है; इसकी अनुमति देने वाले नियोक्ताओं को अधिकतम $11,000 तक के दंड का सामना करना पड़ता है। 3 साल में ऐसी दो दोषसिद्धियां CDL को 60 days के लिए अयोग्य भी कर देती हैं।"},"53":{"q":"Maine CDL Manual के अनुसार, सेवा-से-बाहर आदेश (out-of-service order) के पहले उल्लंघन के लिए एक ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 60 days","कम से कम 30 days","कम से कम 90 days","कम से कम 1 year"],"explanation":"Maine CDL Manual (Section 1.2.4) कहता है कि सेवा-से-बाहर आदेश के पहले उल्लंघन के लिए आप कम से कम 90 days के लिए अपना CDL खो देंगे। (वर्तमान संघीय 49 CFR 383.51 Table 4 न्यूनतम 180-day निर्धारित करता है, परंतु मेन का प्रकाशित मैनुअल 90 days बताता है।)"},"54":{"q":"Maine CDL Manual के अनुसार, दस साल की अवधि के भीतर दो सेवा-से-बाहर आदेश उल्लंघनों के लिए एक ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 90 days","कम से कम 6 months","कम से कम 3 years","कम से कम 1 year"],"explanation":"Maine CDL Manual (Section 1.2.4) कहता है कि दस साल की अवधि में दो सेवा-से-बाहर आदेश उल्लंघनों के लिए आप कम से कम एक वर्ष के लिए अपना CDL खो देंगे। दस साल के भीतर तीसरा होने पर कम से कम तीन वर्ष आते हैं।"},"55":{"q":"Maine CDL Manual के अनुसार, दस साल की अवधि के भीतर तीन या अधिक सेवा-से-बाहर आदेश उल्लंघनों के लिए एक ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 3 years","कम से कम 1 year","आजीवन","कम से कम 120 days"],"explanation":"Maine CDL Manual (Section 1.2.4) कहता है कि दस साल की अवधि के भीतर तीन या अधिक सेवा-से-बाहर आदेश उल्लंघनों के लिए आप कम से कम तीन वर्ष के लिए अपना CDL खो देंगे।"},"56":{"q":"Maine CDL Manual के अनुसार, पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए एक ड्राइवर कितने समय तक अपना CDL खो देगा?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"Maine CDL Manual (Section 1.2.5) कहता है कि 49 CFR 383.51 के अनुसार, पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए आप कम से कम 60 days के लिए अपना CDL खो देंगे।"},"57":{"q":"Maine CDL Manual के अनुसार, तीन साल की अवधि के भीतर तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 120 days","कम से कम 60 days","कम से कम 1 year","कम से कम 90 days"],"explanation":"Maine CDL Manual (Section 1.2.5) कहता है कि तीन साल की अवधि के भीतर तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए आप कम से कम एक वर्ष के लिए अपना CDL खो देंगे (पहला 60 days है, दूसरा 120 days है)।"},"58":{"q":"मेन में, यदि किसी CDL धारक के व्यक्तिगत-वाहन ड्राइविंग विशेषाधिकार को अल्कोहल, नियंत्रित-पदार्थ, या अपराध (felony) उल्लंघन के कारण रद्द (revoked), समाप्त (cancelled), या निलंबित (suspended) कर दिया जाता है, तो CDL का क्या होता है?","options":["कोई प्रभाव नहीं, क्योंकि यह एक व्यक्तिगत वाहन में हुआ","केवल 60 days के लिए CDL की हानि","पहले उल्लंघन पर तत्काल आजीवन अयोग्यता","1 year के लिए CDL की हानि (दूसरे ऐसे उल्लंघन के लिए आजीवन)"],"explanation":"Maine CDL Manual (Section 1.2.7), Motor Carrier Safety Improvement Act को दर्शाते हुए, कहता है कि यदि आपके व्यक्तिगत-वाहन विशेषाधिकार को अल्कोहल, नियंत्रित-पदार्थ, या अपराध (felony) उल्लंघन के लिए रद्द/समाप्त/निलंबित कर दिया जाता है तो आप 1 year के लिए अपना CDL खो देते हैं, और दूसरे ऐसे उल्लंघन पर आजीवन। कोई हार्डशिप CDL उपलब्ध नहीं है।"},"59":{"q":"मेन के 'मूव ओवर' कानून के तहत, जब आप किसी बहु-लेन सड़क पर चमकती बत्तियाँ दिखाते हुए खड़े आपातकालीन या सेवा वाहन के पास पहुँचते हैं, तो यदि सुरक्षित रूप से किया जा सके तो आपकी पहली आवश्यक कार्रवाई क्या है?","options":["खड़े वाहन से सटी हुई लेन से बाहर निकलकर किसी ऐसी लेन में जाएँ जो उससे सटी हुई न हो","जब तक आपातकालीन वाहन स्थल से नहीं चला जाता, तब तक पूरी तरह रुके रहें","अपना हॉर्न बजाएँ और निर्धारित गति सीमा पर चलते रहें","दाईं ओर के किनारे (शोल्डर) पर रुकें और हाथ के इशारे से आगे बढ़ने का संकेत मिलने तक प्रतीक्षा करें"],"explanation":"मेन का 'मूव ओवर' कानून (29-A MRSA Sec. 2054(9), और स्थिर/खराब वाहनों के लिए Sec. 2070(8)) चालक से माँग करता है कि यदि संभव हो तो वह खड़े वाहन से न सटी हुई लेन में होकर गुजरे; केवल तभी जब लेन बदलना असंभव या असुरक्षित हो, आप सावधान और विवेकपूर्ण कम की हुई गति से गुजर सकते हैं। स्रोत: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070।"},"60":{"q":"ऐसी दो-लेन वाली सड़क पर जहाँ किसी न-सटी हुई लेन में जाना असंभव है, मेन का 'मूव ओवर' कानून खड़े आपातकालीन या खराब वाहन के पास से गुजरते हुए चालक से क्या करने की माँग करता है?","options":["वाहन के पास से गुजरने से पहले पूरी तरह रुक जाएँ","कम से कम निर्धारित न्यूनतम गति सीमा बनाए रखें","वाहन के पास से सुरक्षित रूप से गुजरने के लिए उचित, सावधान और विवेकपूर्ण गति से गुजरें","गति घटाकर निर्धारित सीमा से ठीक 20 mph कम कर लें"],"explanation":"जब लेन बदलना संभव न हो या असुरक्षित हो, तो 29-A MRSA Sec. 2070(8)(B) (और Sec. 2054) माँग करता है कि 'वाहन के पास से सुरक्षित रूप से गुजरने के लिए उचित, सावधान और विवेकपूर्ण गति' से गुजरा जाए। मेन कोई सटीक mph का आँकड़ा निर्दिष्ट नहीं करता। स्रोत: Maine Revised Statutes Title 29-A Sec. 2070(8)।"},"61":{"q":"मेन के 'मूव ओवर' कानून का 2023 में विस्तार किया गया। अधिकृत आपातकालीन और सार्वजनिक सेवा वाहनों के अतिरिक्त, अब हटकर चलने या गति घटाने का कर्तव्य निम्न में से किसके पास से गुजरते समय भी लागू होता है:","options":["केवल चिह्नित पुलिस गाड़ियाँ और एम्बुलेंस","कोई भी स्थिर वाहन जिसके बारे में कोई विवेकशील व्यक्ति यह निष्कर्ष निकाले कि वह खराब है या अपनी उपस्थिति बताने के लिए चमकती बत्तियों का उपयोग कर रहा है","केवल टो ट्रक और राजमार्ग रखरखाव वाहन","केवल लाल चेतावनी झंडा दिखाने वाले वाहन"],"explanation":"29-A MRSA Sec. 2070(8), जो PL 2023 c. 122 द्वारा अधिनियमित हुआ, हटकर-चलने/गति-घटाने के कर्तव्य को किसी भी ऐसे स्थिर वाहन तक बढ़ाता है जिसके बारे में कोई विवेकशील व्यक्ति यह निष्कर्ष निकाले कि वह खराब है या जो अपनी उपस्थिति की चेतावनी देने के लिए चमकती बत्तियों का उपयोग कर रहा है। स्रोत: Maine Revised Statutes Title 29-A Sec. 2070(8)।"},"62":{"q":"मेन की मूव-ओवर / स्थिर-वाहन-के-पास-से-गुजरने की आवश्यकता का उल्लंघन करने पर निर्णीत न्यूनतम जुर्माना क्या है?","options":["$135","$500","$1,000","$275"],"explanation":"29-A MRSA Sec. 2070(8) यह प्रावधान करता है कि उल्लंघन एक यातायात अपराध (traffic infraction) है जिसके लिए $275 से कम नहीं का जुर्माना निर्णीत किया जाना चाहिए। स्रोत: Maine Revised Statutes Title 29-A Sec. 2070(8)।"},"63":{"q":"जब मेन के किसी रेलमार्ग क्रॉसिंग पर बिना पुती सफेद स्टॉप लाइन वाला क्रॉस-बक हो, तो प्लेकार्ड लगा खतरनाक-सामग्री वाहन या रुकने के लिए आवश्यक बस को निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 फीट से कम नहीं और 50 फीट से अधिक नहीं","5 फीट से कम नहीं और 25 फीट से अधिक नहीं","25 फीट से कम नहीं और 75 फीट से अधिक नहीं","10 फीट से कम नहीं और 100 फीट से अधिक नहीं"],"explanation":"29-A MRSA Sec. 2076(3) यात्रियों को ले जाने वाली बसों तथा प्लेकार्ड लगे/चिह्नित खतरनाक-सामग्री और कार्गो-टैंक वाहनों से माँग करता है कि वे निकटतम रेल से 15 फीट से कम नहीं और 50 फीट से अधिक नहीं की दूरी पर रुकें। मेन CDL मैनुअल (Sec. 2.15) में भी यही 15-से-50-फीट की सीमा बताई गई है। स्रोत: Maine Revised Statutes Title 29-A Sec. 2076; Maine CDL Manual।"},"64":{"q":"निम्नलिखित में से किस रेलमार्ग क्रॉसिंग पर मेन की बस या प्लेकार्ड लगे हैज़मैट वाहन को रुकने की आवश्यकता नहीं है?","options":["व्यापारिक जिले के बाहर स्थित कोई भी क्रॉसिंग","ऐसा क्रॉसिंग जिसकी चमकती लाल बत्तियाँ चालू नहीं हैं","केवल औद्योगिक स्विचिंग के लिए उपयोग की जाने वाली पटरियों का क्रॉसिंग, या 'exempt' चिह्न से चिह्नित कोई क्रॉसिंग","45 mph या उससे कम पर निर्धारित किसी भी सड़क पर कोई भी क्रॉसिंग"],"explanation":"29-A MRSA Sec. 2076 अनिवार्य रुकने के अपवादों की सूची देता है, जिनमें स्ट्रीटकार क्रॉसिंग, केवल औद्योगिक स्विचिंग के लिए उपयोग की जाने वाली पटरियाँ, जब किसी अधिकारी या फ्लैगर द्वारा आगे बढ़ने का निर्देश मिले, इस रूप में चिह्नित परित्यक्त क्रॉसिंग, और 'exempt' चिह्न से चिह्नित क्रॉसिंग शामिल हैं। स्रोत: Maine Revised Statutes Title 29-A Sec. 2076।"},"65":{"q":"मेन का कानून (29-A Sec. 2306) किसी रेलमार्ग ग्रेड क्रॉसिंग के पास पहुँच रहे स्कूल बस चालक को पूरी तरह रुकने और फिर क्रॉस करने से पहले क्या करने का निर्देश देता है?","options":["परिस्थितियों की परवाह किए बिना पूरे 30 सेकंड प्रतीक्षा करें","हॉर्न दो बार बजाएँ और फिर आगे बढ़ें","किसी यात्री को उतारकर फ्लैगर के रूप में काम करवाएँ","उचित संदेह से परे यह सुनिश्चित करें कि पटरी पर कोई ट्रेन निकट नहीं आ रही है"],"explanation":"29-A MRSA Sec. 2306 स्कूल बस चालक से माँग करता है कि वह पूरी तरह रुके (निकटतम रेल से 50 फीट से अधिक नहीं और 15 फीट से कम नहीं की दूरी पर) और क्रॉस करने से पहले उचित संदेह से परे यह सुनिश्चित करे कि कोई ट्रेन, इंजन या यान निकट नहीं आ रहा है। स्रोत: Maine Revised Statutes Title 29-A Sec. 2306।"},"66":{"q":"मेन की एक स्कूल बस यात्रियों को उतारने के लिए दो-लेन वाली सड़क पर अपनी लाल बत्तियाँ चमकाते हुए रुकती है। विपरीत दिशा से आ रहे वाहन के चालक को क्या करना चाहिए?","options":["गति घटाकर 15 mph करें और सावधानी से गुजरें","बस तक पहुँचने से पहले वाहन रोक दें और तब तक आगे न बढ़ें जब तक बस चल न पड़े या संकेत न दे","सामान्य रूप से चलते रहें क्योंकि विपरीत दिशा का यातायात छूट प्राप्त है","केवल तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पार करते दिखें"],"explanation":"29-A MRSA Sec. 2308(2) माँग करता है कि जब बस लाल बत्तियाँ चमकाते हुए रुकी हो, तो किसी भी दिशा से स्कूल बस के सामने आने वाले या उससे आगे निकलने वाले वाहन का चालक बस तक पहुँचने से पहले रुक जाए और तब तक आगे न बढ़े जब तक बस फिर से चल न पड़े या चालक संकेत न दे। स्रोत: Maine Revised Statutes Title 29-A Sec. 2308(2)।"},"67":{"q":"मेन के स्कूल-बस कानून के तहत, दूसरी ओर रुकी हुई स्कूल बस के लिए किस प्रकार की सड़क पर चालक को रुकने की आवश्यकता नहीं है?","options":["ऐसा मार्ग जो कर्बिंग या अन्य भौतिक अवरोध से अलग किया गया हो, उस अवरोध से अलग की गई लेन में स्थित बस के लिए","पुती दोहरी-पीली केंद्र रेखा वाली कोई भी सड़क","प्रत्येक दिशा में दो या अधिक लेन वाली कोई भी सड़क","50 mph या उससे अधिक की निर्धारित सीमा वाली कोई भी सड़क"],"explanation":"29-A MRSA Sec. 2308(3) चालक को रुकने से केवल तभी छूट देता है जब मार्ग कर्बिंग या अन्य भौतिक अवरोध से अलग किया गया हो (उस अवरोध से अलग की गई लेन में स्थित बस के लिए), या किसी सीमित-पहुँच राजमार्ग पर जहाँ पैदल यात्री पार न कर सकें। केवल पुती हुई रेखा अपने आप यह छूट उत्पन्न नहीं करती। स्रोत: Maine Revised Statutes Title 29-A Sec. 2308(3)।"},"68":{"q":"मेन में स्कूल बस चालक को यात्रियों को लेने या उतारने के लिए रुकने से कम से कम कितनी दूरी पहले बस की चमकती चेतावनी बत्तियाँ चालू करनी आवश्यक हैं?","options":["50 फीट","200 फीट","300 फीट","100 फीट"],"explanation":"29-A MRSA Sec. 2308(1) स्कूल बस चालक से माँग करता है कि वह यात्रियों को लेने या उतारने के लिए रुकने से कम से कम 100 फीट पहले चमकती बत्तियाँ चालू करे, और जब तक यात्री लिए या उतारे न जाएँ तब तक उन्हें चालू रखे। स्रोत: Maine Revised Statutes Title 29-A Sec. 2308(1)।"},"69":{"q":"मेन में, अपनी लाल बत्तियाँ चमकाते हुए रुकी हुई स्कूल बस के पास से अवैध रूप से गुजरना किस रूप में वर्गीकृत किया गया है, और प्रथम-अपराध की क्या सजा है?","options":["$135 जुर्माने वाला एक साधारण यातायात अपराध","एक दीवानी उल्लंघन जिसमें प्रथम अपराध के लिए कोई जुर्माना नहीं","$250 न्यूनतम जुर्माने वाला एक Class E अपराध","अनिवार्य कारावास सहित एक Class C अपराध"],"explanation":"29-A MRSA Sec. 2308(6) उपधारा 2 के उल्लंघन को एक Class E अपराध बनाता है, जो प्रथम अपराध के लिए $250 न्यूनतम जुर्माने से दंडनीय है, तथा 3 वर्षों के भीतर दूसरे अपराध पर अनिवार्य 30-दिन के लाइसेंस निलंबन सहित। स्रोत: Maine Revised Statutes Title 29-A Sec. 2308(6)।"},"70":{"q":"निर्धारित चिह्नों की अनुपस्थिति में, मेन का कानून किसी व्यापारिक या आवासीय जिले में अधिकतम गति क्या निर्धारित करता है?","options":["20 mph","25 mph","30 mph","35 mph"],"explanation":"29-A MRSA Sec. 2074(1) डिफ़ॉल्ट अधिकतम गति निर्धारित करता है: स्कूल ज़ोन में 15 mph, व्यापारिक या आवासीय जिले या घनी बसी हुई हिस्से में 25 mph, और अन्य सभी सार्वजनिक मार्गों पर 45 mph, प्रत्येक 'जब तक अन्यथा निर्धारित न हो'। स्रोत: Maine Revised Statutes Title 29-A Sec. 2074(1)।"},"71":{"q":"मेन की डिफ़ॉल्ट सांविधिक गति सीमाओं के तहत (जहाँ कोई अन्य सीमा निर्धारित नहीं है), 'अन्य सभी सार्वजनिक मार्गों' पर अधिकतम गति क्या है?","options":["55 mph","50 mph","40 mph","45 mph"],"explanation":"29-A MRSA Sec. 2074(1) अन्य सभी सार्वजनिक मार्गों पर डिफ़ॉल्ट अधिकतम गति 45 mph निर्धारित करता है जब तक अन्यथा निर्धारित न हो (व्यापारिक/आवासीय 25 mph है; स्कूल ज़ोन 15 mph है)। अधिकांश संख्यांकित राजमार्गों पर उच्चतर निर्धारित सीमाएँ होती हैं। स्रोत: Maine Revised Statutes Title 29-A Sec. 2074(1)।"},"72":{"q":"Maine Turnpike Authority द्वारा निर्धारित Maine Turnpike (I-95) पर अधिकतम गति सीमा क्या है?","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"Maine Turnpike Authority के नियम Turnpike पर सामान्य अधिकतम गति 70 mph निर्धारित करते हैं, कुछ दक्षिणी और उत्तरी खंडों पर कम निर्धारित सीमाओं के साथ। स्रोत: Maine Turnpike Authority Policies & Rules।"},"73":{"q":"Mile Marker 44 के दक्षिण में Maine Turnpike के तीन-लेन वाले खंडों पर, ट्रकों (ट्रक ट्रैक्टरों सहित) को किस लेन में चलने की अनुमति है?","options":["केवल सबसे दाईं ओर की एकमात्र लेन में","किसी भी लेन में, बाईं ओर की पासिंग लेन सहित","केवल सबसे दाईं ओर की दो लेनों में","केवल बीच की लेन में"],"explanation":"दक्षिणी मेन की वायु गुणवत्ता सुधारने के लिए, Maine Turnpike Authority के नियम ट्रकों (ट्रक ट्रैक्टरों सहित, पिकअप को छोड़कर) को Mile Marker 44 के दक्षिण में किसी भी ऐसे Turnpike खंड पर, जिसमें प्रत्येक दिशा में तीन लेन हों, सबसे दाईं ओर की दो लेनों तक सीमित करते हैं। स्रोत: Maine Turnpike Authority Policies & Rules।"},"74":{"q":"यदि आपको मेन में किसी एक-तरफा या विभाजित राजमार्ग पर या उसके किनारे CMV रोकना पड़े, तो मेन CDL मैनुअल आपकी तीन चेतावनी डिवाइसों को आ रहे यातायात की ओर किन दूरियों पर रखने को कहता है?","options":["10 फीट, 50 फीट, और 150 फीट","10 फीट, 100 फीट, और 200 फीट","25 फीट, 100 फीट, और 300 फीट","50 फीट, 100 फीट, और 500 फीट"],"explanation":"मेन CDL मैनुअल (Sec. 2.5.1) निर्देश देता है कि जब किसी एक-तरफा या विभाजित राजमार्ग पर या उसके किनारे रुका हो, तो चेतावनी डिवाइसों को आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखा जाए। स्रोत: Maine CDL Manual, Section 2।"},"75":{"q":"मेन के किसी दो-लेन (दो-तरफा अविभाजित) राजमार्ग पर, जब CMV रुका हुआ हो तो तीन आवश्यक चेतावनी डिवाइसों को कैसे रखा जाना चाहिए?","options":["10 फीट, 100 फीट, और 200 फीट, सभी वाहन के पीछे","केवल 50 फीट, 200 फीट, और 300 फीट वाहन के पीछे","एक डिवाइस वाहन के 10 फीट के भीतर और दो डिवाइस केवल 500 फीट पीछे","वाहन के 10 फीट के भीतर, और वाहन से 100 फीट आगे तथा 100 फीट पीछे"],"explanation":"मेन CDL मैनुअल (Sec. 2.5.2) निर्देश देता है कि वाहन को चिह्नित करने के लिए एक डिवाइस आगे या पीछे के 10 फीट के भीतर रखा जाए, साथ ही एक 100 फीट पीछे और एक 100 फीट आगे, किनारे (शोल्डर) पर या उस लेन में जिसमें वाहन है। स्रोत: Maine CDL Manual, Section 2।"},"76":{"q":"मेन की किसी सड़क पर CMV रोकने के बाद, आपको कितने मिनटों के भीतर अपनी आपातकालीन चेतावनी डिवाइसें लगा देनी चाहिए?","options":["10 मिनट","5 मिनट","15 मिनट","30 मिनट"],"explanation":"मेन CDL मैनुअल (Sec. 2.5.1) बताता है कि यदि आपको किसी सड़क या किनारे (शोल्डर) पर रुकना पड़े, तो आपको दस मिनट के भीतर आपातकालीन चेतावनी डिवाइसें लगा देनी चाहिए। स्रोत: Maine CDL Manual, Section 2।"},"77":{"q":"यदि मेन में कोई CMV किसी पहाड़ी या मोड़ के ठीक आगे रुका हो, तो मेन CDL मैनुअल कहता है कि पीछे की चेतावनी डिवाइस को इस प्रकार पुनः रखा जाना चाहिए कि:","options":["मोड़ की परवाह किए बिना यह वाहन से ठीक 200 फीट पर रखा जाए","इसे हटा दिया जाए क्योंकि हैज़र्ड बत्तियाँ पर्याप्त हैं","यह चालकों को सड़क पर पीछे की ओर चेतावनी दे, ताकि वाहन 500 फीट के भीतर दिखाई दे","इसे पहाड़ी की चोटी पर ठीक 50 फीट आगे रखा जाए"],"explanation":"मेन CDL मैनुअल (Sec. 2.5.2) निर्देश देता है कि यदि कोई पहाड़ी या मोड़ दृष्टि-रेखा को बाधित करे, तो सबसे पीछे के त्रिकोण को सड़क पर पीछे की ओर हटा दें ताकि चेतावनी मिल सके और अन्य चालक वाहन को 500 फीट के भीतर देख सकें। स्रोत: Maine CDL Manual, Section 2।"},"78":{"q":"मेन में, किसी ऐसे भार के लिए जो निम्न में से किस आयाम से अधिक हो, सामान्यतः Bureau of Motor Vehicles / MaineDOT से एक ओवरलिमिट (ओवरसाइज़) परमिट आवश्यक होता है?","options":["10 फीट 0 इंच से अधिक चौड़ाई या 15 फीट 0 इंच से अधिक ऊँचाई","8 फीट 6 इंच से अधिक चौड़ाई या 13 फीट 6 इंच से अधिक ऊँचाई","8 फीट 0 इंच से अधिक चौड़ाई या 12 फीट 0 इंच से अधिक ऊँचाई","9 फीट 0 इंच से अधिक चौड़ाई या 14 फीट 6 इंच से अधिक ऊँचाई"],"explanation":"मेन 8 फीट 6 इंच चौड़ाई और 13 फीट 6 इंच ऊँचाई की मानक कानूनी सीमाओं का पालन करता है; इनसे अधिक भार के लिए Maine BMV/MaineDOT ओवरलिमिट परमिट कार्यक्रम के माध्यम से जारी किया गया ओवरलिमिट (ओवरसाइज़) परमिट आवश्यक होता है। स्रोत: Maine BMV Overlimit Permits / MaineDOT।"},"79":{"q":"कौन सी मेन एजेंसी कमर्शियल ड्राइवर लाइसेंस (CDL) जारी करती है और CDL परीक्षण का संचालन करती है?","options":["Maine Bureau of Motor Vehicles (BMV), जो Secretary of State के कार्यालय के अंतर्गत है","Maine Department of Transportation (MaineDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Maine State Police Commercial Vehicle Enforcement Unit"],"explanation":"Maine Bureau of Motor Vehicles (BMV), जो Secretary of State के कार्यालय का एक प्रभाग है, सभी मेन CDL जारी करता है और ज्ञान तथा कौशल परीक्षाओं का संचालन करता है। MaineDOT सड़कों और ओवरसाइज़/ओवरवेट परमिटों को संभालता है, लाइसेंसिंग को नहीं। स्रोत: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv)।"},"80":{"q":"मेन CDL स्व-प्रमाणन फॉर्म (MVE-64C) पर, एक आवेदक कितने प्रकार-के-संचालन वर्गों में से चुन सकता है?","options":["चार","दो","तीन","छह"],"explanation":"मेन में चार वर्गों में से किसी एक में स्व-प्रमाणन आवश्यक है: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, या Excepted Intrastate। स्रोत: Maine BMV CDL Medical Self-Certification Form MVE-64C; 49 CFR 383.71।"},"81":{"q":"एक मेन चालक 'Non-Excepted Interstate' के रूप में स्व-प्रमाणन करता है। BMV के पास फाइल में कौन सा अतिरिक्त दस्तावेज़ होना चाहिए?","options":["एक संघीय DOT Medical Examiner's Certificate (मेडिकल कार्ड)","स्व-प्रमाणन फॉर्म के अतिरिक्त कुछ नहीं","एक नोटरीकृत नियोक्ता प्राधिकरण पत्र","एक Maine DOT ओवरसाइज़/ओवरवेट परमिट"],"explanation":"जो चालक Non-Excepted Interstate के रूप में स्व-प्रमाणन करते हैं, उन्हें BMV को एक वैध संघीय Medical Examiner's Certificate (MCSA-5876 / मेडिकल कार्ड) प्रदान करना होगा। Excepted चालकों को इसे जमा करना आवश्यक नहीं है। स्रोत: Maine BMV CDL self-certification guidance; 49 CFR 383.71।"},"82":{"q":"मेन में किसी CDL आवेदक का Medical Examiner's Certificate तैयार करने वाली DOT शारीरिक जाँच करने के लिए कौन योग्य है?","options":["FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक मेडिकल परीक्षक","आवेदक की पसंद का कोई भी लाइसेंस प्राप्त चिकित्सक","परीक्षण स्थल पर एक BMV परीक्षक","आवेदक का नियमित ऑप्टोमेट्रिस्ट"],"explanation":"DOT शारीरिक जाँच एक ऐसे मेडिकल परीक्षक द्वारा की जानी चाहिए जो FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध हो। स्रोत: Maine BMV CDL medical requirements; 49 CFR 391.43।"},"83":{"q":"किसी मेन CDL धारक के लिए DOT Medical Examiner's Certificate अधिकतम कितने समय तक वैध हो सकता है?","options":["2 साल","1 साल","3 साल","5 साल"],"explanation":"एक Medical Examiner's Certificate अधिकतम 2 साल के लिए वैध होता है; यदि किसी स्थिति की निगरानी आवश्यक हो तो परीक्षक चालक को कम अवधि के लिए प्रमाणित कर सकता है। पुराने के समाप्त होने से पहले एक नया कार्ड फाइल में होना चाहिए। स्रोत: Maine BMV CDL medical requirements; 49 CFR 391.45।"},"84":{"q":"एक मेन CDL धारक BMV की CDL Compliance Unit को स्व-प्रमाणन फॉर्म या मेडिकल प्रमाणपत्र कैसे जमा कर सकता है?","options":["BMV CDL Compliance Unit को फैक्स, ईमेल, या डाक द्वारा","केवल Augusta के केंद्रीय कार्यालय में व्यक्तिगत रूप से","केवल FMCSA Training Provider Registry पर अपलोड करके","केवल चालक के नियोक्ता या मोटर कैरियर के माध्यम से"],"explanation":"मेन MVE-64C स्व-प्रमाणन और मेडिकल प्रमाणपत्र को फैक्स द्वारा, CDL Compliance Unit को ईमेल (PDF/Word) द्वारा, या Augusta में BMV CDL Compliance Unit को डाक द्वारा स्वीकार करता है। स्रोत: Maine BMV CDL Compliance Unit submission instructions।"},"85":{"q":"किसी व्यक्ति को मेन Commercial Learner's Permit (CLP) जारी किए जाने से पहले, कम से कम कौन सा ज्ञान परीक्षण पास करना आवश्यक है?","options":["General Knowledge परीक्षण","केवल Air Brakes एंडोर्समेंट परीक्षण","Hazardous Materials परीक्षण","प्री-ट्रिप निरीक्षण कौशल परीक्षण"],"explanation":"CLP प्राप्त करने के लिए General Knowledge परीक्षण (साथ ही आवेदक जो भी एंडोर्समेंट चाहता है उनके परीक्षण) पास करना आवश्यक है। Maine BMV वह आधिकारिक CDL मैनुअल प्रकाशित करता है जिस पर ये परीक्षण आधारित हैं। स्रोत: Maine CDL Manual; Maine BMV CDL Exam page।"},"86":{"q":"प्रत्येक मेन CDL ज्ञान परीक्षण पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["80%","70%","75%","90%"],"explanation":"पास होने के लिए एक चालक को प्रत्येक ज्ञान परीक्षण के कम से कम 80% प्रश्नों का सही उत्तर देना चाहिए। स्रोत: Maine CDL Manual; 49 CFR 383.135।"},"87":{"q":"मेन CDL कौशल परीक्षण में क्रम में कौन से तीन भाग होते हैं?","options":["प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और ऑन-रोड ड्राइविंग","एयर ब्रेक जाँच, बैकिंग, और एक लिखित एंडोर्समेंट परीक्षा","बेसिक वाहन नियंत्रण, समानांतर पार्किंग, और एक हैज़मैट साक्षात्कार"],"explanation":"CDL कौशल परीक्षण के तीन भाग इसी क्रम में संचालित किए जाते हैं: प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण परीक्षण, और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: Maine CDL Manual; 49 CFR 383.113।"},"88":{"q":"कौन सा कौशल-परीक्षण घटक मेन के किसी आवेदक से सीधी-रेखा बैकिंग, ऑफसेट बैकिंग, और एली डॉकिंग जैसी क्रियाएँ करवाने की माँग करता है?","options":["बेसिक वाहन नियंत्रण परीक्षण","प्री-ट्रिप वाहन निरीक्षण","ऑन-रोड ड्राइविंग परीक्षण","General Knowledge परीक्षण"],"explanation":"सीधी-रेखा बैकिंग, ऑफसेट बैकिंग, और एली डॉकिंग जैसी बैकिंग क्रियाओं का मूल्यांकन कौशल परीक्षण के बेसिक वाहन नियंत्रण भाग में किया जाता है। स्रोत: Maine CDL Manual; 49 CFR 383.113।"},"89":{"q":"मेन में पहली बार Class A CDL के आवेदक को किसी ऐसे प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा जो:","options":["FMCSA Training Provider Registry (TPR) में सूचीबद्ध हो","केवल Maine BMV परीक्षक समूह द्वारा अनुमोदित हो","स्थानीय कम्युनिटी कॉलेज प्रणाली द्वारा प्रमाणित हो","MaineDOT के परमिट कार्यालय के साथ पंजीकृत हो"],"explanation":"ELDT एक ऐसे प्रदाता से प्राप्त किया जाना चाहिए जो FMCSA Training Provider Registry में सूचीबद्ध हो; प्रदाता पूर्णता की रिपोर्ट इलेक्ट्रॉनिक रूप से FMCSA को देता है। स्रोत: Maine BMV ELDT page; 49 CFR Part 380 Subpart F।"},"90":{"q":"निम्न में से किसके लिए मेन परीक्षण से पहले ELDT की माँग करता है?","options":["पहली बार Class A या B CDL, या पहली बार P, S, या H एंडोर्समेंट","वर्ग की परवाह किए बिना हर CDL नवीनीकरण","केवल Hazardous Materials (H) एंडोर्समेंट के आवेदक","केवल Class B से Class A में अपग्रेड करने वाले चालक"],"explanation":"ELDT पहली बार Class A या Class B CDL प्राप्त करने, उच्चतर वर्ग में अपग्रेड करने, या पहली बार passenger (P), school bus (S), या hazardous materials (H) एंडोर्समेंट प्राप्त करने के लिए आवश्यक है। स्रोत: Maine BMV ELDT page; 49 CFR Part 380।"},"91":{"q":"मेन CDL आवेदक को आवश्यक ELDT कब पूरा करना चाहिए?","options":["संबंधित ज्ञान या कौशल परीक्षण देने से पहले","कौशल परीक्षण पास करने के बाद लेकिन लाइसेंस प्रिंट होने से पहले","CDL जारी होने के 30 दिनों के भीतर","केवल CLP की 14-दिन की होल्ड अवधि समाप्त होने के बाद"],"explanation":"H एंडोर्समेंट के लिए ELDT थ्योरी ज्ञान परीक्षण से पहले पूरी होनी चाहिए, और Class A/B तथा P/S एंडोर्समेंट के लिए कौशल परीक्षण से पहले बिहाइंड-द-व्हील प्रशिक्षण पूरा होना चाहिए। प्रशिक्षण संबंधित परीक्षण से पहले होना चाहिए। स्रोत: Maine BMV ELDT page; 49 CFR Part 380 Subpart F।"},"92":{"q":"CLP प्राप्त करने के बाद, CDL कौशल परीक्षण देने की अनुमति मिलने से पहले मेन आवेदक को इसे कितने समय तक धारण करना चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"एक CLP धारक को कौशल परीक्षण देने से पहले परमिट जारी होने के बाद कम से कम 14 दिन प्रतीक्षा करनी चाहिए। स्रोत: Maine BMV CDL pages; 49 CFR 383.25।"},"93":{"q":"मेन CLP के तहत संचालन करते समय, परमिट धारक के साथ कौन होना चाहिए:","options":["एक CDL धारक, जो उस वाहन के वर्ग और एंडोर्समेंट के लिए वैध हो, चालक के बगल में बैठा हो","21 वर्ष या उससे अधिक आयु का कोई भी लाइसेंस प्राप्त चालक","केवल एक BMV परीक्षक","कोई नहीं, बशर्ते वाहन खाली हो"],"explanation":"एक CLP धारक किसी कमर्शियल मोटर वाहन का संचालन केवल तभी कर सकता है जब उसके साथ ऐसा व्यक्ति हो जिसके पास उस वर्ग के वाहन के लिए वैध CDL हो, और जो परमिट धारक के बगल में अगली सीट पर बैठा हो। स्रोत: Maine CDL Manual; 49 CFR 383.25।"},"94":{"q":"65 वर्ष से कम आयु के अधिकांश मेन CDL धारकों के लिए, CDL का नवीनीकरण कितनी बार किया जाना चाहिए?","options":["हर 5 साल में","हर 4 साल में","हर 6 साल में","हर 8 साल में"],"explanation":"65 वर्ष से कम आयु के धारकों के लिए मेन CDL 5-वर्षीय चक्र के लिए जारी किया जाता है। (65 वर्ष या उससे अधिक आयु के धारक 4-वर्षीय चक्र पर नवीनीकरण करते हैं।) स्रोत: Maine BMV CDL renewal information।"},"95":{"q":"केवल इंट्रास्टेट (मेन के भीतर) ड्राइविंग के लिए मेन CDL जारी किए जाने की न्यूनतम आयु क्या है?","options":["18","21","19","16"],"explanation":"इंट्रास्टेट ड्राइविंग के लिए मेन CDL प्राप्त करने हेतु आवेदक की आयु कम से कम 18 होनी चाहिए; इंटरस्टेट ड्राइविंग, खतरनाक सामग्री के परिवहन, या यात्रियों को ले जाने के लिए 21 आयु आवश्यक है। स्रोत: Maine CDL Manual; Maine BMV CDL pages।"},"96":{"q":"CDL के लिए आवेदन करते समय पहचान और पात्रता स्थापित करने के लिए मेन आवेदक को आमतौर पर किस दस्तावेज़ों के समूह की आवश्यकता होगी?","options":["पहचान का प्रमाण, अमेरिका में कानूनी उपस्थिति, Social Security नंबर, और मेन निवास","केवल एक वर्तमान मेन गैर-कमर्शियल ड्राइवर लाइसेंस","एक पासपोर्ट के साथ एक MaineDOT ओवरसाइज़ परमिट","केवल एक नियोक्ता पत्र और एक वाहन पंजीकरण"],"explanation":"आवेदकों को मेडिकल और स्व-प्रमाणन आवश्यकताओं को पूरा करने के अतिरिक्त, पहचान, अमेरिका में वैध उपस्थिति, एक Social Security नंबर, और मेन निवास का दस्तावेज़ प्रस्तुत करना होगा। स्रोत: Maine BMV CDL application requirements।"},"97":{"q":"यदि कोई मेन चालक आवश्यक मेडिकल प्रमाणपत्र को इस तरह समाप्त होने देता है कि वह अब BMV के पास फाइल में नहीं रहता, तो इसका संभावित परिणाम क्या है?","options":["जब तक वैध प्रमाणपत्र फाइल नहीं किया जाता, तब तक चालक का CDL विशेषाधिकार डाउनग्रेड कर दिया जाता है (कमर्शियल विशेषाधिकार हटा दिए जाते हैं)","CDL की सामान्य नवीनीकरण तिथि तक कुछ नहीं बदलता","CDL को बिना पुनर्बहाली के किसी मार्ग के स्थायी रूप से निरस्त कर दिया जाता है","केवल एक लिखित चेतावनी जारी की जाती है जिसका लाइसेंस पर कोई प्रभाव नहीं पड़ता"],"explanation":"यदि किसी non-excepted चालक का मेडिकल प्रमाणपत्र समाप्त हो जाता है और BMV के पास अपडेट नहीं किया जाता, तो राज्य को CDL को डाउनग्रेड करना होगा, यानी कमर्शियल ड्राइविंग विशेषाधिकार हटा देने होंगे, जब तक कि एक वर्तमान प्रमाणपत्र जमा न किया जाए। स्रोत: Maine BMV CDL Compliance guidance; 49 CFR 383.73।"}},"ar":{"0":{"q":"على طريق عام في ولاية مين، ما هو الحد الأقصى للعرض الإجمالي المسموح به لمركبة دون تصريح خاص؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"بموجب 29-A M.R.S. §2380، لا يجوز تشغيل مركبة يتجاوز عرضها الإجمالي 102 inches (8'6\") على طريق عام أو جسر في ولاية مين دون تصريح. المصدر: Maine Revised Statutes Title 29-A, §2380."},"1":{"q":"ما هو الحد الأقصى القانوني للارتفاع الهيكلي لمركبة على طرق ولاية مين السريعة دون تصريح تجاوز الحدود؟","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"تحظر 29-A M.R.S. §2380 تشغيل مركبة لها جزء هيكلي دائم أو مؤقت يزيد ارتفاعه عن 13 feet 6 inches. يمكن أن تمتد الحمولة غير القابلة للتقليص حتى 6 inches فوق ذلك، لكن الحد الهيكلي هو 13'6\". المصدر: Maine Revised Statutes Title 29-A, §2380."},"2":{"q":"في ولاية مين، تُستثنى بعض الملحقات الجانبية (مثل المرايا ورفارف الطين) من قياس العرض فقط إذا لم تمتد إلى ما هو أبعد من جانب المركبة بأكثر من أي مقدار؟","options":["2 inches","3 inches","6 inches","9 inches"],"explanation":"تستثني 29-A M.R.S. §2380 الملحقات المحددة (المرايا، مفصلات الأبواب، مزاريب المطر، رفارف الطين، وما إلى ذلك) من قياس العرض البالغ 102-inch شريطة ألا تمتد بأكثر من 3 inches من جانب المركبة. المصدر: Maine Revised Statutes Title 29-A, §2380."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي لمركبة مركبة من خمسة محاور أو أكثر على طرق ولاية مين العامة (غير الطرق السريعة بين الولايات) بموجب حدود الوزن القياسية؟","options":["69,000 pounds","73,280 pounds","80,000 pounds","90,000 pounds"],"explanation":"بموجب 29-A M.R.S. §2353، الحد الأقصى للوزن الإجمالي لمجموعة من خمسة محاور أو أكثر هو 80,000 pounds (تقتصر مركبة ذات محورين على 34,000، وذات ثلاثة محاور على 54,000، وذات أربعة محاور على 69,000). المصدر: Maine Revised Statutes Title 29-A, §2353."},"4":{"q":"بموجب حدود الوزن القياسية في ولاية مين (غير الطرق بين الولايات) في §2353، ما هو الحد الأقصى للوزن المسموح به على محور واحد؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"تحدد 29-A M.R.S. §2353 حد المحور الواحد عند 22,400 pounds على شبكة الطرق السريعة العامة في ولاية مين، وهو أعلى من رقم المحور الواحد الفيدرالي للطرق بين الولايات البالغ 20,000-pound. المصدر: Maine Revised Statutes Title 29-A, §2353."},"5":{"q":"على شبكة الطرق السريعة العامة في ولاية مين (§2353)، ما هو الحد الأقصى للوزن المسموح به على وحدة محور مزدوج؟","options":["34,000 pounds","36,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"تسمح 29-A M.R.S. §2353 بـ 38,000 pounds على وحدة محور مزدوج على الطرق العامة في ولاية مين، وهو ما يتجاوز حد المحور المزدوج البالغ 34,000-pound المطبق على نظام الطرق السريعة بين الولايات بموجب §2355. المصدر: Maine Revised Statutes Title 29-A, §2353."},"6":{"q":"على نظام الطرق السريعة بين الولايات في ولاية مين، ما هو الحد الأقصى للوزن المسموح به على وحدة محور مزدوج؟","options":["32,000 pounds","34,000 pounds","38,000 pounds","41,000 pounds"],"explanation":"تقصر 29-A M.R.S. §2355 وحدة المحور المزدوج على 34,000 pounds على نظام الطرق السريعة بين الولايات، بما يتوافق مع المعيار الفيدرالي. تسمح الطرق العامة في ولاية مين بمحور مزدوج أعلى يبلغ 38,000-pound بموجب §2353. المصدر: Maine Revised Statutes Title 29-A, §2355."},"7":{"q":"على نظام الطرق بين الولايات في ولاية مين، تقتصر مركبة يزيد وزنها الإجمالي عن 73,280 pounds على أي وزن للمحور الواحد؟","options":["18,000 pounds","20,000 pounds","22,000 pounds","22,400 pounds"],"explanation":"تقصر 29-A M.R.S. §2355 المحور الواحد على 20,000 pounds عندما يتجاوز الوزن الإجمالي للمركبة 73,280 pounds (و 22,000 pounds عندما يكون الوزن الإجمالي 73,280 أو أقل) على نظام الطرق السريعة بين الولايات. المصدر: Maine Revised Statutes Title 29-A, §2355."},"8":{"q":"على نظام الطرق بين الولايات في ولاية مين، يجوز لمركبة يبلغ وزنها الإجمالي 73,280 pounds أو أقل أن تحمل أقصى وزن على محور واحد؟","options":["20,000 pounds","22,000 pounds","22,400 pounds","24,200 pounds"],"explanation":"تسمح 29-A M.R.S. §2355 بمحور واحد حتى 22,000 pounds عندما يكون الوزن الإجمالي للمركبة 73,280 pounds أو أقل على الطرق بين الولايات، وينخفض إلى 20,000 pounds عندما يتجاوز الوزن الإجمالي 73,280. المصدر: Maine Revised Statutes Title 29-A, §2355."},"9":{"q":"في معادلة الجسر الفيدرالية المستخدمة على نظام الطرق بين الولايات في ولاية مين، W = 500(LN/(N-1) + 12N + 36)، ماذا يمثل المتغير \"L\"؟","options":["طول الحمولة بالأقدام","المسافة بالأقدام بين المحورين الطرفيين لمجموعة","الوزن القانوني لكل محور بآلاف الأرطال","عدد المحاور المحملة على المركبة"],"explanation":"في معادلة الجسر الفيدرالية B المطبقة بموجب 29-A M.R.S. §2355، W هو الوزن الإجمالي المسموح به على مجموعة من المحاور، و N هو عدد المحاور في المجموعة، و L هو المسافة بالأقدام بين المحورين الطرفيين (الخارجيين) لتلك المجموعة. المصدر: Maine Revised Statutes Title 29-A, §2355 (federal bridge formula)."},"10":{"q":"يجوز لمركبة مركبة من ستة محاور في ولاية مين (جرّار ذو 3 محاور مع نصف مقطورة ثلاثية المحاور) أن تصل إلى حد أقصى للوزن الإجمالي يصل إلى أي مقدار عند استيفاء جميع الشروط؟","options":["80,000 pounds","90,000 pounds","100,000 pounds","120,000 pounds"],"explanation":"تسمح 29-A M.R.S. §2354 بمركبة مركبة من ستة محاور (جرّار شاحنة ذو 3 محاور مع نصف مقطورة ثلاثية المحاور) حتى 100,000 pounds عند استيفاء شروط المباعدة وغيرها؛ والحد الأساسي هو 90,000 pounds. المصدر: Maine Revised Statutes Title 29-A, §2354."},"11":{"q":"بالنسبة لمركبة ولاية مين المركبة من ستة محاور بوزن 100,000-pound، يجب ألا تقل المسافة بين المحورين الطرفيين (باستثناء محور التوجيه) عن كم قدم؟","options":["30 feet","32 feet","36 feet","40 feet"],"explanation":"تشترط 29-A M.R.S. §2354 ألا تقل المسافة بين المحورين الطرفيين (باستثناء محور التوجيه) عن 36 feet؛ ويُخفَّض الحد الأقصى للوزن الإجمالي بمقدار 2,000 pounds عن كل قدم تقل فيها المسافة عن 36 feet. المصدر: Maine Revised Statutes Title 29-A, §2354."},"12":{"q":"بموجب قانون الوزن لستة محاور في ولاية مين، بأي مقدار يُخفَّض الحد الأقصى للوزن الإجمالي عن كل قدم تقل فيها مباعدة المحورين الطرفيين عن الحد الأدنى المطلوب؟","options":["1,000 pounds per foot","1,500 pounds per foot","2,000 pounds per foot","2,500 pounds per foot"],"explanation":"تخفّض 29-A M.R.S. §2354 الحد الأقصى المسموح به للوزن الإجمالي لمركبة مركبة من ستة محاور بمقدار 2,000 pounds عن كل قدم تقل فيها المسافة بين المحورين الطرفيين عن 36 feet المطلوبة. المصدر: Maine Revised Statutes Title 29-A, §2354."},"13":{"q":"يسمح قانون تفاوت الوزن في ولاية مين (§2357) للحمولات المؤهلة (مثل المنتجات الخشبية وملح الطرق والحصى) بتجاوز الحد الأقصى للوزن الإجمالي بأي مقدار؟","options":["حتى 5% فوق الحد الأقصى","حتى 10% (110% من الحد الأقصى)","حتى 15% فوق الحد الأقصى","حتى 2,000 pounds فوق الحد الأقصى"],"explanation":"تنص 29-A M.R.S. §2357 على أن المركبة المؤهلة لا تعد مخالِفة إذا لم يتجاوز وزنها الإجمالي 110% (10% فوق) من الحد الأقصى للوزن الإجمالي في §2353، بالنسبة للسلع المدرجة مثل المنتجات الخشبية والحصى وملح الطرق والمواد السائبة المماثلة. المصدر: Maine Revised Statutes Title 29-A, §2357."},"14":{"q":"ينطبق تفاوت الوزن بنسبة 10% في ولاية مين لبعض السلع (§2357) على أي الطرق؟","options":["فقط على نظام الطرق السريعة بين الولايات","على جميع طرق ولاية مين باستثناء نظام الطرق السريعة بين الولايات","فقط على طريق مين السريع (Maine Turnpike)","على جميع طرق ولاية مين بما في ذلك الطرق بين الولايات"],"explanation":"تنص 29-A M.R.S. §2357 صراحة على أن تفاوت الوزن لا ينطبق على مركبة تُشغَّل على نظام الطرق السريعة بين الولايات؛ فهو متاح على الطرق العامة (غير الطرق بين الولايات) في ولاية مين. المصدر: Maine Revised Statutes Title 29-A, §2357."},"15":{"q":"من هي الجهة المخوّلة بمنح تصاريح حركة تجاوز الحدود على مستوى الولاية (الحجم الزائد/الوزن الزائد) في ولاية مين، بناءً على مشورة مفوض النقل؟","options":["وزير الخارجية (Secretary of State)","شرطة ولاية مين (Maine State Police)","هيئة طريق مين السريع (Maine Turnpike Authority)","لجنة المرافق العامة (Public Utilities Commission)"],"explanation":"بموجب 29-A M.R.S. §2382، يمنح وزير الخارجية (من خلال مكتب المركبات الآلية Bureau of Motor Vehicles)، متصرفًا وفق إرشادات ومشورة مفوض النقل، تصاريح حركة تجاوز الحدود؛ ويجوز للمقاطعات والبلديات السماح بالمرور على طرقها الخاصة. المصدر: Maine Revised Statutes Title 29-A, §2382."},"16":{"q":"في ولاية مين، يُشترط تصريح تجاوز الحدود (الحجم الزائد/الوزن الزائد) لنقل أي نوع من الحمولات التي تتجاوز حدود الأبعاد أو الوزن القانونية؟","options":["أي حمولة، سواء أمكن فصلها أم لا","فقط الحمولات القابلة للتقسيم التي يمكن تقسيمها إلى وحدات قانونية","جسم غير قابل للتقسيم لا يمكن تقليصه إلى الحدود القانونية","فقط الحمولات المنقولة على نظام الطرق السريعة بين الولايات"],"explanation":"تجيز 29-A M.R.S. §2381 و §2382 التصاريح للأجسام غير القابلة للتقسيم (تلك التي لا يمكن تقليصها بشكل معقول إلى الطول أو العرض أو الارتفاع أو الوزن القانوني). يجب تفكيك الحمولات القابلة للتقسيم إلى الحدود القانونية بدلاً من الترخيص لها. المصدر: Maine Revised Statutes Title 29-A, §§2381–2382."},"17":{"q":"ما هي أقصى مدة لتصريح تجاوز الحدود طويل الأجل الذي يجوز لوزير خارجية ولاية مين إصداره للشاحنات والجرّارات وأنصاف المقطورات؟","options":["30 days","6 months","One year","Two years"],"explanation":"تسمح 29-A M.R.S. §2382 لوزير الخارجية بمنح تصاريح صالحة لمدة تصل إلى عام واحد للشاحنات وجرّارات الشاحنات وأنصاف المقطورات ومركبات الإنقاذ شديدة التحمل ومعدات Class A المتنقلة الخاصة؛ وإلا تُصدر تصاريح رحلة واحدة. المصدر: Maine Revised Statutes Title 29-A, §2382."},"18":{"q":"عندما تعمل نصف مقطورة بطول 53-foot في ولاية مين خارج الشبكة الوطنية للطرق السريعة، يجب ألا يتجاوز الطول الإجمالي للمركبة والحمولة أي طول إجمالي؟","options":["65 feet","69 feet","74 feet","80 feet"],"explanation":"تسمح 29-A M.R.S. §2390 بنصف مقطورة يزيد طولها عن 48 feet ولكن لا يتجاوز 53 feet (مع مسافة من مسمار الارتكاز إلى المحور الخلفي لا تزيد عن 43 feet)، لكن عند العمل خارج الشبكة الوطنية يجب ألا يتجاوز الطول الإجمالي 74 feet. على نظام الطرق السريعة بين الولايات لا ينطبق حد الطول الإجمالي. المصدر: Maine Revised Statutes Title 29-A, §2390."},"19":{"q":"بموجب قانون ولاية مين، أي فئة من CDL مطلوبة لتشغيل أي مجموعة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) يبلغ 26,001 pounds أو أكثر، حيث تتجاوز المركبة (المركبات) المقطورة 10,000 pounds من تصنيف الوزن الإجمالي للمركبة (GVWR)؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تعرّف ولاية مين Class A بأنها أي مجموعة من المركبات بتصنيف GCWR يبلغ 26,001 رطل أو أكثر، شريطة أن يتجاوز تصنيف GVWR/الوزن الإجمالي للمركبة (المركبات) المقطورة 10,000 pounds. المصدر: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"20":{"q":"يشغّل سائق في ولاية مين شاحنة مستقيمة واحدة بتصنيف وزن إجمالي للمركبة يبلغ 30,000 pounds ولا يقطر أي مقطورة. أي فئة CDL يتطلبها ذلك؟","options":["Class A","Class B","Class C","لا يلزم CDL"],"explanation":"تشمل Class B في ولاية مين أي مركبة واحدة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، أو مركبة كهذه تقطر وحدة لا تزيد عن 10,000 pounds. وحدة واحدة بوزن 30,000-pound تندرج ضمن Class B. المصدر: Maine CDL Manual, 'Definitions of Classes'; 29-A MRSA §1253."},"21":{"q":"في ولاية مين، المركبة التي لا تستوفي تعريفات الوزن للفئة A أو B لكنها مصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق)، أو تنقل مواد خطرة تتطلب لوحات تحذيرية، تندرج ضمن أي فئة CDL؟","options":["Class A","Class B","Class C","Class M"],"explanation":"Class C في ولاية مين هي أي مركبة واحدة أو مركبة مركّبة لا تستوفي شروط Class A/B ومصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق) أو تنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: Maine CDL Manual, 'Definitions of Classes' and Figure 1.1; 29-A MRSA §1253."},"22":{"q":"وفقًا لدليل CDL لولاية مين، أي مصادقة مطلوبة لتشغيل المركبات التي تنقل مواد خطرة عندما يجب وضع لوحات تحذيرية على الحمولة بموجب لوائح DOT الفيدرالية؟","options":["مصادقة N","مصادقة H","مصادقة T","مصادقة X"],"explanation":"تستخدم ولاية مين مصادقة H لتشغيل المركبات التي تنقل مواد خطرة عندما يُشترط وضع لوحات تحذيرية عليها بموجب لائحة DOT الفيدرالية. تجمع مصادقة X بين الصهريج (N) والمواد الخطرة (H). المصدر: Maine CDL Manual, 'Endorsements.'"},"23":{"q":"على CDL في ولاية مين، ماذا تخوّل مصادقة 'X'؟","options":["تشغيل مركبات الصهاريج فقط","تشغيل مركبات الصهاريج التي تنقل مواد خطرة (تجمع بين N و H)","تشغيل المقطورات المزدوجة والثلاثية","تشغيل حافلات الركاب التي تزيد عن 15 راكبًا"],"explanation":"مصادقة X في ولاية مين مخصصة لتشغيل مركبات الصهاريج التي تنقل مواد خطرة، وتجمع بين مصادقتي N (الصهريج) و H (المواد الخطرة) في مصادقة واحدة. المصدر: Maine CDL Manual, 'Endorsements.'"},"24":{"q":"يشير دليل CDL لولاية مين إلى قيد محدد يتعلق بمصادقة 'T' (المقطورات المزدوجة/الثلاثية). أي عبارة صحيحة بالنسبة لولاية مين؟","options":["يجوز تشغيل المقطورات المزدوجة والثلاثية بحرية في جميع أنحاء الولاية","المقطورات الثلاثية غير مسموح بها في ولاية مين","تخوّل مصادقة T أيضًا مركبات الصهاريج","تتطلب المقطورات المزدوجة اختبار ركاب منفصلاً"],"explanation":"يصف دليل CDL لولاية مين مصادقة T بأنها للمقطورات المزدوجة/الثلاثية 'حيثما يسمح القانون' وينص بوضوح على أن المقطورات الثلاثية غير مسموح بها في ولاية مين. المصدر: Maine CDL Manual, 'Endorsements.'"},"25":{"q":"وفقًا لدليل CDL لولاية مين، تُشترط مصادقة N (مركبة الصهريج) لنقل سائل أو غاز سائل في صهريج شحن مثبّت بشكل دائم بسعة لا تقل عن أي حد أدنى؟","options":["100 gallons or more","119 gallons or more","1,000 gallons or more","450 gallons or more"],"explanation":"تشترط ولاية مين اختبار/مصادقة الصهريج (N) لنقل سائل أو غاز سائل في صهريج شحن مثبّت بشكل دائم بسعة 119 gallons or more، أو صهريج محمول بسعة 1,000 gallons or more. المصدر: Maine CDL Manual, '1.1.1 Knowledge Tests' and tank vehicle section."},"26":{"q":"في ولاية مين، التأهل بنجاح لأي مصادقة يكسب أيضًا تلقائيًا مصادقة 'P' (الركاب) دون رسوم إضافية أو فحص آخر؟","options":["H (Hazardous Materials)","N (Tank Vehicle)","S (School Bus)","T (Doubles/Triples)"],"explanation":"ينص دليل CDL لولاية مين على أن التأهل بنجاح لمصادقة S (الحافلة المدرسية) يكسب أيضًا مصادقة P (الركاب) دون رسوم إضافية أو فحص آخر. المصدر: Maine CDL Manual, 'Endorsements.'"},"27":{"q":"وفقًا لدليل CDL لولاية مين، أي المصادقات تُمنح عند اجتياز اختبار المعرفة (الكتابي) فقط، دون الحاجة إلى اختبار مهارات منفصل؟","options":["P and S","N, H, X, and T","Only H","تتطلب جميع المصادقات اختبار مهارات"],"explanation":"ينص دليل CDL لولاية مين على أن مصادقات N و H و X و T تُمنح لحامل CDL عند إتمام فحص المعرفة فقط بنجاح؛ بينما تتطلب P و S الاختبار الكامل بما في ذلك اختبار المهارات. المصدر: Maine CDL Manual, 'Endorsements.'"},"28":{"q":"تعترف ولاية مين بمصادقة '3' لنوع واحد من تشغيل الحافلات المدرسية لا يتطلب من السائق حمل CDL. تلك الحافلة مصممة لنقل كم راكبًا؟","options":["16 راكبًا أو أكثر بمن فيهم السائق","15 راكبًا أو أقل بمن فيهم السائق","24 راكبًا بالضبط","أكثر من 15 راكبًا باستثناء السائق"],"explanation":"يصف دليل CDL لولاية مين مصادقة '3' لحافلة مدرسية مصممة لنقل 15 راكبًا أو أقل (بمن فيهم السائق)؛ ويمكن إلحاقها برخصة غير تجارية ولا تتطلب CDL. المصدر: Maine CDL Manual, '\"3\" endorsement.'"},"29":{"q":"بموجب قواعد CDL لولاية مين، ما هو الحد الأدنى للسن لتشغيل مركبة آلية تجارية في التجارة داخل الولاية (ضمن ولاية مين فقط)؟","options":["16 years","18 years","21 years","19 years"],"explanation":"الحد الأدنى لسن CDL داخل الولاية في ولاية مين هو 18. (يشير النص الأقدم في دليل CDL لولاية مين إلى سن 16 لبعض العمليات داخل الولاية، لكن BMV يطبق الحد الأدنى الفيدرالي البالغ 18 لتشغيل CDL داخل الولاية.) المصدر: Maine BMV / FMCSA 49 CFR 391.11; Maine CDL Manual age provisions."},"30":{"q":"ما هو الحد الأدنى للسن في ولاية مين للحصول على CDL صالح للتجارة بين الولايات (عبور حدود الولايات)؟","options":["18 years","19 years","21 years","25 years"],"explanation":"يجب أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات، أو لنقل مواد خطرة، أو لقيادة حافلة ركاب. المصدر: Maine CDL Manual age provisions; FMCSA 49 CFR 391.11."},"31":{"q":"بموجب 29-A MRSA §1304(4-A)، لا يحق لحامل تصريح متعلم تجاري (CLP) في ولاية مين الخضوع لاختبار مهارات CDL خلال أي فترة بعد الإصدار الأولي للتصريح؟","options":["أول 7 days","أول 14 days","أول 30 days","أول 60 days"],"explanation":"ينص قانون ولاية مين على أنه لا يحق لحامل CLP الخضوع لاختبار مهارات CDL في أول 14 days بعد الإصدار الأولي لـ CLP، بما يطابق المتطلب الفيدرالي. المصدر: 29-A MRSA §1304(4-A)(I)."},"32":{"q":"بموجب 29-A MRSA §1304، يكون تصريح المتعلم التجاري (CLP) في ولاية مين صالحًا لمدة لا تزيد عن كم من تاريخ الإصدار؟","options":["180 days","One year","Two years","Five years"],"explanation":"ينص قانون ولاية مين على أن تصريح المتعلم التجاري صالح لمدة لا تزيد عن عام واحد من تاريخ الإصدار. المصدر: 29-A MRSA §1304(4-A)(G)."},"33":{"q":"أثناء تشغيل مركبة آلية تجارية بموجب تصريح متعلم تجاري في ولاية مين، يجب أن يرافق حامل CLP حاملُ CDL يكون متمركزًا أين؟","options":["في أي مكان داخل المركبة","يتبعه في مركبة منفصلة","حاضرًا جسديًا في المقعد الأمامي بجوار حامل CLP (أو، في مركبة ركاب، مباشرة خلف السائق أو في الصف الأول خلفه)","متاحًا عبر الهاتف أثناء التشغيل"],"explanation":"يشترط قانون ولاية مين أن يكون حامل CDL المرافق حاضرًا جسديًا في المقعد الأمامي بجوار حامل CLP، أو في مركبة ركاب مباشرة خلف السائق أو في الصف الأول خلفه، مع الفئة والمصادقات المناسبة. المصدر: 29-A MRSA §1304(4-A)(A)."},"34":{"q":"أي نشاط محظور صراحةً على حامل تصريح متعلم تجاري في ولاية مين بموجب 29-A MRSA §1304(4-A)؟","options":["تشغيل مركبة آلية تجارية تنقل مواد خطرة","القيادة خلال ساعات النهار","تشغيل مركبة Class B","التدرّب على الطرق السريعة بين الولايات"],"explanation":"يحظر قانون ولاية مين على حامل CLP تشغيل مركبة آلية تجارية تنقل مواد خطرة كما هي معرّفة في 49 CFR §383.5. المصدر: 29-A MRSA §1304(4-A)(F)."},"35":{"q":"بموجب 29-A MRSA §1304(4-A)، ما هو الحد الأدنى للسن الذي يجب أن يبلغه حامل CLP في ولاية مين للتقدم بطلب مصادقة ركاب (P) أو حافلة مدرسية (S)؟","options":["18 years","20 years","21 years","22 years"],"explanation":"يشترط قانون ولاية مين أن يكون عمر حامل CLP 21 عامًا على الأقل للتقدم بطلب مصادقة ركاب أو حافلة مدرسية، ويجب أن يحمل حامل CDL المرافق مصادقة ركاب، ولديه خبرة عام واحد على الأقل، وعمره 22 على الأقل. المصدر: 29-A MRSA §1304(4-A)(E)."},"36":{"q":"متطلب تدريب السائق المبتدئ (ELDT) المطبق على المتقدمين الجدد لـ CDL في ولاية مين يتم التحقق منه من خلال أي نظام؟","options":["بوابة Maine BMV عبر الإنترنت","FMCSA Training Provider Registry (TPR)","National Driver Register","TSA Secure Flight database"],"explanation":"اعتبارًا من February 7, 2022، تشترط قاعدة ELDT الصادرة عن FMCSA تدريب مشغّلي CDL الجدد وبعض الترقيات، على أن يُكمَل لدى مزوّد مدرج ومسجّل لدى FMCSA Training Provider Registry (tpr.fmcsa.dot.gov). المصدر: Maine CDL Manual, 'Entry Level Driver Training (ELDT)'; FMCSA 49 CFR Part 380."},"37":{"q":"عند التقدم بطلب CDL في ولاية مين، يجب على المتقدم أن يقرّ ذاتيًا بنوع واحد من عمليات القيادة. أي مجموعة تسرد بشكل صحيح الفئات الفيدرالية الأربع للإقرار الذاتي المستخدمة في ولاية مين؟","options":["محلية، وإقليمية، ووطنية، ودولية","بين الولايات غير معفاة، وبين الولايات معفاة، وداخل الولاية غير معفاة، وداخل الولاية معفاة","تجارية، وخاصة، وزراعية، وطارئة","عمليات Class A و Class B و Class C و Class D"],"explanation":"تشترط ولاية مين، اتباعًا لـ 49 CFR §383.71، على المتقدمين لـ CDL أن يقرّوا ذاتيًا بإحدى الفئات الأربع: بين الولايات غير معفاة، أو بين الولايات معفاة، أو داخل الولاية غير معفاة، أو داخل الولاية معفاة. تتطلب الفئات غير المعفاة شهادة فاحص طبي سارية. المصدر: FMCSA 49 CFR §383.71; Maine BMV."},"38":{"q":"بخلاف وثائق الهوية والإقامة والوجود القانوني، أي عنصر إضافي يجب على المتقدم لـ CDL في ولاية مين الإفصاح عنه، وفقًا لما يفرضه 29-A MRSA لإصدار رخصة القيادة؟","options":["رقم جواز سفر","رقم الضمان الاجتماعي (Social Security number)","بطاقة تسجيل ناخب","سند ملكية مركبة"],"explanation":"يشير بيان الإفصاح عن رقم الضمان الاجتماعي في دليل CDL لولاية مين إلى أن الإفصاح عن SSN إلزامي ومطلوب بموجب 29-A MRSA للتقدم بطلب رخصة قيادة أو تجديدها؛ كما يشترط BMV إثبات الهوية والإقامة في ولاية مين والوجود القانوني. المصدر: Maine CDL Manual, 'Social Security Number Disclosure Statement'; 29-A MRSA."},"39":{"q":"بموجب قواعد CDL لولاية مين، عند أي تركيز للكحول في الدم (BAC) يكون من غير القانوني تشغيل مركبة آلية تجارية؟","options":["0.04% or more","0.08% or more","0.02% or more","0.10% or more"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنه من غير القانوني تشغيل مركبة آلية تجارية إذا كان BAC لديك .04% or more. هذا الحد البالغ 0.04 هو نصف الحد البالغ 0.08 للسائقين العاديين ويطابق المعيار الفيدرالي 49 CFR 383.51."},"40":{"q":"بتشغيل مركبة آلية تجارية في ولاية مين، يُعتبر السائق قانونيًا أنه قد فعل ماذا؟","options":["تنازل عن الحق في محامي دفاع","أعطى موافقته على اختبار الكحول","وافق على تفتيش المركبة في أي وقت","وافق على فحص بول عشوائي للمخدرات أسبوعيًا"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على: 'إذا قمت بتشغيل مركبة آلية تجارية، فإنك تُعتبر قد أعطيت موافقتك على اختبار الكحول.' هذه هي قاعدة الموافقة الضمنية في ولاية مين لتشغيل المركبات الآلية التجارية (انظر أيضًا 29-A M.R.S. 2521)."},"41":{"q":"بالنسبة لمخالفة كبرى أولى (مثل قيادة مركبة آلية تجارية بـ BAC يبلغ .04% أو أعلى)، كم من الوقت سيفقد سائق ولاية مين CDL الخاص به؟","options":["At least 60 days","At least 6 months","At least 1 year","At least 90 days"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنك ستفقد CDL لمدة عام واحد على الأقل لمخالفة كبرى أولى، بما في ذلك قيادة مركبة آلية تجارية بـ BAC يبلغ .04% أو أعلى. هذا يطابق المعيار الفيدرالي 49 CFR 383.51."},"42":{"q":"في ولاية مين، ماذا يحدث لحامل CDL الذي يرفض الخضوع لاختبار الكحول في الدم عندما يكون مطلوبًا أثناء تشغيل مركبة آلية تجارية (المخالفة الأولى)؟","options":["تحذير دون فقدان الأهلية","فقدان CDL لمدة 30 days","فقدان CDL لمدة 120 days","فقدان CDL لمدة عام واحد على الأقل"],"explanation":"يدرج دليل CDL لولاية مين (Section 1.2.2) 'رفض الخضوع لاختبار الكحول في الدم' كمخالفة كبرى أولى، تترتب عليها خسارة CDL لمدة عام واحد على الأقل (3 سنوات إذا كانت تحمل لوحات تحذيرية لمواد خطرة)."},"43":{"q":"إذا وقعت مخالفة كبرى أولى (مثل القيادة تحت تأثير الكحول) بينما يشغّل سائق ولاية مين مركبة آلية تجارية تحمل لوحات تحذيرية لمواد خطرة، يُفقَد CDL لمدة لا تقل عن كم؟","options":["3 years","1 year","5 years","مدى الحياة"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنك ستفقد CDL لمدة ثلاث سنوات على الأقل إذا وقعت مخالفة كبرى أولى أثناء تشغيلك مركبة آلية تجارية تحمل لوحات تحذيرية لمواد خطرة، وفقًا لـ 49 CFR 383.51."},"44":{"q":"ما هي العاقبة في ولاية مين لمخالفة كبرى ثانية (مثل قيادة ثانية تحت تأثير الكحول في مركبة آلية تجارية)؟","options":["فقدان CDL لمدة 10 years","فقدان CDL مدى الحياة","فقدان CDL لمدة 3 years","فقدان CDL لمدة 5 years"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنك ستفقد CDL مدى الحياة لمخالفة كبرى ثانية. يتبع فقدان الأهلية مدى الحياة هذا المعيار الفيدرالي 49 CFR 383.51."},"45":{"q":"بموجب قواعد ولاية مين، ما هي عقوبة استخدام مركبة آلية تجارية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة؟","options":["فقدان CDL لمدة سنة واحدة","فقدان CDL لمدة 3 سنوات","فقدان CDL مدى الحياة","فقدان CDL لمدة 120 days"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنك ستفقد CDL مدى الحياة إذا استخدمت مركبة آلية تجارية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة. لا توجد إمكانية لإعادة الترخيص لهذه المخالفة."},"46":{"q":"في ولاية مين، السائق الذي لديه كمية قابلة للكشف من الكحول أقل من .04% أثناء تشغيل مركبة آلية تجارية سيُعامَل بـ:","options":["فقدان الأهلية لمدة 60 days","غرامة قدرها $5,000","الاعتقال تلقائيًا بتهمة القيادة تحت تأثير الكحول (OUI)","إخراجه من الخدمة لمدة 24 ساعة"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.2) على أنه سيتم إخراجك من الخدمة لمدة 24 ساعة إذا كانت لديك أي كمية قابلة للكشف من الكحول أقل من .04%. ويتطلب فقدان الأهلية الكامل BAC يبلغ .04% أو أكثر."},"47":{"q":"أي مما يلي يُصنَّف على أنه 'مخالفة مرورية خطيرة' في دليل CDL لولاية مين؟","options":["السرعة المفرطة (15 mph أو أكثر فوق الحد المعلن)","القيادة بسرعة 5 mph فوق الحد المعلن","تسجيل مركبة منتهي الصلاحية","مخالفة وقوف واحدة"],"explanation":"يعرّف دليل CDL لولاية مين (Section 1.2.3) السرعة المفرطة بأنها 15 mph أو أكثر فوق الحد المعلن، ويدرجها كمخالفة مرورية خطيرة إلى جانب القيادة المتهورة، وتغييرات الحارة غير السليمة، والاقتراب المفرط من المركبة الأمامية."},"48":{"q":"كم من الوقت سيفقد سائق ولاية مين CDL الخاص به لارتكاب مخالفتين مروريتين خطيرتين في مركبة آلية تجارية خلال فترة ثلاث سنوات؟","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.3) على أنك ستفقد CDL لمدة 60 days على الأقل لمخالفتين مروريتين خطيرتين خلال فترة ثلاث سنوات تتضمن مركبة آلية تجارية، وفقًا لـ 49 CFR 383.51."},"49":{"q":"كم من الوقت سيفقد سائق ولاية مين CDL الخاص به لارتكاب ثلاث مخالفات مرورية خطيرة أو أكثر في مركبة آلية تجارية خلال فترة ثلاث سنوات؟","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.3) على أنك ستفقد CDL لمدة 120 days على الأقل لثلاث مخالفات مرورية خطيرة أو أكثر خلال فترة ثلاث سنوات تتضمن مركبة آلية تجارية، وفقًا لـ 49 CFR 383.51."},"50":{"q":"أي من هذه مدرج ضمن المخالفات المرورية الخطيرة في دليل CDL لولاية مين؟","options":["عدم استخدام إشارة الانعطاف في موقف سيارات","القيادة بمصباح أمامي واحد معطّل","حمل حمولة غير مثبّتة أقل من 500 pounds","قيادة مركبة آلية تجارية دون الحصول على CDL أو دون حيازته"],"explanation":"يدرج دليل CDL لولاية مين (Section 1.2.3) قيادة مركبة آلية تجارية دون الحصول على CDL، أو دون حيازة CDL، أو دون الفئة/المصادقات المناسبة كمخالفات مرورية خطيرة."},"51":{"q":"بموجب القواعد الفيدرالية المعتمدة في ولاية مين، تُعامَل الكتابة عبر الرسائل أثناء قيادة مركبة آلية تجارية واستخدام هاتف محمول يدوي على أنهما:","options":["مخالفات مرورية خطيرة","مخالفات كبرى مع فقدان أهلية لمدة سنة واحدة","مخالفات أمر إخراج من الخدمة","مخالفات لا تؤدي إلى فقدان الأهلية"],"explanation":"وفقًا لـ 49 CFR 383.51، تُعد الكتابة عبر الرسائل (49 CFR 392.80) واستخدام الهاتف المحمول اليدوي (49 CFR 392.82) أثناء قيادة مركبة آلية تجارية مخالفات مرورية خطيرة. اثنتان خلال ثلاث سنوات تؤديان إلى فقدان أهلية لمدة 60 days؛ وثلاث تؤدي إلى 120 days. تعتمد ولاية مين هذه المعايير الفيدرالية."},"52":{"q":"بموجب قواعد الهاتف اليدوي الفيدرالية التي تنطبق على سائقي CDL في ولاية مين، يمكن أن تترتب على إدانة واحدة بالكتابة عبر الرسائل أو استخدام الهاتف اليدوي أيضًا غرامة مدنية على السائق تصل إلى:","options":["$500","$2,750","$11,000","$250"],"explanation":"بموجب قواعد FMCSA (49 CFR 392.80/392.82) المطبقة في ولاية مين، يواجه السائق غرامة مدنية تصل إلى $2,750 عن كل مخالفة كتابة عبر الرسائل أو استخدام هاتف يدوي؛ ويواجه أصحاب العمل الذين يسمحون بذلك غرامات تصل إلى $11,000. كما تؤدي إدانتان من هذا النوع خلال 3 سنوات إلى فقدان أهلية CDL لمدة 60 days."},"53":{"q":"وفقًا لدليل CDL لولاية مين، كم من الوقت سيفقد السائق CDL الخاص به لمخالفة أولى لأمر إخراج من الخدمة؟","options":["At least 60 days","At least 30 days","At least 90 days","At least 1 year"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.4) على أنك ستفقد CDL لمدة 90 days على الأقل لمخالفة أولى لأمر إخراج من الخدمة. (يحدد المعيار الفيدرالي الحالي 49 CFR 383.51 Table 4 حدًا أدنى يبلغ 180-day، لكن دليل ولاية مين المنشور ينص على 90 days.)"},"54":{"q":"وفقًا لدليل CDL لولاية مين، كم من الوقت سيفقد السائق CDL الخاص به لمخالفتين لأمر إخراج من الخدمة خلال فترة عشر سنوات؟","options":["At least 90 days","At least 6 months","At least 3 years","At least 1 year"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.4) على أنك ستفقد CDL لمدة عام واحد على الأقل لمخالفتين لأمر إخراج من الخدمة خلال فترة عشر سنوات. وتؤدي مخالفة ثالثة خلال عشر سنوات إلى ثلاث سنوات على الأقل."},"55":{"q":"وفقًا لدليل CDL لولاية مين، كم من الوقت سيفقد السائق CDL الخاص به لثلاث مخالفات أو أكثر لأمر إخراج من الخدمة خلال فترة عشر سنوات؟","options":["At least 3 years","At least 1 year","مدى الحياة","At least 120 days"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.4) على أنك ستفقد CDL لمدة ثلاث سنوات على الأقل لثلاث مخالفات أو أكثر لأمر إخراج من الخدمة خلال فترة عشر سنوات."},"56":{"q":"بموجب دليل CDL لولاية مين، كم من الوقت سيفقد السائق CDL الخاص به لمخالفة أولى لمعبر السكة الحديدية مع الطريق السريع؟","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.5) على أنك ستفقد CDL لمدة 60 days على الأقل لمخالفة أولى لمعبر السكة الحديدية مع الطريق السريع، وفقًا لـ 49 CFR 383.51."},"57":{"q":"بموجب دليل CDL لولاية مين، ما هو فقدان الأهلية لمخالفة ثالثة لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات؟","options":["At least 120 days","At least 60 days","At least 1 year","At least 90 days"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.5) على أنك ستفقد CDL لمدة عام واحد على الأقل لمخالفة ثالثة لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات (الأولى 60 days، والثانية 120 days)."},"58":{"q":"في ولاية مين، إذا تم إلغاء أو سحب أو تعليق امتياز قيادة المركبة الشخصية لحامل CDL بسبب مخالفة تتعلق بالكحول أو المواد الخاضعة للرقابة أو جناية، فماذا يحدث لـ CDL؟","options":["لا تأثير، لأنها وقعت في مركبة شخصية","فقدان CDL لمدة 60 days فقط","فقدان أهلية فوري مدى الحياة عند المخالفة الأولى","فقدان CDL لمدة سنة واحدة (مدى الحياة لمخالفة ثانية من هذا النوع)"],"explanation":"ينص دليل CDL لولاية مين (Section 1.2.7)، بما يعكس قانون تحسين سلامة الناقلين الآليين (Motor Carrier Safety Improvement Act)، على أنه إذا تم إلغاء/سحب/تعليق امتياز مركبتك الشخصية بسبب مخالفات تتعلق بالكحول أو المواد الخاضعة للرقابة أو جناية، فإنك تفقد CDL لمدة سنة واحدة، ومدى الحياة لمخالفة ثانية من هذا النوع. ولا يتوفر CDL للحالات الاضطرارية."},"59":{"q":"بموجب قانون \"التنحّي جانباً\" (Move Over) في ولاية ماين، عندما تقترب من مركبة طوارئ أو خدمة متوقفة تعرض أضواءً وامضة على طريق متعدد المسارات، ما هو أول إجراء مطلوب منك إذا أمكن القيام به بأمان؟","options":["الانتقال من المسار المجاور للمركبة المتوقفة إلى مسار غير مجاور","التوقف تماماً حتى تغادر مركبة الطوارئ موقع الحادث","إطلاق المنبّه ومتابعة السير بحد السرعة المعلن","الانعطاف نحو الكتف الأيمن والانتظار حتى يُشار إليك بالمرور"],"explanation":"يتطلب قانون \"التنحّي جانباً\" في ماين (29-A MRSA Sec. 2054(9)، وSec. 2070(8) للمركبات المتوقفة/المعطلة) من السائق المرور في مسار غير مجاور للمركبة المتوقفة إن أمكن؛ وفقط إذا كان تغيير المسار مستحيلاً أو غير آمن يجوز لك المرور بسرعة منخفضة بحذر وتعقّل. المصدر: Maine Revised Statutes Title 29-A Sec. 2054 / Sec. 2070."},"60":{"q":"على طريق ذي مسارين حيث يكون الانتقال إلى مسار غير مجاور مستحيلاً، ماذا يتطلب قانون \"التنحّي جانباً\" في ماين من السائق الذي يتجاوز مركبة طوارئ أو مركبة معطلة متوقفة؟","options":["التوقف الكامل قبل تجاوز المركبة","الحفاظ على الأقل على حد السرعة الأدنى المعلن","المرور بسرعة حذرة وتعقّلية معقولة لتجاوز المركبة بأمان","تخفيف السرعة إلى 20 mph بالضبط دون الحد المعلن"],"explanation":"عندما يكون تغيير المسار غير ممكن أو غير آمن، يتطلب 29-A MRSA Sec. 2070(8)(B) (وSec. 2054) المرور بـ \"سرعة حذرة وتعقّلية معقولة لتجاوز المركبة بأمان\". ولا تحدد ماين قيمة mph دقيقة. المصدر: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"61":{"q":"جرى توسيع قانون \"التنحّي جانباً\" في ماين عام 2023. بالإضافة إلى مركبات الطوارئ ومركبات الخدمة العامة المرخّصة، فإن واجب التنحّي جانباً أو تخفيف السرعة ينطبق الآن أيضاً عند تجاوز:","options":["فقط سيارات الشرطة المميَّزة وسيارات الإسعاف","أي مركبة متوقفة يستنتج شخص عاقل أنها معطلة أو أنها تستخدم أضواءً وامضة","فقط شاحنات القطر ومركبات صيانة الطرق السريعة","فقط المركبات التي تعرض رايةً تحذيرية حمراء"],"explanation":"يوسّع 29-A MRSA Sec. 2070(8)، الذي سُنّ بموجب PL 2023 c. 122، واجب التنحّي جانباً/تخفيف السرعة ليشمل أي مركبة متوقفة يستنتج شخص عاقل أنها معطلة أو أنها تستخدم أضواءً وامضة للتحذير من وجودها. المصدر: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"62":{"q":"ما هو الحد الأدنى للغرامة المحكوم بها عند مخالفة شرط التنحّي جانباً / تجاوز مركبة متوقفة في ماين؟","options":["$135","$500","$1,000","$275"],"explanation":"ينص 29-A MRSA Sec. 2070(8) على أن المخالفة تُعدّ مخالفة مرورية يجب أن يُحكم فيها بغرامة لا تقل عن $275. المصدر: Maine Revised Statutes Title 29-A Sec. 2070(8)."},"63":{"q":"عندما يحتوي معبر سكة حديد في ماين على علامة صليبية (cross-buck) بدون خط توقف أبيض مطلي، فإن مركبة محمّلة بمواد خطرة موسومة بلوحة أو حافلة مُلزمة بالتوقف يجب أن تتوقف ضمن أي مسافة من أقرب قضيب؟","options":["لا تقل عن 15 feet ولا تزيد عن 50 feet","لا تقل عن 5 feet ولا تزيد عن 25 feet","لا تقل عن 25 feet ولا تزيد عن 75 feet","لا تقل عن 10 feet ولا تزيد عن 100 feet"],"explanation":"يتطلب 29-A MRSA Sec. 2076(3) من الحافلات التي تنقل ركاباً ومن المركبات الموسومة بلوحات/علامات للمواد الخطرة وصهاريج الشحن التوقف على مسافة لا تقل عن 15 feet ولا تزيد عن 50 feet من أقرب قضيب. وينص دليل CDL في ماين (Sec. 2.15) على النطاق نفسه من 15 إلى 50 feet. المصدر: Maine Revised Statutes Title 29-A Sec. 2076؛ Maine CDL Manual."},"64":{"q":"عند أي من معابر السكك الحديدية التالية لا يُطلب من حافلة أو مركبة موسومة بمواد خطرة في ماين التوقف؟","options":["أي معبر يقع خارج منطقة تجارية","معبر فيه أضواء حمراء وامضة غير مُفعَّلة","معبر قضبان تُستخدم حصرياً للمناورة الصناعية، أو معبر مُعلَّم بإشارة \"معفى\" (exempt)","أي معبر على طريق معلن عليه 45 mph أو أقل"],"explanation":"يسرد 29-A MRSA Sec. 2076 استثناءات من التوقف الإلزامي، بما في ذلك معابر عربات الترام، والقضبان المستخدمة حصرياً للمناورة الصناعية، وعند توجيهك بالمرور من قبل ضابط أو مُنظّم مرور، والمعابر المهجورة الموسومة بذلك، والمعابر المعلَّمة بإشارة \"معفى\" (exempt). المصدر: Maine Revised Statutes Title 29-A Sec. 2076."},"65":{"q":"يوجّه قانون ماين (29-A Sec. 2306) مشغّل الحافلة المدرسية الذي يقترب من معبر سكة حديد عند مستوى سطح الأرض إلى التوقف الكامل ثم القيام بماذا قبل العبور؟","options":["الانتظار 30 ثانية كاملة بغض النظر عن الظروف","إطلاق المنبّه مرتين ثم المتابعة","إنزال أحد الركاب ليعمل كمنظّم مرور","التأكد بما لا يدع مجالاً للشك المعقول من عدم اقتراب أي قطار على القضيب"],"explanation":"يتطلب 29-A MRSA Sec. 2306 من مشغّل الحافلة المدرسية التوقف الكامل (على مسافة لا تزيد عن 50 feet ولا تقل عن 15 feet من أقرب قضيب) والتأكد بما لا يدع مجالاً للشك المعقول من عدم اقتراب أي قطار أو قاطرة أو وسيلة نقل قبل العبور. المصدر: Maine Revised Statutes Title 29-A Sec. 2306."},"66":{"q":"تتوقف حافلة مدرسية في ماين على طريق ذي مسارين وأضواؤها الحمراء وامضة لإنزال الركاب. ماذا يجب على سائق مركبة قادمة من الاتجاه المعاكس أن يفعل؟","options":["التباطؤ إلى 15 mph والمرور بحذر","إيقاف المركبة قبل الوصول إلى الحافلة وعدم المتابعة حتى تتحرك الحافلة أو تُعطي إشارة","المتابعة بشكل طبيعي لأن حركة المرور المقابلة معفاة","التوقف فقط إذا كان الأطفال يعبرون الطريق بشكل ظاهر"],"explanation":"يتطلب 29-A MRSA Sec. 2308(2) من مشغّل مركبة تلتقي بحافلة مدرسية أو تتجاوزها من أي اتجاه، عندما تكون الحافلة متوقفة وأضواؤها الحمراء وامضة، التوقف قبل الوصول إلى الحافلة وعدم المتابعة حتى تستأنف الحافلة الحركة أو يُعطي المشغّل إشارة. المصدر: Maine Revised Statutes Title 29-A Sec. 2308(2)."},"67":{"q":"بموجب قانون الحافلات المدرسية في ماين، على أي نوع من الطرق لا يحتاج السائق إلى التوقف لحافلة مدرسية متوقفة على الجانب الآخر؟","options":["طريق مفصول برصيف أو حاجز مادي آخر، بالنسبة لحافلة في مسار مفصول بذلك الحاجز","أي طريق فيه خط مركزي أصفر مزدوج مطلي","أي طريق فيه مساران أو أكثر في كل اتجاه","أي طريق معلن عليه حد 50 mph أو أعلى"],"explanation":"يُعفي 29-A MRSA Sec. 2308(3) السائق من التوقف فقط عندما يكون الطريق مفصولاً برصيف أو حاجز مادي آخر (بالنسبة لحافلة في مسار مفصول بذلك الحاجز)، أو على طريق سريع محدود الوصول حيث لا يجوز للمشاة العبور. والخط المطلي وحده لا يُنشئ هذا الاستثناء. المصدر: Maine Revised Statutes Title 29-A Sec. 2308(3)."},"68":{"q":"تتطلب ماين من مشغّل الحافلة المدرسية تفعيل أضواء التحذير الوامضة للحافلة قبل التوقف لاستقبال الركاب أو إنزالهم بأي مسافة على الأقل؟","options":["50 feet","200 feet","300 feet","100 feet"],"explanation":"يتطلب 29-A MRSA Sec. 2308(1) من مشغّل الحافلة المدرسية تفعيل الأضواء الوامضة قبل التوقف بمسافة لا تقل عن 100 feet لاستقبال الركاب أو إنزالهم، والإبقاء عليها معروضة حتى يتم استقبال الركاب أو إنزالهم. المصدر: Maine Revised Statutes Title 29-A Sec. 2308(1)."},"69":{"q":"في ماين، يُصنَّف تجاوز حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة بشكل غير قانوني على أنه ماذا، وما عقوبة المخالفة الأولى؟","options":["مخالفة مرورية بسيطة بغرامة $135","مخالفة مدنية بدون غرامة للمخالفة الأولى","جريمة من الفئة E (Class E) بغرامة حد أدنى $250","جريمة من الفئة C (Class C) مع حكم سجن إلزامي"],"explanation":"يجعل 29-A MRSA Sec. 2308(6) مخالفة الفقرة الفرعية 2 جريمة من الفئة E (Class E) يُعاقب عليها بغرامة حد أدنى $250 للمخالفة الأولى، مع تعليق إلزامي للرخصة لمدة 30 يوماً لمخالفة ثانية خلال 3 سنوات. المصدر: Maine Revised Statutes Title 29-A Sec. 2308(6)."},"70":{"q":"في غياب الإشارات المعلنة، ما الحد الأقصى للسرعة الذي يحدده قانون ماين في منطقة تجارية أو سكنية؟","options":["20 mph","25 mph","30 mph","35 mph"],"explanation":"يحدد 29-A MRSA Sec. 2074(1) حدوداً قصوى افتراضية تبلغ 15 mph في منطقة مدرسية، و25 mph في منطقة تجارية أو سكنية أو قسم مبنيّ، و45 mph على جميع الطرق العامة الأخرى، كلٌّ منها \"ما لم يُعلن خلاف ذلك\". المصدر: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"71":{"q":"بموجب حدود السرعة القانونية الافتراضية في ماين (حيث لا يُعلن أي حد آخر)، ما الحد الأقصى للسرعة على \"جميع الطرق العامة الأخرى\"؟","options":["55 mph","50 mph","40 mph","45 mph"],"explanation":"يحدد 29-A MRSA Sec. 2074(1) الحد الأقصى الافتراضي بـ 45 mph على جميع الطرق العامة الأخرى ما لم يُعلن خلاف ذلك (المنطقة التجارية/السكنية هي 25 mph؛ والمنطقة المدرسية هي 15 mph). ومعظم الطرق السريعة المرقّمة تحمل حدوداً معلنة أعلى. المصدر: Maine Revised Statutes Title 29-A Sec. 2074(1)."},"72":{"q":"ما الحد الأقصى للسرعة على طريق ماين السريع برسوم (Maine Turnpike / I-95) كما تحدده هيئة طريق ماين السريع (Maine Turnpike Authority)؟","options":["70 mph","65 mph","75 mph","80 mph"],"explanation":"تحدد قواعد هيئة طريق ماين السريع (Maine Turnpike Authority) الحد الأقصى العام للسرعة على الطريق السريع بـ 70 mph، مع حدود معلنة أدنى على بعض المقاطع الجنوبية والشمالية. المصدر: Maine Turnpike Authority Policies & Rules."},"73":{"q":"على المقاطع ذات الثلاثة مسارات من طريق ماين السريع جنوب علامة الميل 44 (Mile Marker 44)، أين يُسمح للشاحنات (بما في ذلك جرارات الشاحنات) بالسير؟","options":["فقط في المسار الواحد الأقصى يميناً","في أي مسار، بما في ذلك مسار التجاوز الأيسر","فقط في المسارين الأقصى يميناً","فقط في المسار الأوسط"],"explanation":"لتحسين جودة الهواء في جنوب ماين، تقيّد قواعد هيئة طريق ماين السريع الشاحنات (بما في ذلك جرارات الشاحنات، باستثناء البيك أب) بالمسارين الأقصى يميناً على أي مقطع من الطريق السريع جنوب علامة الميل 44 (Mile Marker 44) يحتوي على ثلاثة مسارات في كل اتجاه. المصدر: Maine Turnpike Authority Policies & Rules."},"74":{"q":"إذا اضطررت إلى إيقاف مركبة تجارية (CMV) على طريق باتجاه واحد أو طريق مقسوم في ماين أو بجانبه، يقول دليل CDL في ماين بوضع أجهزة التحذير الثلاثة على أي مسافات باتجاه حركة المرور القادمة؟","options":["10 feet و50 feet و150 feet","10 feet و100 feet و200 feet","25 feet و100 feet و300 feet","50 feet و100 feet و500 feet"],"explanation":"يوجّه دليل CDL في ماين (Sec. 2.5.1) إلى أنه عند التوقف على طريق باتجاه واحد أو طريق مقسوم أو بجانبه، توضع أجهزة التحذير على مسافات 10 feet و100 feet و200 feet باتجاه حركة المرور القادمة. المصدر: Maine CDL Manual, Section 2."},"75":{"q":"على طريق ماين سريع ذي مسارين (ثنائي الاتجاه غير مقسوم)، كيف يجب وضع أجهزة التحذير الثلاثة المطلوبة عند توقف مركبة تجارية (CMV)؟","options":["10 feet و100 feet و200 feet، جميعها خلف المركبة","على مسافات 50 feet و200 feet و300 feet خلف المركبة فقط","جهاز واحد ضمن 10 feet وجهازان على بُعد 500 feet خلف المركبة فقط","ضمن 10 feet من المركبة، و100 feet أمام المركبة و100 feet خلفها"],"explanation":"يوجّه دليل CDL في ماين (Sec. 2.5.2) إلى وضع جهاز ضمن 10 feet من المقدمة أو المؤخرة لتعليم المركبة، بالإضافة إلى جهاز واحد على بُعد 100 feet خلفها وجهاز واحد على بُعد 100 feet أمامها، على الكتف أو في المسار المشغول. المصدر: Maine CDL Manual, Section 2."},"76":{"q":"بعد إيقاف مركبة تجارية (CMV) على طريق في ماين، خلال كم دقيقة يجب أن تكون أجهزة التحذير في حالات الطوارئ موضوعة في مكانها؟","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"explanation":"ينص دليل CDL في ماين (Sec. 2.5.1) على أنه إذا اضطررت إلى التوقف على طريق أو كتف، يجب أن تضع أجهزة التحذير في حالات الطوارئ خلال عشر دقائق. المصدر: Maine CDL Manual, Section 2."},"77":{"q":"إذا توقفت مركبة تجارية (CMV) مباشرة بعد تلة أو منعطف في ماين، يقول دليل CDL في ماين إنه ينبغي إعادة وضع جهاز التحذير الخلفي بحيث:","options":["يُوضع على بُعد 200 feet بالضبط من المركبة بغض النظر عن المنعطف","يُزال لأن أضواء التحذير كافية","يُعطي السائقين تحذيراً على امتداد الطريق، بحيث تكون المركبة مرئية ضمن 500 feet","يُوضع على قمة التلة على بُعد 50 feet بالضبط أماماً"],"explanation":"يوجّه دليل CDL في ماين (Sec. 2.5.2) إلى أنه إذا حجبت تلة أو منعطف خط الرؤية، يُحرَّك المثلث الأبعد إلى الخلف على امتداد الطريق بحيث يُوفَّر تحذير ويتمكن السائقون الآخرون من رؤية المركبة ضمن 500 feet. المصدر: Maine CDL Manual, Section 2."},"78":{"q":"في ماين، إن حمولة تتجاوز أي بُعد تتطلب عادةً تصريح تجاوز الحدود (الحجم الزائد) من مكتب المركبات الآلية (Bureau of Motor Vehicles) / MaineDOT؟","options":["عرض أكبر من 10 feet 0 inches أو ارتفاع أكبر من 15 feet 0 inches","عرض أكبر من 8 feet 6 inches أو ارتفاع أكبر من 13 feet 6 inches","عرض أكبر من 8 feet 0 inches أو ارتفاع أكبر من 12 feet 0 inches","عرض أكبر من 9 feet 0 inches أو ارتفاع أكبر من 14 feet 6 inches"],"explanation":"تتبع ماين الحدود القانونية القياسية البالغة 8 feet 6 inches عرضاً و13 feet 6 inches ارتفاعاً؛ والحمولات التي تتجاوز هذه الحدود تتطلب تصريح تجاوز الحدود (الحجم الزائد) الصادر عبر برنامج تصاريح تجاوز الحدود لدى Maine BMV/MaineDOT. المصدر: Maine BMV Overlimit Permits / MaineDOT."},"79":{"q":"أي وكالة في ماين تُصدر رخص القيادة التجارية (CDLs) وتدير اختبار CDL؟","options":["مكتب المركبات الآلية في ماين (Maine Bureau of Motor Vehicles, BMV)، ضمن مكتب وزير الخارجية (Secretary of State)","وزارة النقل في ماين (MaineDOT)","الإدارة الفيدرالية لسلامة الناقلين بالمحركات (FMCSA)","وحدة إنفاذ المركبات التجارية التابعة لشرطة ولاية ماين"],"explanation":"يُصدر مكتب المركبات الآلية في ماين (Maine Bureau of Motor Vehicles, BMV)، وهو قسم من مكتب وزير الخارجية (Secretary of State)، جميع رخص CDL في ماين ويدير اختبارات المعرفة والمهارات. وتتولى MaineDOT الطرق وتصاريح الحجم/الوزن الزائد، لا إصدار الرخص. المصدر: Maine BMV Commercial Driver License pages (maine.gov/sos/bmv)."},"80":{"q":"على نموذج التصديق الذاتي لـ CDL في ماين (MVE-64C)، من بين كم فئة من فئات نوع التشغيل يمكن لمقدم الطلب الاختيار؟","options":["أربع","اثنتان","ثلاث","ست"],"explanation":"تتطلب ماين التصديق الذاتي ضمن واحدة من أربع فئات: غير المُعفى بين الولايات (Non-Excepted Interstate)، أو المُعفى بين الولايات (Excepted Interstate)، أو غير المُعفى داخل الولاية (Non-Excepted Intrastate)، أو المُعفى داخل الولاية (Excepted Intrastate). المصدر: Maine BMV CDL Medical Self-Certification Form MVE-64C؛ 49 CFR 383.71."},"81":{"q":"يُصدّق سائق في ماين ذاتياً بأنه \"غير مُعفى بين الولايات\" (Non-Excepted Interstate). ما المستند الإضافي الذي يجب أن يكون لدى BMV في الملف؟","options":["شهادة فاحص طبي فيدرالي من DOT (البطاقة الطبية)","لا شيء بخلاف نموذج التصديق الذاتي","خطاب تفويض من جهة العمل موثَّق لدى كاتب العدل","تصريح حجم/وزن زائد من Maine DOT"],"explanation":"يجب على السائقين الذين يصدّقون ذاتياً بأنهم غير مُعفين بين الولايات (Non-Excepted Interstate) أن يزوّدوا BMV بشهادة فاحص طبي فيدرالية سارية (MCSA-5876 / البطاقة الطبية). والسائقون المُعفون غير مطالَبين بتقديم واحدة. المصدر: Maine BMV CDL self-certification guidance؛ 49 CFR 383.71."},"82":{"q":"من المؤهَّل لإجراء الفحص البدني الخاص بـ DOT الذي يُنتج شهادة الفاحص الطبي لمقدم طلب CDL في ماين؟","options":["فاحص طبي مُدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA (FMCSA National Registry of Certified Medical Examiners)","أي طبيب مرخَّص يختاره مقدم الطلب","فاحص من BMV في موقع الاختبار","طبيب البصريات (optometrist) المعتاد لمقدم الطلب"],"explanation":"يجب أن يُجري الفحص البدني الخاص بـ DOT فاحص طبي مُدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA (FMCSA National Registry of Certified Medical Examiners). المصدر: Maine BMV CDL medical requirements؛ 49 CFR 391.43."},"83":{"q":"ما الحد الأقصى لمدة سريان شهادة الفاحص الطبي الخاصة بـ DOT لحامل CDL في ماين؟","options":["2 years","1 year","3 years","5 years"],"explanation":"شهادة الفاحص الطبي سارية لمدة أقصاها 2 years؛ ويجوز للفاحص أن يعتمد سائقاً لمدة أقصر إذا كانت حالة ما تتطلب المراقبة. ويجب أن تكون بطاقة جديدة في الملف قبل انتهاء صلاحية القديمة. المصدر: Maine BMV CDL medical requirements؛ 49 CFR 391.45."},"84":{"q":"كيف يمكن لحامل CDL في ماين تقديم نموذج التصديق الذاتي أو الشهادة الطبية إلى وحدة الامتثال لـ CDL (CDL Compliance Unit) التابعة لـ BMV؟","options":["بالفاكس أو البريد الإلكتروني أو البريد إلى وحدة الامتثال لـ CDL لدى BMV","فقط شخصياً في المكتب المركزي في أوغوستا (Augusta)","فقط عبر الرفع إلى سجل مزوّدي التدريب لدى FMCSA (Training Provider Registry)","فقط من خلال جهة عمل السائق أو الناقل بالمحركات"],"explanation":"تقبل ماين نموذج التصديق الذاتي MVE-64C والشهادة الطبية بالفاكس، أو بالبريد الإلكتروني (PDF/Word) إلى وحدة الامتثال لـ CDL، أو بالبريد إلى وحدة الامتثال لـ CDL لدى BMV في أوغوستا (Augusta). المصدر: Maine BMV CDL Compliance Unit submission instructions."},"85":{"q":"قبل أن يتمكن الشخص من الحصول على تصريح متعلّم تجاري (Commercial Learner's Permit, CLP) في ماين، ما اختبار المعرفة الذي يجب اجتيازه كحدّ أدنى؟","options":["اختبار المعرفة العامة (General Knowledge)","اختبار مصادقة المكابح الهوائية (Air Brakes) فقط","اختبار المواد الخطرة (Hazardous Materials)","اختبار مهارات الفحص قبل الرحلة (pre-trip inspection)"],"explanation":"يجب اجتياز اختبار المعرفة العامة (General Knowledge) (بالإضافة إلى أي اختبارات مصادقة يسعى إليها مقدم الطلب) للحصول على CLP. ويُصدر Maine BMV دليل CDL الرسمي الذي تستند إليه هذه الاختبارات. المصدر: Maine CDL Manual؛ Maine BMV CDL Exam page."},"86":{"q":"ما الحد الأدنى لدرجة النجاح في كل اختبار معرفة لـ CDL في ماين؟","options":["80%","70%","75%","90%"],"explanation":"يجب على السائق الإجابة بشكل صحيح عن 80% على الأقل من الأسئلة في كل اختبار معرفة لكي ينجح. المصدر: Maine CDL Manual؛ 49 CFR 383.135."},"87":{"q":"يتألف اختبار مهارات CDL في ماين من أي ثلاثة أجزاء، بالترتيب؟","options":["الفحص قبل الرحلة للمركبة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة الكتابية، وفحص الرؤية، والقيادة على الطريق","فحص المكابح الهوائية، والرجوع للخلف، واختبار مصادقة كتابي","التحكم الأساسي بالمركبة، والركن الموازي، ومقابلة المواد الخطرة"],"explanation":"يتألف اختبار مهارات CDL من ثلاثة أجزاء تُدار بهذا الترتيب: الفحص قبل الرحلة للمركبة، واختبار التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: Maine CDL Manual؛ 49 CFR 383.113."},"88":{"q":"أي مكوّن من اختبار المهارات يتطلب من مقدم الطلب في ماين أداء مناورات مثل الرجوع للخلف بخط مستقيم، والرجوع للخلف المُزاح (offset backing)، والرسوّ في الزقاق (alley docking)؟","options":["اختبار التحكم الأساسي بالمركبة","الفحص قبل الرحلة للمركبة","اختبار القيادة على الطريق","اختبار المعرفة العامة (General Knowledge)"],"explanation":"تُقيَّم مناورات الرجوع للخلف مثل الرجوع للخلف بخط مستقيم، والرجوع للخلف المُزاح (offset backing)، والرسوّ في الزقاق (alley docking) في جزء التحكم الأساسي بالمركبة من اختبار المهارات. المصدر: Maine CDL Manual؛ 49 CFR 383.113."},"89":{"q":"يجب على مقدم طلب CDL من الفئة A لأول مرة في ماين إكمال تدريب السائق المبتدئ (Entry-Level Driver Training, ELDT) من مزوّد يكون:","options":["مُدرجاً في سجل مزوّدي التدريب لدى FMCSA (Training Provider Registry, TPR)","معتمداً فقط من مجموعة فاحصي Maine BMV","معتمداً من نظام كليات المجتمع المحلية","مسجَّلاً لدى مكتب التصاريح في MaineDOT"],"explanation":"يجب الحصول على ELDT من مزوّد مُدرج في سجل مزوّدي التدريب لدى FMCSA (Training Provider Registry)؛ ويبلّغ المزوّد عن الإكمال إلكترونياً إلى FMCSA. المصدر: Maine BMV ELDT page؛ 49 CFR Part 380 Subpart F."},"90":{"q":"في أي من الحالات التالية تتطلب ماين إكمال ELDT قبل الاختبار؟","options":["CDL من الفئة A أو B لأول مرة، أو مصادقة P أو S أو H لأول مرة","كل تجديد لـ CDL بغض النظر عن الفئة","فقط مقدمو طلبات مصادقة المواد الخطرة (H)","فقط السائقون المرتقون من الفئة B إلى الفئة A"],"explanation":"يُطلب ELDT للحصول على CDL من الفئة A أو الفئة B لأول مرة، أو الترقية إلى فئة أعلى، أو الحصول على مصادقة الركاب (P)، أو الحافلة المدرسية (S)، أو المواد الخطرة (H) لأول مرة. المصدر: Maine BMV ELDT page؛ 49 CFR Part 380."},"91":{"q":"متى يجب على مقدم طلب CDL في ماين إكمال ELDT المطلوب؟","options":["قبل إجراء اختبار المعرفة أو المهارات ذي الصلة","بعد اجتياز اختبار المهارات ولكن قبل طباعة الرخصة","خلال 30 days بعد إصدار CDL","فقط بعد انتهاء فترة الانتظار 14-day لـ CLP"],"explanation":"يجب إكمال الجزء النظري من ELDT قبل اختبار المعرفة لمصادقة H، والتدريب خلف المقود قبل اختبار المهارات للفئة A/B ومصادقات P/S. ويجب أن يسبق التدريب الاختبار المعنيّ. المصدر: Maine BMV ELDT page؛ 49 CFR Part 380 Subpart F."},"92":{"q":"بعد الحصول على CLP، كم يجب على مقدم الطلب في ماين الاحتفاظ به قبل السماح له بإجراء اختبار مهارات CDL؟","options":["14 days على الأقل","30 days على الأقل","7 days على الأقل","60 days على الأقل"],"explanation":"يجب على حامل CLP الانتظار حداً أدنى قدره 14 days بعد إصدار التصريح قبل إجراء اختبار المهارات. المصدر: Maine BMV CDL pages؛ 49 CFR 383.25."},"93":{"q":"عند القيادة بموجب CLP في ماين، يجب أن يكون حامل التصريح برفقة:","options":["حامل CDL، ساري المفعول لفئة تلك المركبة ومصادقاتها، جالس بجوار السائق","أي سائق مرخَّص يبلغ من العمر 21 عاماً أو أكثر","فاحص من BMV فقط","لا أحد، شريطة أن تكون المركبة فارغة"],"explanation":"يجوز لحامل CLP تشغيل مركبة تجارية بالمحركات فقط عندما يكون برفقة شخص يحمل CDL سارية لتلك الفئة من المركبات، جالس في المقعد الأمامي بجانب حامل التصريح. المصدر: Maine CDL Manual؛ 49 CFR 383.25."},"94":{"q":"بالنسبة لمعظم حاملي CDL في ماين دون سن 65، كم مرة يجب تجديد CDL؟","options":["كل 5 years","كل 4 years","كل 6 years","كل 8 years"],"explanation":"تُصدر CDL في ماين لدورة مدتها 5 years لحامليها دون سن 65. (يُجدِّد من بلغوا 65 أو أكثر وفق دورة مدتها 4 years.) المصدر: Maine BMV CDL renewal information."},"95":{"q":"ما الحد الأدنى للسن للحصول على CDL في ماين للقيادة داخل الولاية فقط (ضمن ماين)؟","options":["18","21","19","16"],"explanation":"يجب أن يكون عمر مقدم الطلب 18 على الأقل للحصول على CDL في ماين للقيادة داخل الولاية؛ ويُشترط 21 للقيادة بين الولايات، أو نقل المواد الخطرة، أو حمل الركاب. المصدر: Maine CDL Manual؛ Maine BMV CDL pages."},"96":{"q":"أي مجموعة من المستندات يحتاجها مقدم الطلب في ماين عادةً لإثبات الهوية والأهلية عند التقدّم للحصول على CDL؟","options":["إثبات الهوية، والوجود القانوني في الولايات المتحدة، ورقم الضمان الاجتماعي (Social Security number)، والإقامة في ماين","فقط رخصة قيادة غير تجارية حالية في ماين","جواز سفر بالإضافة إلى تصريح حجم زائد من MaineDOT","خطاب من جهة العمل وتسجيل المركبة فقط"],"explanation":"يجب على مقدمي الطلبات توثيق الهوية، والوجود القانوني في الولايات المتحدة، ورقم الضمان الاجتماعي (Social Security number)، والإقامة في ماين، بالإضافة إلى استيفاء المتطلبات الطبية ومتطلبات التصديق الذاتي. المصدر: Maine BMV CDL application requirements."},"97":{"q":"إذا ترك سائق في ماين الشهادة الطبية المطلوبة تنتهي صلاحيتها بحيث لم تعد في الملف لدى BMV، ما العاقبة المرجَّحة؟","options":["يُخفَّض امتياز CDL للسائق (تُزال الامتيازات التجارية) حتى تُقدَّم شهادة سارية","لا يتغير شيء حتى تاريخ التجديد المعتاد لـ CDL","تُلغى CDL نهائياً دون أي مسار لإعادة الترخيص","يُصدَر تحذير كتابي فقط دون أي تأثير على الرخصة"],"explanation":"إذا انتهت صلاحية الشهادة الطبية لسائق غير مُعفى ولم تُحدَّث لدى BMV، فيجب على الولاية تخفيض CDL بإزالة امتيازات القيادة التجارية حتى تُقدَّم شهادة حالية. المصدر: Maine BMV CDL Compliance guidance؛ 49 CFR 383.73."}}};
